INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7454454307116179456/', 'Loads going on at Durlston Partners and we''re looking for the right people to come in and make the most of it. The platform is strong. Warm desks with active mandates, long-standing relationships across the world''s top hedge funds, HFTs, AI labs, fintechs and digital asset firms, and a diverse client base so there''s always something interesting to work on. You come in, take on live accounts, and start billing. Delivery is heavily rewarded with market leading commission - no caps, no thresholds, no desk fees. Zero internal restrictions on access to roles, clients or regions. No partners sitting on house accounts. No gatekeeping. The team is what makes it. Super collaborative across all three offices, with market info, moves, training and search ideas shared in real time. Looking for kind, humble hard-workers at any level, from people 6 months into recruitment to experienced billers wanting a better platform. If you want to come in and bill big on warm desks with a team that genuinely has your back, drop me a message. shannon@durlstonpartners.com …more', '23m • 23 minutes ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7454431680632664064/', 'The UAE AI hiring market is moving faster than most people realise. I''m looking for AI and LLM engineers right now across some genuinely exciting clients in the region. Family offices building out proprietary AI capabilities. Trading firms to well-backed startups moving at real pace on foundation model applications. The profile these clients want is consistent. Top-tier universities. Big Tech background. Actual depth in large language models, not just a line on a CV. And if you''re not based in the UAE yet? Relocation is absolutely on the table. Honestly, for the right engineer, this market is one of the best moves you can make right now, on comp, lifestyle, and the quality of problems you''d be working on. Profiles at this level are rare. If that''s you, or you know someone, email me directly mo@durlstonpartners.com. Happy to have a no-pressure chat about what''s out there. …more', '1h • 1 hour ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7454099462182027264/', '📈 QUANT TRADERS We have a number of mandates currently live covering Hedge Funds and Tier-1 HFT Prop Shops on a global scale. Thought I would share some information below: 👇 🌎Locations ➡️ US (Chicago/New York) ➡️ APAC (Sydney, Mumbai, Shanghai, Hong Kong) ➡️ EU (Amsterdam, London) ⚙️Products Options ➡️ APAC - Indian Options (SSO/Index - Positional/MM) ➡️ APAC - Hong Kong Options (SSO/Index - Positional/MM/CBBC) ➡️ APAC - Japan Options (SSO/Index - Positional/MM) ➡️ APAC - Korea Options (SSO/Index - Positional/MM) ➡️ EU - Options (SSO/Index - Positional/MM) ➡️ US - Equity Options (SSO/Index - Positional/MM) ETFs ➡️ APAC - (JP, HK, CN) ➡️ EU - (Equities, Commodities) ➡️ US - (US + Int, FI, Commodities) ⛏️ From pure buildouts to joining high PnL driving teams 🚀 If you are interested in having a confidential conversation please feel free to reach out. ab@durlstonpartners.com …more', '23h • 23 hours ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
