INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7453393593047797760/', 'Hiring for AI roles that actually ship 🚀 🌍 UAE and London/Europe Most AI roles live in notebooks. The ones I’m working on run in production, on live data, with real users. 𝐖𝐡𝐚𝐭 𝐈’𝐦 𝐬𝐞𝐞𝐢𝐧𝐠 𝐝𝐞𝐦𝐚𝐧𝐝 𝐟𝐨𝐫: - Agentic systems (designing and scaling multi-agent workflows) - Strong LLM fundamentals + post-training (LoRA, SFT, DPO, RL) - Building and optimising LLM-powered systems end-to-end - Frameworks like LangGraph, MCP, ReAct, Deep Research agents 𝐋𝐢𝐯𝐞 𝐫𝐨𝐥𝐞𝐬: UAE 1. AI Engineer / Scientist – Sovereign Fund – up to $400k TC 2. AI Engineer – Global Fund – up to $220k base 3. Agentic AI Engineer – HFT – up to $400k TC London / Europe 1. Agentic Engineering Manager – AI Unicorn – up to £280k base 2. Senior Research Engineer – AI Unicorn – up to £300k base 3. AI Engineer – Hedge Fund – up to £400k TC 4. Deep Learning Researcher – HFT - up to $1m TC If you’re building (or want to build) AI that actually gets used - let’s talk. jared@durlstonpartners.com …more', '2d • 2 days ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7453080342707662849/', 'A few AI-focused roles that I''m currently working on: Senior Research Engineer – Conversational AI Startup – London Up to £300,000 base + equity https://lnkd.in/et7SxHkh Software Engineer (All Levels) – Frontier AI Startup – London Up to £300,000 base + equity https://lnkd.in/e96DefAu AI Software Engineer – Elite Hedge Fund – London Up to £130,000 + 50% bonus https://lnkd.in/eEMw7y98 DevOps Engineer – AI Startup – London £130,000 + equity https://lnkd.in/eaiYk8DM Working on a lot more besides these - if you''re exploring the market and want to get a feel for what''s out there, drop me a message. I''m sure we''d find something worth talking about. david@durlstonpartners.com …more', '3d • 3 days ago • Visible to anyone on or off LinkedIn', 0, 1, 2, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7452642390269579264/', 'London based - Frontend Engineer - up to £120,000 plus equity. There are some roles that are just jobs. And then there are roles where what you build actually matters. I''m working with an early-stage team on a genuinely complex, real-world software platform. Multiple systems, multiple data streams, intelligent decision-making, unified into a single interface. The kind of product where engineering decisions have real consequences. This is not a pixel-pushing role. They need a Frontend Engineer (React, TypeScript) who has operated in fast-moving, ambiguous environments and taken real ownership of a product, not just tickets. You''ll be joining early. That means: - High autonomy from day one - Direct influence on product direction - Building from first principles, not maintaining someone else''s legacy The profiles that tend to thrive here: - Strong academic foundations: Maths, Physics, Engineering - Experience in high-performance environments, startups, or technically complex systems - Engineers who want to solve hard problems, not just ship features UK-based and eligible to work without restriction is a must. If this sounds like your kind of environment, or you know someone who belongs in a room like this, drop me a message or email me mo@durlstonpartners.com. …more', '5d • 5 days ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7452268677368016896/', '***Hiring*** Systems Integration/AI Automation Engineer (NYC/CT with flexibility) I''m looking for someone who gets excited about making technology actually work - eliminating silos, automating the tedious, and bringing AI into day-to-day workflows in meaningful ways. This is a rare individual contributor role at a well-resourced, mission-driven private office with a truly exceptional benefits package and a culture that takes both the work and the people seriously. What you''d be doing: → Designing and owning enterprise integrations across Microsoft 365, Salesforce & other SaaS platforms → Partnering with Finance, HR, and other business units to identify and automate manual workflows → Building and deploying custom GPTs, Copilot extensions, and AI agents that actually move the needle → Collaborating with global teams across time zones What we''re looking for: ✅ 4+ years in IT systems integration, automation, or AI development ✅ Strong command of Microsoft 365, Azure & Power Platform ✅ Hands-on experience with tools like PowerAutomate, Zapier, Copilot, or ChatGPT ✅ Someone who thrives in ambiguity and can translate business needs into scalable tech The package is competitive, 100% employer-paid medical, a 401(k) match that''s genuinely one of the best I''ve seen, hybrid work, summer Fridays, and more. If this sounds like you - or someone in your network - drop me a DM or send to a colleague. I''d love to connect. 👇 matt@durlstonpartners.com …more', '6d • 6 days ago • Visible to anyone on or off LinkedIn', 0, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7451928923157983232/', 'Most GUI roles: You build dashboards., you move buttons around, you argue about padding. This one’s a bit different. You’re building the interface traders rely on to make decisions in real time, where latency matters, accuracy matters, and bad UX isn’t just annoying… it’s expensive. One minute you’re visualising live positions across multiple venues. Next, you’re helping surface trading activity from dozens of exchanges into something actually usable. Then you’re working on systems that reconcile trades, flag issues, and feed directly into decision-making. It’s GUI, but it actually matters You’re: - Working directly with traders (not through five layers of product) - Owning systems that sit close to revenue - Solving real time data problems, not static dashboards - Building tools that are used all day, every day Tech wise, it’s Python, Qt, Linux but more importantly, it’s about how you think and build. They’re also pretty selective on background, typically looking for people from top globally ranked universities, with degrees in Computer Science, Physics or Mathematics and must have experience in GUI & QT. No finance experience needed just strong engineering fundamentals and curiosity. If you’ve ever felt like your work sits a bit too far away from impact… this is the opposite of that. Happy to share more context if it’s of interest. daniel@durlstonpartners.com …more', '6d • 6 days ago • Visible to anyone on or off LinkedIn', 2, 0, 0, 'image', 0, NULL);
