INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7451626915196461056/', '6 months at Durlston Partners and I genuinely couldn''t be happier with how it''s gone so far. A lot of that comes down to the team that I''m surrounded by, but also the space we''re operating in. Quant and AI - there''s a lot happening right now and it makes for a pretty exciting place to be. The next few years look very promising! A particular thank you to Vax, Meraj and Shannon for the opportunity. I''ve enjoyed every minute of it so far! On that note - the team is growing. If you''re a Recruiter specialising in Quant, Tech, or AI and you''re looking for your next move, please reach out. Feel free to message me directly, or reach out to Shannon Palmer. david@durlstonpartners.com …more', '1w • 1 week ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7451264527641358336/', '𝐑𝐞𝐬𝐞𝐚𝐫𝐜𝐡 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫𝐬 – 𝐔𝐩 𝐭𝐨 £300𝐤 𝐛𝐚𝐬𝐞 + 𝐄𝐪𝐮𝐢𝐭𝐲 I’m working with a hypergrowth AI start-up that is building out a brand-new Research Engineering team in London. 𝐓𝐡𝐞𝐲’𝐫𝐞 𝐥𝐨𝐨𝐤𝐢𝐧𝐠 𝐭𝐨 𝐬𝐩𝐞𝐚𝐤 𝐰𝐢𝐭𝐡: Research Engineers / Research Scientists / ML Engineers from 𝐁𝐢𝐠 𝐓𝐞𝐜𝐡 who are frustrated by bureaucracy and want to work in a far more agile, fast-paced environment. 𝐐𝐮𝐚𝐧𝐭 𝐑𝐞𝐬𝐞𝐚𝐫𝐜𝐡𝐞𝐫𝐬 from 𝐇𝐅𝐓 who are interested in moving into AI, without waiting through a 12–18-month non-compete at a competing financial firm. 𝐂𝐡𝐚𝐧𝐜𝐞 𝐭𝐨 𝐛𝐥𝐞𝐧𝐝 𝐲𝐨𝐮𝐫 𝐐𝐮𝐚𝐧𝐭 𝐞𝐱𝐩𝐞𝐫𝐢𝐞𝐧𝐜𝐞 𝐰𝐢𝐭𝐡 𝐀𝐈/𝐋𝐋𝐌𝐬 𝐞𝐭𝐜. Research Engineers / 𝐌𝐞𝐦𝐛𝐞𝐫𝐬 𝐨𝐟 𝐓𝐞𝐜𝐡𝐧𝐢𝐜𝐚𝐥 𝐒𝐭𝐚𝐟𝐟 who are already working on 𝐩𝐨𝐬𝐭-𝐭𝐫𝐚𝐢𝐧𝐢𝐧𝐠 𝐦𝐨𝐝𝐞𝐥𝐬 𝐢𝐧 𝐩𝐫𝐨𝐝𝐮𝐜𝐭𝐢𝐨𝐧. This is an opportunity to help 𝐩𝐮𝐬𝐡 𝐭𝐡𝐞 𝐛𝐨𝐮𝐧𝐝𝐚𝐫𝐢𝐞𝐬 of what’s possible in 𝐦𝐮𝐥𝐭𝐢-𝐦𝐨𝐝𝐚𝐥 𝐀𝐈 at a company moving at real speed with 𝐫𝐞𝐚𝐥 𝐞𝐪𝐮𝐢𝐭𝐲 𝐩𝐨𝐭𝐞𝐧𝐭𝐢𝐚𝐥. 𝐕𝐢𝐬𝐚 𝐬𝐩𝐨𝐧𝐬𝐨𝐫𝐬𝐡𝐢𝐩 𝐚𝐯𝐚𝐢𝐥𝐚𝐛𝐥𝐞 Also, open to considering candidates across Europe who are 𝐰𝐢𝐥𝐥𝐢𝐧𝐠 𝐭𝐨 𝐫𝐞𝐥𝐨𝐜𝐚𝐭𝐞 𝐭𝐨 𝐋𝐨𝐧𝐝𝐨𝐧. If this could be of interest, please apply via the link below or contact me directly at 𝐉𝐚𝐦𝐢𝐞@𝐃𝐮𝐫𝐥𝐬𝐭𝐨𝐧𝐩𝐚𝐫𝐭𝐧𝐞𝐫𝐬.𝐜𝐨𝐦 …more', '1w • 1 week ago • Visible to anyone on or off LinkedIn', 13, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7450826654383443968/', 'Around this time of year, bonus season is wrapping up across most firms, and the market starts to move in an interesting way. Candidates who have been sitting tight since January are now free to have conversations. Firms that have been planning their hires for the first half of the year are ready to move quickly. For a brief window, both sides are aligned - and that tends to make for some of the most efficient hiring of the year. In my experience, the period right after bonus season is one of the best times to explore the market. Motivations are clear, timelines are realistic, and there''s genuine momentum on both sides of the conversation. If you''ve been thinking about what''s next - this is a good moment to start that conversation. Not because the pressure is on, but because the conditions are right. Feel free to reach out if you want to understand what''s out there: david@durlstonpartners.com …more', '1w • 1 week ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7450539758390296576/', 'The best quant talent is usually heads-down, not actively applying - but I’m currently representing several top trading firms and am looking to connect with exceptional researchers and traders across a range of strategies. NYC/Chicago, Hong Kong, Singapore, UAE, and London openings. Current searches include: • Equities Stat-Arb Quant Researchers • Options Traders • Options Quant Researchers • Quant Vol Traders • Commodities Quant Researchers • Fixed Income ETF Traders • Macro Quant Researchers • HFT Quants across Equities, Futures, and ETFs • Sr. AI Engineers, Head of AI, and Sr. AI Scientists These searches are centered on individuals with a real edge - whether that means generating alpha, building differentiated research, owning risk, or driving measurable trading performance. If you have a strong track record in one of these areas, or know someone who does/should be on my radar, feel free to reach out directly. All conversations handled discreetly. matt@durlstonpartners.com …more', '1w • 1 week ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7450178744884932609/', 'It’s been a solid week at Durlston Partners. Big day of meetings in Abu Dhabi with Rahnpreet Sandhu with clients and candidates (we haven’t gone anywhere), Jared Wolfaardt’s 30th birthday, and somewhere in there a ceasefire for good measure. From a hiring perspective, things are pretty steady. Which I’ll admit is not what you’d expect reading the news. Our pipeline of new starters is unaffected. A couple of candidates have nudged start dates back slightly, mostly starting remotely first and relocating a bit later. Nothing dramatic. What has changed is how people now fall into three camps: 1.	Those who were always set on moving 2.	Those who were on the fence 3.	Those who were just kicking the tyres This conflict has basically forced everyone to pick a lane. The first group are leaning into it more. They’ve usually done their homework on the region and are making decisions based on deep rooted fundamental views of the UAE, not whatever the latest headline is. Clients have clocked this as well. They’re going out of their way to make things work for these people. Delayed start dates, flexible relocation, more support around families. There’s a bit more give on their side than usual. If you’re in that first bucket, it’s actually a good time to be interviewing. Competition has thinned out a lot. Feels a bit like December hiring where half the market is waiting for January for a clean start. On the whole, life here feels pretty normal and I’m going fishing this weekend. josh@durlstonpartners.com …more', '1w • 1 week ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7450094319245594624/', 'We receive a high volume of messages and applications through the Durlston Partners website and LinkedIn page every day. We really appreciate that a lot of people are looking for new opportunities at the moment, and the team does try to respond and have speculative conversations where possible. That said, many of our clients have very specific requirements, and there are only so many hours in the day, so the team has to prioritise candidates who are most aligned with live roles. If you see a role on our website or LinkedIn that you feel is a good fit, please feel free to send a follow up email to hello@durlstonpartners.com with your CV, a short summary of what you have been doing, and the types of roles and firms you would be interested in. This helps us review your profile properly and keep you in mind for relevant opportunities. Thanks in advance, and we really appreciate your patience. …more', '1w • 1 week ago • Visible to anyone on or off LinkedIn', 0, 0, 2, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7449788572171259904/', 'Non-competes in trading have got longer. 12 months is now quite common on the buy side. Some stretch to 24 (maybe even longer). But there''s a nuance a lot of people are starting to pick up on. If you move to an AI firm rather than a direct competitor, your current employer has no real grounds to enforce it. No conflict, no client overlap, no competition. The legal basis simply isn''t there. In practice, a lot of quant talent is quietly opting to move into AI (where the technical problems are just as interesting) rather than sitting at home for a year waiting out a clock that arguably doesn''t need to run. I''ve been seeing this more and more over the last few months. The AI firms on the receiving end of that talent are serious operators, and they''re hiring. I''m currently working with several looking for Quant Developers, Quant Researchers, and ML Engineers from a trading or systematic finance background. If that''s relevant to you, feel free to drop me a message or reach out at david@durlstonpartners.com …more', '1w • 1 week ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7449373315502350336/', 'Most people at large firms won’t say this out loud But I hear it every week Frustration doesn’t usually come from the work itself It comes from everything around it – You’re one of many, not the person driving something – Impact gets diluted across layers of process and approvals – Comp is strong… but often capped relative to what you actually generate – Progression is slow, because the structure has to be rigid – Decisions are made far away from the people doing the work And over time, that starts to wear thin Especially for people who know they can do more What’s interesting is where a lot of these people end up going Not the firms posting job ads every week Not the ones everyone is already talking about The moves I’m seeing most often are into smaller, growing funds The ones that aren’t advertising The ones building quietly The ones where hiring is deliberate, not volume-driven Why? Because the trade-off is very different: – Your work actually moves the needle – You’re closer to the PnL and decision-making – There’s less noise, less politics, fewer layers – Comp is more directly tied to impact – Growth isn’t boxed into a predefined ladder It’s not for everyone Less structure More accountability from day one But for the right person, it’s where careers can accelerate quickly Most of these opportunities never get posted If you’re starting to feel that disconnect where you are now, it’s probably worth a conversation daniel@durlstonpartners.com …more', '2w • 2 weeks ago • Visible to anyone on or off LinkedIn', 4, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7449075100659683328/', 'The global ETF market has crossed $20 trillion in AUM - and European flows hit a record $396 billion in 2025 alone. More flow, more complexity, more demand for people who can price it properly. I am looking for a 𝗝𝘂𝗻𝗶𝗼𝗿 𝗤𝘂𝗮𝗻𝘁 𝗧𝗿𝗮𝗱𝗲𝗿 to join a 𝗠𝗮𝗿𝗸𝗲𝘁 𝗠𝗮𝗸𝗶𝗻𝗴 firm in 𝗟𝗼𝗻𝗱𝗼𝗻, covering an ETF desk. 𝗧𝗵𝗲 𝗿𝗼𝗹𝗲: - Pricing models, hedging, and making markets across ETFs from day one - Tier 1 team (ex. IMC, Optiver, etc.) small, flat, high-expectation 𝗪𝗵𝗮𝘁 𝘁𝗵𝗲𝘆 𝘄𝗮𝗻𝘁: - Strong quant background (maths, physics, CS, stats) - Some grounding in derivatives or microstructure - 0-2 years experience — genuine junior hire 𝗪𝗵𝗮𝘁''𝘀 𝗼𝗻 𝗼𝗳𝗳𝗲𝗿: - Competitive base + performance bonus 𝗟𝗼𝗰𝗮𝘁𝗶𝗼𝗻: - London Real mentorship from people who''ve run ETF books at the top level. If you are interested, send me a message or reach out to david@durlstonpartners.com for a confidential chat. …more', '2w • 2 weeks ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7448769347080179712/', '𝗟𝗟𝗠 𝗕𝗹𝗶𝗻𝗱 𝘀𝗽𝗼𝘁𝘀 𝗮𝗻𝗱 𝘁𝘂𝗿𝗻𝗶𝗻𝗴 𝗮𝘁𝘁𝗲𝗻𝘁𝗶𝗼𝗻 𝘁𝗼 𝗪𝗼𝗿𝗹𝗱 𝗠𝗼𝗱𝗲𝗹𝘀 🌍 𝗔𝗴𝗲𝗻𝘁𝗶𝗰/𝗥𝗲𝗮𝗹 𝗪𝗼𝗿𝗹𝗱 𝗠𝗼𝗱𝗲𝗹 𝗛𝗶𝗿𝗶𝗻𝗴 - 𝙚.𝙜. 𝙃𝙚𝙖𝙙 𝙤𝙛 𝘼𝙄 (𝙇𝙤𝙣𝙙𝙤𝙣) The fact that LLMs are fundamentally pattern matchers making ''educated guesses'', but have rapidly progressed to the point that they run most of our lives and workflows, is truly incredible! But there are limitations in some uses. World models are a new race, acting as internal simulators understanding physical rules and cause-and-effect, to simulate outcomes before action. This is a step towards true reasoning and incredibly reliable and autonomous AI Agents. Analogy: LLMs can memorise your route home every day and make it more efficient. Real world models will already know what to do is there''s a crash along the way. We have clients with huge backing that are gearing up to be early movers in Real World Models within the wide use cases of their Agentic offering, including a firm in London that is looking for a Head of AI. Please reach out if you are interested in hearing more: rahn@durlstonpartners.com …more', '2w • 2 weeks ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/vaxbahram', 'https://www.linkedin.com/feed/update/urn:li:activity:7445046644624019457/', 'Why I believe in a strong V Shape bounce for Dubai and Abu Dhabi similar to 2021. The fundamentals haven’t changed in the UAE. At Durlston Partners in Dubai, we have been coming into the office every single day since the conflict began and every single day we have been speaking to our clients; hedge funds, sovereign wealth funds and family offices. We remain 100% committed to Dubai, Abu Dhabi and the whole region. This is the same for at least 80%+ of the people I speak to. The fundamentals haven’t changed: great leadership that serves the people, with intention, with calmness, urgency and vision. The Dubai + Abu Dhabi reserves sit at $2.9 Trillion, that’s 100x the annual budget so the UAE could run the state tax free for 100 years! Dubai will have a whole new image when this is over and will attract even more great people and investment. Just like the US attracted the most positive and hardworking people globally, over 100 years ago, the UAE is now doing the same. Great people build Great nations. Photo: This morning, our team gathered for Breakfast Club at Bisou Restaurant and Founders Dubai …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 0, 9, 7, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7448308802170548224/', 'If you enjoy building tools that traders actually rely on (not just maintaining systems in the background), this one’s worth a look. A leading crypto trading firm is hiring a Python engineer with Qt experience to join their core team, a group that touches everything across front and middle office. You’ll be: - Building trading GUIs used daily by traders - Working directly with them to shape how they interact with markets - Handling real-time data, positions, alerts, and internal tooling - Jumping across different problems (no silos, no “this isn’t my area”) The setup: - High autonomy (no KPI''s, no one breathing down your neck, just get things done) - Flexible working (flexible hours, remote-friendly as long as you deliver) - Greenfield work (not just a buzzword, and if you end up speaking to the hiring manager, you’ll see why) If you’re strong in Python + Qt, enjoy variety, and want to work closer to the action, drop me a message. karolis@durlstonpartners.com …more', '2w • 2 weeks ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/jamie-burman-b6281b127', 'https://www.linkedin.com/feed/update/urn:li:activity:7444654463501561856/', '𝐑𝐞𝐬𝐞𝐚𝐫𝐜𝐡 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫𝐬 – 𝐔𝐩 𝐭𝐨 £300𝐤 𝐛𝐚𝐬𝐞 + 𝐄𝐪𝐮𝐢𝐭𝐲 I’m working with a hypergrowth AI start-up that is building out a brand-new Research Engineering team in London. 𝐓𝐡𝐞𝐲’𝐫𝐞 𝐥𝐨𝐨𝐤𝐢𝐧𝐠 𝐭𝐨 𝐬𝐩𝐞𝐚𝐤 𝐰𝐢𝐭𝐡: Research Engineers / Research Scientists / ML Engineers from 𝐁𝐢𝐠 𝐓𝐞𝐜𝐡 who are frustrated by bureaucracy and want to work in a far more agile, fast-paced environment. 𝐐𝐮𝐚𝐧𝐭 𝐑𝐞𝐬𝐞𝐚𝐫𝐜𝐡𝐞𝐫𝐬 from 𝐇𝐅𝐓 who are interested in moving into AI, without waiting through a 12–18-month non-compete at a competing financial firm. 𝐂𝐡𝐚𝐧𝐜𝐞 𝐭𝐨 𝐛𝐥𝐞𝐧𝐝 𝐲𝐨𝐮𝐫 𝐐𝐮𝐚𝐧𝐭 𝐞𝐱𝐩𝐞𝐫𝐢𝐞𝐧𝐜𝐞 𝐰𝐢𝐭𝐡 𝐀𝐈/𝐋𝐋𝐌𝐬 𝐞𝐭𝐜. Research Engineers / 𝐌𝐞𝐦𝐛𝐞𝐫𝐬 𝐨𝐟 𝐓𝐞𝐜𝐡𝐧𝐢𝐜𝐚𝐥 𝐒𝐭𝐚𝐟𝐟 who are already working on 𝐩𝐨𝐬𝐭-𝐭𝐫𝐚𝐢𝐧𝐢𝐧𝐠 𝐦𝐨𝐝𝐞𝐥𝐬 𝐢𝐧 𝐩𝐫𝐨𝐝𝐮𝐜𝐭𝐢𝐨𝐧. This is an opportunity to help 𝐩𝐮𝐬𝐡 𝐭𝐡𝐞 𝐛𝐨𝐮𝐧𝐝𝐚𝐫𝐢𝐞𝐬 of what’s possible in 𝐦𝐮𝐥𝐭𝐢-𝐦𝐨𝐝𝐚𝐥 𝐀𝐈 at a company moving at real speed with 𝐫𝐞𝐚𝐥 𝐞𝐪𝐮𝐢𝐭𝐲 𝐩𝐨𝐭𝐞𝐧𝐭𝐢𝐚𝐥. 𝐕𝐢𝐬𝐚 𝐬𝐩𝐨𝐧𝐬𝐨𝐫𝐬𝐡𝐢𝐩 𝐚𝐯𝐚𝐢𝐥𝐚𝐛𝐥𝐞 Also, open to considering candidates across Europe who are 𝐰𝐢𝐥𝐥𝐢𝐧𝐠 𝐭𝐨 𝐫𝐞𝐥𝐨𝐜𝐚𝐭𝐞 𝐭𝐨 𝐋𝐨𝐧𝐝𝐨𝐧. If this could be of interest, please apply via the link below or contact me directly at 𝐉𝐚𝐦𝐢𝐞@𝐃𝐮𝐫𝐥𝐬𝐭𝐨𝐧𝐩𝐚𝐫𝐭𝐧𝐞𝐫𝐬.𝐜𝐨𝐦 hashtag#AIJobs hashtag#MachineLearning hashtag#DeepLearning hashtag#LLMs hashtag#MultimodalAI hashtag#ArtificialIntelligence hashtag#AIEngineering hashtag#ResearchEngineering hashtag#MLJobs hashtag#AIResearch hashtag#AppliedAI hashtag#BigTech hashtag#SoftwareEngineers hashtag#MLEngineers hashtag#ResearchScientists hashtag#TechCareers hashtag#QuantResearch hashtag#HFT hashtag#QuantJobs hashtag#EngineeringCareers …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 24, 1, 4, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7447942641410809857/', 'I''m looking for Traders Immediately. There’s demand for: • A Junior ETF Trader (up to 2 years’ experience) • A Mid Level Trader For the junior seat, this is a strong opportunity for someone who’s had exposure at top tier electronic trading firms and is now looking for the right platform to build on that foundation. Timing matters here, especially for the junior hire. If you’re in that bracket, or know someone who is, feel free to reach out. daniel@durlstonpartners.com …more', '2w • 2 weeks ago • Visible to anyone on or off LinkedIn', 0, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7447610475112058881/', '𝗛𝗲𝗮𝗱 𝗼𝗳 𝗔𝗜 - 𝗙𝗼𝘂𝗻𝗱𝗶𝗻𝗴 𝘁𝗲𝗮𝗺 - 𝗘𝘅𝘁𝗿𝗲𝗺𝗲𝗹𝘆 𝘄𝗲𝗹𝗹-𝗯𝗮𝗰𝗸𝗲𝗱 𝗦𝘁𝗮𝗿𝘁𝘂𝗽 𝗨𝗽 𝘁𝗼 £𝟰𝟬𝟬𝗸 𝗯𝗮𝘀𝗲 + 𝗦𝗶𝗴𝗻𝗶𝗳𝗶𝗰𝗮𝗻𝘁 𝗘𝗾𝘂𝗶𝘁𝘆 - 𝗟𝗼𝗻𝗱𝗼𝗻 I am working with the founding team of an AI startup in London, looking for their Head of AI/CTO, who will have a complete remit to build their central LLM from scratch, with huge investments in the resources needed to scale this rapidly. This will be an enterprise agentic platform, allowing for deeper specialism into some of their target industries, many of which are already involved in the plans for this build. Please reach out if you''ve worked on the build of LLMs (10B+ parameters), then please reach out: rahn@durlstonpartners.com …more', '2w • 2 weeks ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7447202772455731200/', '🇦🇪 The list of hedge funds planting flags in ADGM keeps growing. The number of funds operating there has grown from a handful to over 220 - and the operational entities have jumped 43% in the same period. The infrastructure supporting all of that capital needs to be built by someone. I am working with a hedge fund in Abu Dhabi looking for a strong 𝗦𝗲𝗻𝗶𝗼𝗿 𝗣𝗹𝗮𝘁𝗳𝗼𝗿𝗺 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 to join their team. You''ll be owning the infrastructure that keeps trading systems alive and performant - cloud, containers, automation, etc. 𝗪𝗵𝗮𝘁 𝘁𝗵𝗲 𝘀𝘁𝗮𝗰𝗸 𝗹𝗼𝗼𝗸𝘀 𝗹𝗶𝗸𝗲: ◼️ Linux (this is your native environment) ◼️ AWS - architecting and running production cloud infrastructure ◼️ Kubernetes - managing containerised workloads at scale ◼️ Python - scripting, automation, glue ◼️ CI/CD pipelines, IaC, monitoring, etc. 𝗪𝗵𝗮𝘁 𝘁𝗵𝗲𝘆''𝗿𝗲 𝗹𝗼𝗼𝗸𝗶𝗻𝗴 𝗳𝗼𝗿: ◼️ Solid hands-on experience in a performance-sensitive environment (finance/trading) ◼️ Someone who''s built and scaled infrastructure, not just maintained it ◼️ Clean thinking under pressure - these systems don''t get to be down 𝗪𝗵𝗮𝘁''𝘀 𝗼𝗻 𝗼𝗳𝗳𝗲𝗿: ◼️ Base salary up to $175,000 + bonuses - tax-free ◼️ Strong relocation package for candidates moving to Abu Dhabi - they''ll make the move straightforward ◼️ Real ownership of infrastructure in a lean, high-quality team 𝗟𝗼𝗰𝗮𝘁𝗶𝗼𝗻: ◼️ Abu Dhabi, UAE 🇦🇪 If you are interested, send me a message or reach out to david@durlstonpartners.com for a confidential chat. …more', '2w • 2 weeks ago • Visible to anyone on or off LinkedIn', 0, 1, 2, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7446866834366136323/', 'If you’re a senior engineer operating at a lead level (but still enjoy being the one writing the code), this could be your step into a CTO seat. A small but very high calibre team, building a latency sensitive production critical platform, is looking for a hands-on technical leader to take full ownership. This isn’t a “sit in meetings” CTO role, closer to a player coach: setting direction and building alongside the team. You’d be: - Owning the entire tech function (architecture, infra, security, delivery) - Designing and scaling cloud-native systems (AWS, Kubernetes, microservices) - Writing code (C++ ideally), reviewing PRs, and solving real production issues - Working directly with the CEO to shape product and technical direction They’re looking for someone who: - Has built and shipped complex systems (ideally in trading or high-performance environments) - Is still deeply hands-on (this is a ~90% coding role) - Thinks in terms of latency, reliability, and scale - Wants to step into a CTO role and earn it through output London based, 4 days in, senior team, high ownership, no layers. If you’ve been waiting for the right moment to step up without giving up the code, happy to chat. karolis@durlstonpartners.com …more', '2w • 2 weeks ago • Visible to anyone on or off LinkedIn', 9, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7446470439394267136/', 'The market is picking up quickly right now Spoke with several clients recently and the message was consistent: they want these roles filled before the end of April. Hiring processes are moving faster, decisions are being made quicker, and strong candidates aren’t sitting on the market for long. Here’s a snapshot of what’s live: Senior Infrastructure leadership (Windows focus) ➟ New York ➟ High-impact, business-critical hire Lead Frontend Engineer ➟ Trading environment ➟ Ownership from day one C++ Engineers ➟ Core trading systems ➟ Performance-critical work Strategy Developer (C++ + quant exposure) ➟ Blending research + engineering ➟ Fully remote Rust Engineers ➟ Building next-gen trading infrastructure ➟ Remote across Europe Quant hires ➟ Credit focused role in London ➟ Futures quant in APAC The common theme: urgency. This isn’t a “see what’s out there” kind of market. It’s a “move quickly or miss out” one. If you’re open to a move, now’s a good time to have a conversation. daniel@durlstonpartners.com …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7446176017804804096/', '🚀 Head of AI – £400k base + equity - London UK I’m partnering with a seriously well-funded AI start-up building next-generation language models and agentic AI systems. They’re looking for someone who has built or led teams building ~10B+ parameter LLMs and wants to own the AI roadmap at company level. • £400k base + equity • Hands-on role • Build the AI platform from the ground up • Backed by significant funding • Multi-year vision – looking for long-term builders jared@durlstonpartners.com …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7445753224277622784/', '𝗣𝗶𝘃𝗼𝘁 𝘁𝗼 𝗔𝗜 We''re seeing a massive shift right now, with top AI labs in both tech and trading firms actively being the most attractive draw for SWEs, QDs, and QRs out of the HFT and Hedge Fund space. While many firms throw buzzwords around and just wrap APIs to keep investors happy, there is a whole world of firms who are capturing quality talent and giving them the platform to work on complex agentic systems. Similar problems to what you''ve done before: - Distributed Systems Engineering - direct parallel to AI Engineering and the multi-agent orchestration platforms. - Applied Probablility - essentially the topic of modern GenAI. Advanced reasoning relies heavily on RL with optimisation based on reward functions, very similar to alpha generation. - Alt Data Research - noisy data used in Quant trading is a fantastic stepping stone to the noisy world of multimodal data research. The biggest bottleneck right now for our clients isn''t invention, its execution and scaling, under the time pressure of how quickly this industry is moving. In the same way, trading firms don''t have time to wait to build, each day of delay is a day of missed PnL. Roles: - Head of AI (LLM building exp) - London - Up to £400k base + Equity - Senior AI Researcher - Europe (HFT) - $400k-$2m USD TC - GenAI Research Engineer - London - Up to £300k base + Equity - GenAI SWE - London - Up to £270k base + Equity - Senior GenAI Engineer - Abu Dhabi - Up to $220k base + Bonus Please feel free to reach out: rahn@durlstonpartners.com …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7445724914612994048/', 'Happy Easter from Durlston Partner. As we head into the long weekend, a quick reminder, we’re offering attractive referral incentives. If there’s someone in your network exploring new roles, we’d be glad to support and manage the process. Please reach out at hello@durlstonpartners.com …more', '3w • Edited • 3 weeks ago • Edited • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7445451699454119936/', 'A lot of people underestimate just how much systematic talent is now driving the economics of the buy side. Look at the numbers. Even in a weaker year, Citadel paid roughly $3.8bn in compensation, with average pay around $1.2m per employee. Top performers in the UK reportedly cleared $20m+. Why? Because the people building systematic strategies, running stat arb books, or managing portfolio risk are directly tied to the P&L. Firms cannot afford to lose that talent to competitors. Strong performance is also feeding directly into hiring. Balyasny returned 16.7% in 2025, ahead of several other multi-managers, and is planning to take in over a 100 quant interns globally, converting roughly half to full-time roles. That is how the multi-manager model expands: More capital → more pods → more seats → tighter screening. And that last part is key. Funds are no longer hiring purely on strong academics. Candidates are expected to arrive interview ready, with clear evidence they can apply mathematics, statistics, machine learning or programming to real trading problems. The bar keeps moving higher. But so does the upside for those who clear it. 🚀 daniel@durlstonpartners.com …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7445440863876517888/', 'Excited to have Muhammad Aly join our team in Dubai. With 15+ years of specialist recruitment experience across APAC and MENA, and over a decade building networks across the UAE, Mo brings a rare combination of deep market knowledge and genuine commercial instinct to every search. At Durlston Partners, Mo will focus on placing elite talent across AI, product, and technology with some of the region’s most ambitious organizations, while continuing to build lasting relationships with the most innovative and forward-thinking firms in the market. From AI research labs and innovation teams to high-growth fintech''s and global technology consultancies, his focus is on the kind of talent that doesn’t show up on job boards and the kind of relationships that take years to build properly. Outside of work, you’ll usually find him on a padel court, somewhere on a bike, building Lego sets with a level of seriousness that probably warrants its own LinkedIn post, or convinced he’d have made an exceptional chef. Welcome to the team, Mo. Durlston Partners …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 0, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7445111670626119680/', 'Pour mon réseau français, je recherche un(e) Product Manager (Équipe Fondatrice) pour une Start-up IA & Finance à Paris! Vous travaillerez en direct avec le CEO pour construire des produits tech à fort impact. Le profil idéal : ◾ Track record solide en tant que PM ◾ Expérience préalable dans la finance OU en start-up tech ◾ Maîtrise de l''anglais obligatoire L''offre : ◾ Rôle clé dans l''équipe fondatrice ◾ Salaire jusqu''à 120 000 € + Bonus + Equity Si ça vous parle, n''hésitez pas à me contacter directement ici ou sur david@durlstonpartners.com. …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 0, 0, 2, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7442860745383534592/', 'We receive a high volume of messages and applications through the Durlston Partners website and LinkedIn page every day. We really appreciate that a lot of people are looking for new opportunities at the moment, and the team does try to respond and have speculative conversations where possible. That said, many of our clients have very specific requirements, and there are only so many hours in the day, so the team has to prioritise candidates who are most aligned with live roles. If you see a role on our website or LinkedIn that you feel is a good fit, please feel free to send a follow up email to hello@durlstonpartners.com with your CV, a short summary of what you have been doing, and the types of roles and firms you would be interested in. This helps us review your profile properly and keep you in mind for relevant opportunities. Thanks in advance, and we really appreciate your patience. …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 2, 'image', 1, NULL);
