INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7444379158211911680/', '𝗤𝗥 𝘁𝗼 𝗚𝗲𝗻𝗔𝗜 𝗥𝗲𝘀𝗲𝗮𝗿𝗰𝗵 𝗘𝗻𝗴 - 𝗟𝗼𝗻𝗱𝗼𝗻 - 𝗨𝗽 𝘁𝗼 £𝟯𝟬𝟬𝗸 𝗯𝗮𝘀𝗲 + 𝗦𝗶𝗴𝗻𝗶𝗳𝗶𝗰𝗮𝗻𝘁 𝗘𝗾𝘂𝗶𝘁𝘆 𝗔𝘃𝗼𝗶𝗱 𝗻𝗼𝗻-𝗰𝗼𝗺𝗽𝗲𝘁𝗲𝘀 + 𝘂𝗽𝘀𝗸𝗶𝗹𝗹 Really interesting role, allowing research-driven QRs to transition into GenA and avoid the limits of their non-compete, while upskilling themselves in an incredible Agentic team. You''ll be working to build and apply cutting-edge conversational GenAI models, all the way from idea to production, and have freedom to work on frontier approaches for training, evaluation and orchestration of these agentic systems. Up to £300k base + Equity Please let me know if you are interested in hearing more! rahn@durlstonpartners.com …more', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7443922406546534400/', 'Two dream quant roles just opened in London Both sit directly on the trading side, working closely with PMs and researchers to build models, generate signals and influence real investment decisions across credit markets. Open roles: • Quantitative Researcher • Quant Analyst (Open to profiles outside of credit) Think large scale data analysis, model development, signal generation and tooling that feeds directly into live trading. Looking for candidates with buy-side or sell-side experience, a top university background in Maths/Stats (or similar), and already based in London. Seats like this don’t come around often If you’re interested (or know someone who should be), feel free to message me. daniel@durlstonpartners.com …more', '4w • 0 months ago • Visible to anyone on or off LinkedIn', 0, 1, 1, 'image', 0, NULL);
