INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7444709508326608896/', 'Join our team 💙', '3w • 3 weeks ago • Visible to anyone on or off LinkedIn', 15, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7411383012526936064/', 'What does a day look like for an engineer powering a real time trading platform? You start by diving into high performance Java services, the engine behind a fast, data hungry UI. You’re not designing interfaces, but you are making them feel effortless by optimising every step of the data journey from backend to browser. One moment you’re profiling latency in a pipeline and the next you’re working with the UI team to streamline how market data is transported, processed, and rendered. You get full access to the stack, real ownership, and the chance to make meaningful performance improvements that traders feel instantly. This trading firm is looking for top java engineers with a passion for performance, strong computer science fundamentals, and Java experience. Trading experience is a required. Sounds exciting? DM me to learn more! daniel@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7443276917161623552/', 'AI is taking over trading Systematic funds have always used models. What’s changed is the impact. Better data. More compute. Stronger models. Faster research cycles. AI is now directly tied to PnL What clients want is very clear: • Engineers who’ve applied AI to live trading strategies, not just trained models, but shipped them. • Researchers from top labs who can turn cutting-edge ML into commercial edge. The skillset? – Deep ML fundamentals – Production grade engineering – Experience with messy, real world data – Understanding of markets, latency and scale The bar is high and an “AI enthusiast” doesn’t cut it... Roles I’m currently working on: • AI Engineer – London (Systematic Fund) • AI Solutions Engineer – London (Global Asset Manager) • AI Engineer / Scientist – Abu Dhabi (Hedge Fund) • Head of ML – Remote (Crypto HFT) • AI Engineer – Abu Dhabi (Prop Shop) • Lead Deep Learning Engineers – Amsterdam (Systematic Fund) AI talent with real applied impact is scarce In trading, scarcity = value daniel@durlstonpartners.com …more', '4w • 0 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7442914518399115265/', 'Spent some time last month in a Performance Lab session with Jeremy Snell - was a good opportunity to step back and ask myself if we are doing enough to get the absolute best out of our team. The session focused on leadership energy, accountability and standards - challenging us to be clearer, more intentional and more consistent in how we raise performance without lowering the bar. There are definitely a few things I think we already do well... but as always, there’s plenty of room to improve. I’ve come away with a lot of ideas to implement off the back of it! Thank you, Jeremy :) …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7420038783322079232/', 'We’re lucky to receive a high volume of applications, so please understand that we’re only able to reach out directly if your profile is a strong match for one of our current openings. In the meantime, do keep an eye on our website and LinkedIn page for new roles, and apply directly where relevant. You’re also always welcome to email hello@durlstonpartners.com with your CV and a brief note on the types of roles you’re targeting - if something suitable comes up, someone from Durlston Partners will be in touch. Thanks so much for your understanding. …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 2, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7442552119993364480/', '🚨 ELITE HIRING - IMMEDIATE MANDATES 🚨 Not average roles. Not average companies. We’re building founding GTM teams, scaling agentic AI in finance, and hiring into high-performance trading environments. NEW YORK / CHICAGO / LONDON 2 Founding Account Executives (Tech) - build it from zero 1 Founding BDR (Tech) - first on the ground Multiple C++ Engineers (Ultra Low Latency) 1 Quant Researcher - Commodities 1 ETF Trader (Equity + Fixed Income) - APAC edge preferred UAE 5 Agentic AI hires (AI Engineers, AI Researchers, Quant Researchers - Finance) 1 Network Engineer (Low Latency, HFT) 1 CISO 1 Product Manager 1 Senior Program Officer These are high-comp, high-visibility, zero-passenger environments. If you’ve: Closed $1M+ ARR Shipped production AI systems Built ultra-low latency infrastructure Generated alpha I want to speak to you this week! DM me directly. Referrals welcomed. Only serious operators. matt@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/rahnpreet-sandhu-2b84a515a', 'https://www.linkedin.com/feed/update/urn:li:activity:7418915181440765952/', 'AI''s Disruption of the Asset Allocation world Whether you''re an LP looking to allocate to GPs, or a multistrategy fund optimising internal strategy allocation, your asset allocation process is likely iterating rapidly with the implementation of AI, and the potential to implement more advanced and continuous predictive analytics, with standardisation, scale and speed. Previously, finding patterns in unstructured data, and moving beyond correlation in financial data to find causality, has been a challenge in this process. Now the latest models can tackle these interesting data sets with speed and scale, allowing more discretionary decisions to be well-informed and efficient. Topics of interest include: - attributing performance to fund alpha vs market beta - alpha decay prediction - crowding risk - regime-based sizing We have clients expanding their footprint in AI-driven Asset Allocation, and the UAE seems to be the fastest growing region for it (larger capital base, faster growing). Please reach out if you''re interest in finding out more, either for roles or hiring Rahnpreet Sandhu hashtag#assetallocation hashtag#gp hashtag#lp hashtag#ai hashtag#hedgefund hashtag#uae …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7442189741808074753/', '𝗔𝗴𝗲𝗻𝘁𝗶𝗰 𝗔𝗜 𝗳𝗼𝗿 𝗙𝗶𝗻𝗮𝗻𝗰𝗲 - 𝗔𝗯𝘂 𝗗𝗵𝗮𝗯𝗶/𝗗𝘂𝗯𝗮𝗶 𝗔𝗜 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿𝘀, 𝗥𝗲𝘀𝗲𝗮𝗿𝗰𝗵𝗲𝗿𝘀 & 𝗤𝘂𝗮𝗻𝘁 𝗥𝗲𝘀𝗲𝗮𝗿𝗰𝗵𝗲𝗿𝘀 In the last month, 5 of my clients have given us new headcount for Agentic AI hiring in the UAE. This spans Engineering, Research and Quant Research roles. Hiring across all levels, junior up to team lead. Comp is very competitive! If you are interested, please message me: rahn@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7441827345516167168/', 'Could an off-the-record chat be one of the small, good choices you make this year? This is pinned on our office fridge. I must open fridge about 10 times a day (usually when Marcus has hidden office treats from himself in there and I go and find them…), but every now and then I actually notice it. Choosing a new role doesn’t feel like a small choice at the time. It’s a big one. There’s risk, unknowns, trade-offs. I remember when I joined DP, I had a couple of strong offers on the table. DP was the only “unknown” route - I’d worked in the finance space but never in recruitment. It felt like a big leap and (to be honest) slightly too good to be true. Nearly six years later, it’s more than lived up to expectations. Of course it hasn’t all been smooth sailing, there have been challenges and growing pains, but I’m so proud of where the team is today and incredibly grateful for the opportunities I’ve been given. I’m ambitious, hardworking and yes, motivated by earning well. But I also love my life... my friends, family, travelling the world, eating incredible food (arguably some of the best places I’ve ever eaten have been with DP). DP has given me the balance of having a role that stretches and rewards me financially, while still allowing me to actually enjoy life. Somehow I managed 15 countries last year and have already ticked off 3 this year. Recruitment isn’t easy... you have to be good to earn well. But at DP we give people a platform, warm desks, real access and the opportunity to fly. What you do with it is up to you. If you’re not happy where you are, and you’re craving more opportunity, balance, and reward, could an off-the-record chat be one of the small, good choices you make this year? My inbox is open :) shannon@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7441464956841168896/', 'This role is not for most ETF traders I''m looking for an ETF trader from a genuinely elite firm... anything else won’t cut it. Profiles in scope: - Equity ETF / Delta 1 - Fixed Income ETF (APAC experience preferred, but not essential) Why people at the top are looking at this: - Multiple millions If money doesn’t motivate you it should, but: - The ability to set up and run your own desk. - More risk, more autonomy, and clear P&L ownership/structure. - Backing to scale if you deliver. - And if we’re being honest, doing this well will be personally and professionally rewarding. This is a serious seat for someone who already knows how the game is played. If this resonates, or you know someone it should, you know where to find me daniel@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7441098797990113280/', '𝗡𝗲𝘁𝘄𝗼𝗿𝗸 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 (𝗟𝗼𝘄 𝗟𝗮𝘁𝗲𝗻𝗰𝘆) - 𝗛𝗙𝗧 - 𝗔𝗯𝘂 𝗗𝗵𝗮𝗯𝗶 One of the first books I read when I started working in this industry was Flash Boys, and the lengths firms would go to (𝘭𝘪𝘵𝘦𝘳𝘢𝘭𝘭𝘺 𝘥𝘳𝘪𝘭𝘭𝘪𝘯𝘨 𝘵𝘩𝘳𝘰𝘶𝘨𝘩 𝘮𝘰𝘶𝘯𝘵𝘢𝘪𝘯𝘴 𝘵𝘰 𝘭𝘢𝘺 𝘴𝘵𝘳𝘢𝘪𝘨𝘩𝘵-𝘭𝘪𝘯𝘦 𝘧𝘪𝘣𝘳𝘦 𝘫𝘶𝘴𝘵 𝘵𝘰 𝘴𝘩𝘢𝘷𝘦 𝘢 𝘧𝘦𝘸 𝘮𝘪𝘭𝘭𝘪𝘴𝘦𝘤𝘰𝘯𝘥𝘴 𝘰𝘧𝘧 𝘢 𝘵𝘳𝘢𝘥𝘦) was crazy to me. That same obsession is what drives the team I’m working with right now. You’ll be joining a tech-first, open-collar team in Abu Dhabi (think ICPC World Finalists and ex-Big Tech architects) with zero red tape and a massive hardware budget. 💼 𝗡𝗲𝘁𝘄𝗼𝗿𝗸 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 💻 𝗟𝗶𝗻𝘂𝘅, 𝗢𝗦𝗣𝗙, 𝗕𝗚𝗣, 𝗠𝘂𝗹𝘁𝗶𝗰𝗮𝘀𝘁, 𝗣𝗧𝗣, 𝗣𝘆𝘁𝗵𝗼𝗻, 𝗲𝘁𝗰. 🌍 𝗔𝗯𝘂 𝗗𝗵𝗮𝗯𝗶 (𝗳𝘂𝗹𝗹 𝗿𝗲𝗹𝗼𝗰𝗮𝘁𝗶𝗼𝗻 𝗮𝘀𝘀𝗶𝘀𝘁𝗮𝗻𝗰𝗲 𝗮𝘃𝗮𝗶𝗹𝗮𝗯𝗹𝗲) 💰 𝗘𝘅𝗰𝗲𝗽𝘁𝗶𝗼𝗻𝗮𝗹 𝗰𝗼𝗺𝗽 𝗽𝗮𝗰𝗸𝗮𝗴𝗲 (𝘁𝗮𝘅-𝗳𝗿𝗲𝗲) 📩 david@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7393656335944503296/', 'This week at Durlston Partners, we have 200+ of the best opportunities across Software Engineering, Portfolio Management, and Quant Trading. With offices in London, New York, and Dubai, we’re often the first to hear about the latest and most exciting projects across AI, Family Offices, Hedge Funds, HFTs, Crypto Trading, and Defence. This week, I’m looking to speak with anyone interested in the following opportunities: Full Stack Engineer for a Defence for Good client in London C++ Engineer (Fully Remote) for an HFT client Data Engineers for a Sovereign Wealth Fund client Please connect or follow for the latest opportunities and news Dana Bahram …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7393927972577058818/', '🌟 So excited for our Women at the Table event today in partnership with the BlueCove team in London! This evening will be a fantastic opportunity to reconnect with others in the space, meet new faces, and hear directly from some of the talented women in BlueCove’s Engineering and Quant Research teams as they share their technical insights and career journeys. 🎤 Our speakers for the evening include: Rhea Potdar - Head of Systems Engineering Rhea leads a team focused on scaling BlueCove across business lines and building the systems that power the firm’s investment process. Prior to joining in 2019, she spent six years at Goldman Sachs as VP in Investment Banking Technology. Diana Fomina, CFA - Quantitative Researcher Diana develops and builds the models that underpin BlueCove’s investment process. Before joining the research team, she worked at Squarepoint Capital and previously as a Quantitative Engineer at BlueCove. Rachel Brown - Quant Engineering Rachel plays a central role in shaping BlueCove’s data strategy and leads the design of its ETL pipeline. Before joining in 2025, she headed up data at Fulcrum Asset Management and began her career at HSBC and Coutts & Co. We’re fully at capacity for this one, but if you’d like to register your interest for future events, please email events@durlstonpartners.com to be added to our list. Can’t wait for what’s set to be another incredible evening of conversation, connection, and inspiration. hashtag#WomenAtTheTable hashtag#DurlstonPartners hashtag#BlueCove hashtag#WomenInFinance hashtag#WomenInSTEM hashtag#Networking …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 10, 0, 3, 'image', 0, NULL);
