INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7391738636297314304/', '𝗦𝘁𝗿𝗲𝘀𝘀𝗲𝗱 𝗮𝗯𝗼𝘂𝘁 𝘆𝗼𝘂𝗿 𝗻𝗼𝗻-𝗰𝗼𝗺𝗽𝗲𝘁𝗲? - Rahnpreet Sandhu 𝗧𝗼𝗽 𝗚𝗲𝗻𝗔𝗜 𝗳𝗶𝗿𝗺 𝗶𝗻 𝗟𝗼𝗻𝗱𝗼𝗻 - $𝟯𝟰𝟬𝗸 𝗯𝗮𝘀𝗲 + 𝗘𝗾𝘂𝗶𝘁𝘆 Short story: Top GenAI firm in London, incredible engineering team (think top 10 global universities, tops of their class, top tech firms etc), looking for best of the best Software Engineers. Great opportunity to move out of finance/trading into a new position, avoiding any lengthy non-competes. 2+ YOE, problem solvers, with strong understanding of multimodal models. High bar, but one of the fastest processes I''ve seen, just 2-3 stages!! Please reach out if you''re interested Rahnpreet Sandhu …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 13, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7391872139995451392/', 'Another AI opportunity for my London network – up to £300k + Equity We’re working with an institutionally backed AI startup operating in stealth mode. The team is building both large-scale LLMs and in-house high-performance systems used to train and deploy them. There is close integration between engineers and researchers, and they are looking to hire Engineers with HPC expertise to optimise every layer of the stack, from software infrastructure to algorithmic efficiency. Given the performance-driven nature of the environment, they have had strong success hiring engineers from HFT backgrounds, either looking to move into AI or stay active during a non-compete. For more information on the role and the team, please reach out at 📧 xander@durlstonpartners.com or connect with Xander Oliver https://lnkd.in/dvc5yRkc …more', '5mo • Edited • 5 months ago • Edited • Visible to anyone on or off LinkedIn', 2, 0, 0, 'image', 0, NULL);
