INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/rahnpreet-sandhu-2b84a515a', 'https://www.linkedin.com/feed/update/urn:li:activity:7407417107266572288/', '𝗗𝗶𝘀𝗰𝗿𝗲𝗲𝘁, 𝗘𝗹𝗶𝘁𝗲 𝗔𝗜 𝗛𝗙𝗧 𝗤𝘂𝗮𝗻𝘁 𝗥𝗲𝘀𝗲𝗮𝗿𝗰𝗵 𝘁𝗲𝗮𝗺𝘀 𝗶𝗻 𝘁𝗵𝗲 𝗨𝗔𝗘 𝘓𝘢𝘵𝘦𝘴𝘵 𝘓𝘓𝘔𝘴, 𝘈𝘐 𝘈𝘨𝘦𝘯𝘵𝘴, 𝘋𝘦𝘦𝘱 𝘙𝘓, 𝘈𝘥𝘷𝘢𝘯𝘤𝘦𝘥 𝘛𝘪𝘮𝘦-𝘴𝘦𝘳𝘪𝘦𝘴 𝘈𝘯𝘢𝘭𝘺𝘴𝘪𝘴 We are working with a few elite AI-driven HFT Quant teams, who have discreetly set up shop in the UAE, coming from top financial hubs such as NYC, London, Amsterdam and Singapore. They''re here to: - capture talent from migration to the region - leverage the cost-effective compute future of the region (cheaper energy) - position for new market expansion (e.g. US firms expanding in APAC markets) They''re targeting the best talent around, and compensation is highly reflective of this, aligning to Tier 1 global salaries. Now is the time to get in early with the best of the best! Please reach out if you''re working on cutting- edge AI Research or Infrastructure across any industry, or the applications to Quant Research and Trading. Rahnpreet Sandhu Durlston Partners …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 0, 1, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7440026738253828096/', 'A few years ago, when clients asked for “options experience”, it usually meant something narrow. One desk. One product. One flavour of risk. That’s not what’s happening now. Over the last few weeks, my inbox has been telling a very different story. Market makers building deeper volatility franchises. Buyside teams leaning harder into optionality as a core return driver. Systematic shops pushing further into index and single stock options. Discretionary funds looking for sharper valuation judgement, not just surface level Greeks. And almost every conversation starts the same way: “Do you know anyone strong in options?” Not pricing only. Not pure vol. But People who can spot a good options trade, explain why it’s good, and actually put the trade on with confidence. What’s striking is the breadth: - Market making and risk taking - Index options and single stock options - Research led and trading led profiles Different strategies, same conclusion: options are no longer a side act. They’re front and centre. Geographically, it’s just as broad. Demand is coming simultaneously from teams in New York, London, Singapore, Hong Kong and the UAE. If you’re an options trader or researcher on the buy side, quietly thinking: “I want more influence over risk” “I want my valuation work to actually matter” “I want to be closer to P&L, or closer to decision making” …you’re not alone. And you’re not imagining the shift. Options talent is hot right now. And the best seats are moving quickly. If this resonates, you know where to find me daniel@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7439649306334208000/', '🚀 NYC SALES BUILDERS - FOUNDING ROLES OPEN 🚀 I’m hiring Founding Sales Talent in New York City for two exceptional opportunities: 🔥 Founding AE + Founding BDR at a tech company already doing strong ARR and ready to scale fast 🦄 Founding AE for AI company - first NY sales hire with huge runway This is for people who want more than “just another sales job.” This is about being early, building from the ground up, and owning real upside. 💰 Competitive Compensation 📈 Meaningful Equity — the kind that actually matters when you join at the founding stage 🏙️ NYC-based ideally, high-impact, high-visibility roles 🤖 Ideal background: SaaS / AI sales, builder mindset, hungry to lead If you’re driven by ownership, growth, and the chance to help shape the future of a category-defining company… Let’s talk. DM me or comment “interested” and I’ll reach out. matt@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
