INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7403749359135121408/', 'We were delighted to partner with BlueCove for this fantastic Women at the Table event earlier this month. A huge thank you to Diana, Rhea and Rachel for such insightful technical talks, and to the whole BlueCove team for being brilliant collaborators throughout. It was a pleasure to bring together so many inspiring finance and technology professionals - and we’re looking forward to hosting more events like this in 2026. https://lnkd.in/eGzWqwvZ …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 8, 1, 1, 'article', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7439313284568125440/', '𝐒𝐞𝐧𝐢𝐨𝐫 𝐑𝐞𝐬𝐞𝐚𝐫𝐜𝐡 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 | 𝐏𝐫𝐨𝐝𝐮𝐜𝐭𝐢𝐨𝐧 𝐋𝐋𝐌 𝐒𝐲𝐬𝐭𝐞𝐦𝐬 | 𝐋𝐨𝐧𝐝𝐨𝐧 | £𝟑𝟎𝟎𝐤 + 𝐄𝐪𝐮𝐢𝐭𝐲 We''re hiring for a very well-funded AI startup with a team from top quant firms, frontier AI labs, and Big Tech. Hard problems: multi-turn reasoning, production reliability at scale, novel post-training approaches. You would be building multi-agent systems that reason reliably across millions of requests daily. Not benchmarks. Production. James@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 6, 3, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7438924465557651457/', 'Back in 2021, the market was loud. Offers were flying. Counter offers were routine. Salaries jumped 20-40% overnight and firms were throwing money at people simply to stop them walking out the door. Fastforward to 2026, and it’s a very different conversation. Firms aren’t hiring “good engineers” anymore. They’re hiring specific problem solvers. Not potential value, not nice to have. But people who can clearly answer one question: 👉 What value will this person bring to the business? That said, we’re not back in the depths of the 2023/24 market either. This isn’t a hiring freeze or we are on hold situation. It’s a selective market, somewhere in the middle. The candidates doing well right now aren’t the ones chasing titles or blanket pay rises. They’re the ones who can: - Articulate impact, not responsibilities - Tie their experience directly to a firm’s needs • Show depth in a niche rather than surface level breadth • Move with intent, not frustration Ironically, this is exactly how you put yourself in a position to recreate the upside of 2021. Strong compensation still exists. Interesting roles still exist. But they’re going to people who are deliberate about when, why, and where they move, not those reacting to the noise. If you’re considering a move and want an honest view of how your profile is landing in today’s market and how to position yourself to maximise it, I’m always happy to talk. No hype. No CV spray and pray. Just straight advice daniel@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7400197688979247104/', 'It’s officially Christmas at Durlston Partners 🎄✨ We’re on the three-week countdown to our annual two-week bonus holiday, but the market clearly didn’t get the memo… it is busier than ever! Interviews are flying in, offers are going out, and we’ve even had starters confirmed before year-end - no signs of slowing down at all. If you’re a candidate exploring your next move, our team has a huge amount live right now. Drop your CV to hello@durlstonpartners.com and one of us will be in touch if we have something relevant for your profile. If you’re a client looking to make the most of December and get ahead of the January hiring rush, we’d love to support you. And if you’re a recruiter in our space… we’re hiring for January starts - next year is set to be a big one. Warm desks, brilliant clients, no restrictions on access to roles or clients, no thresholds, no desk fees, and the ability to plug into our platform and bill from day one. Plus proper incentives and rewards for performance. Exciting end to the year strong and even bigger things ahead. 🎄🚀 …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 10, 0, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7438562077927120896/', '𝗟𝗮𝘁𝗲𝘀𝘁 𝗔𝗜 𝗙𝘂𝗻𝗱 𝗯𝘂𝗶𝗹𝗱𝗼𝘂𝘁 𝗶𝗻 𝗔𝗯𝘂 𝗗𝗵𝗮𝗯𝗶 - relo, strong comp, huge growth! AI Engineers, leveraging Claude code, building rapidly Huge greenfield project in Abu Dhabi, working to rapidly iterate systems that can completely overhaul a reputable fund in the region. The scope here is massive and they are looking to move fast and hire consistently. Reach out if you''re interested, or know someone who will be: rahn@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 3, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7399737508898435072/', 'This month we hosted our latest Women at the Table event in partnership with BlueCove - and what an inspiring evening it was. Women across the tech and trading space joined us for an evening of conversation, connection, and insight. BlueCove - founded in 2018 as a scientific asset management firm bringing together leading investment and engineering professionals to research, develop and deploy state-of-the-art scientific investment processes in fixed income - kindly opened their doors and provided the perfect setting for the night. We were incredibly fortunate to hear from three exceptional speakers from BlueCove: Rhea Potdar, Diana Fomina, CFA & Rachel Brown. Events like this are exactly why Women at the Table exists - to create spaces where women across the investment and technology landscape can meet peers, learn from leaders, and feel seen, supported and celebrated. A huge thank you to the BlueCove team for partnering with us and to everyone who joined us! If you’d like to attend, collaborate, or get involved in the next event, drop us a note at events@durlstonpartners.com. & don''t forget to join our community: https://lnkd.in/eb9-cSGB …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 13, 0, 0, 'video', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7438199712576507904/', '𝗦𝗲𝗻𝗶𝗼𝗿 𝗛𝗣𝗖 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 - 𝗛𝗙𝗧, 𝗡𝗬𝗖 - 𝘂𝗽 𝘁𝗼 $𝟴𝟱𝟬𝗸 I’m hiring a Senior HPC Engineer for a top-tier HFT in New York. They need someone to build the next generation of their research grid. You will be working with ICPC finalists and kernel maintainers to push metal to its absolute limit. 𝗧𝗵𝗲 𝗠𝗶𝘀𝘀𝗶𝗼𝗻: - Architect a high-performance compute environment for simulation. - Deep dive into OS internals and memory management. - Write tooling in Python to automate everything. 𝗧𝗵𝗲 𝗢𝗳𝗳𝗲𝗿: - $500k - $800k TC. - Relaxed, engineering-first culture. 📩 david@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 1, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7396501697398726656/', 'A huge thank you to everyone who joined us at our 100 Hedge Funds event in Dubai earlier this month. The room was packed with brilliant people across hedge funds, trading, fintech, and digital assets, and the energy reflected the momentum building in the region. We’re excited to keep building spaces where this community can connect, collaborate, and share ideas. If you’d like to get involved - whether attending, partnering, or contributing - we’d love to hear from you. Upcoming events: • 100 Hedge Funds – Abu Dhabi (February) • 100 Hedge Funds – Dubai (March) • Women at the Table – London (TBC) • 100 Hedge Funds – London (April) • 100 AI Firms – London (May) To attend, sponsor, or get involved: events@durlstonpartners.com. You can see more photos here: https://lnkd.in/enCX2-ya …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 28, 2, 2, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7437837324991877120/', '𝗖𝗠𝗘 𝗙𝘂𝘁𝘂𝗿𝗲𝘀 𝗤𝘂𝗮𝗻𝘁 𝗧𝗿𝗮𝗱𝗲𝗿/𝗣𝗠 𝗵𝗶𝗿𝗶𝗻𝗴 - 𝗗𝘂𝗯𝗮𝗶 𝗼𝗿 𝗨𝗦 𝗕𝗮𝘀𝗲 + 𝗖𝗹𝗲𝗮𝗿 % 𝗼𝗳 𝗣𝗻𝗟, 𝘄𝗶𝘁𝗵 𝘀𝗰𝗮𝗹𝗶𝗻𝗴 𝗰𝗮𝗽𝗶𝘁𝗮𝗹 𝗮𝗻𝗱 𝘀𝘁𝗿𝗼𝗻𝗴 𝗶𝗻𝗳𝗿𝗮 I''m working with a client to onboard Systematic CME Futures PMs to their new LL co-located trading platform, with a focus on both HFT and MFT strategies. They need Quants with existing strategies, and can help you get up and running, within 4-5 months max. 3+ sharpe is required, and PnL pay-outs are tier based on sharpe, with the upside being huge here. Interview process is quick, led by performance and interviews that focus on what you do, less of a theoretical code heavy interview style (yes, no leetcode here). Comp: Competitive base + % of PnL (based on sharpe) Please reach out if this if of interest, or if you have any referrals (well-rewarded). rahn@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7396098566450212864/', 'Durlston Partners 100 Hedge Funds Event - Dubai 🇦🇪 What an evening! This month we hosted our 100 Hedge Funds event at Sexy Fish DIFC, and it was absolutely incredible - a massively oversubscribed night bringing together some of the most brilliant minds in the region. The energy in the room was electric and a real reflection of the momentum and appetite for growth in the UAE. It’s an exciting time to be here, and we’re proud to be part of building this community. Huge thank you to our amazing partners - IG Prime, HAS Law Firm, and Paragon Consulting Partners! We’re already planning future events across London, Dubai, Abu Dhabi, and New York, so if you’d like to attend, sponsor, or get involved, drop us a message or email events@durlstonpartners.com and we’ll keep you posted. …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 16, 0, 2, 'video', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7394294750998134784/', 'Another fantastic evening last night co-hosting with BlueCove for our latest Women at the Table event 💫 Interesting presentations, great conversations, and some truly inspiring women in the room. A huge thank you to the BlueCove team for partnering with us - it’s been such a lovely collaboration, and the energy on the night was fab. For those unfamiliar, Women at the Table is all about visibility, connection, and conversation... bringing brilliant women together across tech, trading, and finance! Massive thank you again to everyone who joined us, to Natalie and the BlueCove team for hosting, and to our brilliant speakers. If you’d like to be invited to future Women at the Table events, drop a note to events@durlstonpartners.com and make sure you join our community: https://lnkd.in/e8EXxtFm we’d love to have you at the next one. …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 25, 7, 2, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7437452314929487872/', 'Lead Python Engineer (USD300k+); UAE We have a pretty unique opportunity for a Python Engineer to work directly with the founder of an algo trading business in the UAE. It''s unique because your reporting line will be directly to them, so if you want to learn the ins and outs of algo trading, few opportunities will come close. What this will look like on a day to day basis is taking algo trading models for DeFi from ideation, through to deployment and then optimisation. I can already hear the screams of Engineers with expertise of lower-level languages; "WHY ARE THEY USING PYTHON?" Well, this is because for this role, you''ll effectively be the research and engineering brains for the DeFi strategies. The speed the founder is looking for here, is speed to deploy the idea, not the speed of the idea itself. You will not need to have worked in any form of trading firm before, but the firm will be looking for you to have knowledge of the following (in Python): - sync/await patterns - scalability - performance tuning This role will require you to relocate to the UAE full time. 📩 warwick@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 1, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7437112617011314689/', 'On the hunt for elite Quant Researchers across several top tier firms in New York These are opportunities with several top tier firms to work on real alpha problems, with serious infrastructure, long runways, and teams that still value original thinking. Here are the profiles I’m actively headhunting for: 𝗜𝗻𝘁𝗿𝗮𝗱𝗮𝘆 𝗦𝘁𝗮𝘁-𝗔𝗿𝗯 𝗤𝗥𝘀 - NYC Researchers working on minutes to hours horizons, with a strong focus on signal research and alpha generation. Seconds level experience can be relevant 𝗠𝗼𝗻𝗲𝘁𝗶𝘀𝗮𝘁𝗶𝗼𝗻 / 𝗣𝗼𝗿𝘁𝗳𝗼𝗹𝗶𝗼 𝗤𝘂𝗮𝗻𝘁𝘀 - NYC Profiles focused on alpha blending, optimisation, portfolio construction, and turning research into scalable PnL in equities 𝗙𝘂𝗻𝗱𝗮𝗺𝗲𝗻𝘁𝗮𝗹 / 𝗔𝗹𝘁-𝗗𝗮𝘁𝗮 𝗤𝗥𝘀 - NYC Systematic researchers using non market data to generate differentiated signals within stat-arb frameworks 𝗠𝗮𝗰𝗵𝗶𝗻𝗲 𝗟𝗲𝗮𝗿𝗻𝗶𝗻𝗴 𝗤𝘂𝗮𝗻𝘁𝘀 - NYC Industry experience is ideal, but exceptional applied ML researchers from senior IC levels in tech or AI first environments are very much in line 𝗖𝗼𝗺𝗺𝗼𝗱𝗶𝘁𝗶𝗲𝘀 𝗤𝘂𝗮𝗻𝘁𝗮𝗺𝗲𝗻𝘁𝗮𝗹 𝗤𝗥𝘀 - NYC/SG Semi-systematic researchers combining discretionary intuition with systematic tools, focused on commodities 𝗘𝘅𝗲𝗰𝘂𝘁𝗶𝗼𝗻 𝗤𝘂𝗮𝗻𝘁 𝗥𝗲𝘀𝗲𝗮𝗿𝗰𝗵𝗲𝗿𝘀 - NYC/London Researchers specialising in market impact, execution quality, and microstructure as a source of edge If you’re a high calibre quant who’s quietly open to hearing what the top end of the market looks like right now, my DMs are open. daniel@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7391087342763212801/', '**Huge Growth Opportunities** ~ Founding DevOps Engineer (NYC) - First DevOps hire! - Strong AWS experience, Python, CI/CD - DevOps/Infrastructure engineering - Experience at a startup, small-midsize preferred - Strong software engineering fundamentals, ability to debug/optimize systems ~ Multiple Software Engineers (NYC or SF) - Python, Java, or GO exp - 1-3+ years of experience ~ Full Stack SWE (NYC or SF) - Python + React exp - 1-3+ years of experience ~ Data Engineer (NYC) - Experience building ETL pipelines - Founding engineer or co-founding experience is a plus ~ AI Operations (NYC) - Recent grads with STEM degrees (3.6/4.0 GPA or higher) ~ SDR (NYC) - Recent grads with some sales background ~ General Manager - Healthcare (NYC) - Lead and develop a high-performing cross-functional team - 8+ years of experience, including leadership roles at early-stage startups and in high-growth environments - consulting background is a plus ~ Mid-Market Account Executive Location: NYC / Chicago / Boston / SF Compensation: OTE $320k ($100k base) - Minimum 2+ years in a quota-carrying role at a SaaS startup - Proven track record of achieving an annual quota of $800k+ ~ Enterprise Account Executive Location: NYC / Chicago / Boston / SF Compensation: OTE $370k ($115k base) - Minimum 2+ years in a quota-carrying role at a SaaS startup - Proven track record of achieving an annual quota of $1.2M+ ~ Strategic Account Executive Location: NYC / Chicago / Boston / SF Compensation: OTE $430k ($130k base) - Minimum 4+ years in a quota-carrying role at a SaaS startup - Proven track record of achieving an annual quota of $1.6M+ DM if interested (*no third parties please*) matt@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 4, 2, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7391027086913667073/', 'Touched down in Dubai ahead of our 100 Hedge Funds event this Thursday - and we’re already at 160+ confirmed guests from across the market. The hedge fund landscape in the UAE has transformed over the last few years, and we’ve been incredibly fortunate to sit right at the heart of it, partnering with firms across Dubai and Abu Dhabi to help build world-class quant, tech and investment teams. This event is all about celebrating that growth, connecting the community, and continuing to push the region forward as one of the most exciting global hubs for systematic investing. If you''re in the HF/quant/tech space and haven’t registered yet, drop me a message - very limited spots remaining. Looking forward to a brilliant evening... and to a week of sunshine, face-to-face meetings and spending time with the Dubai team ☀️ …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 0, 0, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7436746388857798656/', '𝗧𝗿𝗮𝗱𝗲 𝗙𝗹𝗼𝗼𝗿 𝗦𝘂𝗽𝗽𝗼𝗿𝘁 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 - 𝗛𝗲𝗱𝗴𝗲 𝗙𝘂𝗻𝗱 - 𝗔𝗯𝘂 𝗗𝗵𝗮𝗯𝗶 I am working with a leading Hedge Fund in Abu Dhabi looking for a Desktop Support Engineer to own their Windows environment on the trading floor. You will be the "go-to" person for PMs and Traders, handling everything from Bloomberg terminal connectivity to complex network issues. 🌍 𝗟𝗼𝗰𝗮𝘁𝗶𝗼𝗻: Abu Dhabi (full relocation assistance available) 💰 𝗖𝗼𝗺𝗽: $150,000 TC (tax-free) 💻 𝗧𝗲𝗰𝗵: - Windows 10/11 ecosystem - Active Directory & SCCM - Bloomberg Terminal & Market Data connectivity - Network troubleshooting - Scripting experience (PowerShell, Python, Bash) 𝗠𝘂𝘀𝘁 𝗛𝗮𝘃𝗲𝘀: - Experience in a fast-paced trade floor environment (Buy-Side preferred). - Ability to handle high-pressure situations with composure. 📩 david@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 3, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7388574638500622336/', 'Just two weeks to go until our next Women at the Table event in partnership with BlueCove. We’re excited to announce our next speaker, Rachel Brown. Rachel is an Engineer in BlueCove’s Quant Engineering team, where she plays a central role in shaping the firm’s data strategy. She has designed and implemented BlueCove’s Extract, Transform, and Load (ETL) pipeline for the firm’s Data Warehouse and works closely with teams across the business to unify data services that underpin investment and research processes. Before joining BlueCove in 2025, Rachel led the data function at Fulcrum Asset Management, overseeing a major transformation of the firm’s data ingestion, validation, and delivery pipelines. Prior to this, she worked as a data science consultant within HSBC’s Capital Finance and Investment Bank, and she began her career with an internship at Coutts & Co, a UK-based private bank. Rachel holds an MEng in Engineering from Imperial College London. We’re looking forward to hearing from Rachel and the other incredible women at BlueCove as they share their experiences and insights on the night. 📅 Date & Time: Tuesday 11th November, from 6pm 📍 Location: Mayfair, London …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 16, 1, 2, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7436383989789085697/', 'Keeping the memes coming; come build AI Agents for a trading firm in the UAE. I typically refuse to reduce a job-spec to the game of key-word bingo, however in this instance our client is explicity looking for people with the following expertise of AI: - Multi-agent - ReAct Agent - Deep Research Agent - LangGraph - MCP For them, a full-house of these skills is the holy-grail, however they''re keeping an open mind. The extent to which their mind can be open will be influenced by other factors like; previous work experience, publications and/or excellent academics. For more information, please reach out! 📩 warwick@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 5, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7386794047790665728/', 'Just over three weeks to go until our next Women at the Table event in partnership with BlueCove. We’re delighted to announce our next speaker, Diana Fomina, CFA, Quantitative Researcher. Diana is a member of BlueCove’s Quantitative Research team where she works to develop and build the models required for the firm’s investment process. Prior to joining BlueCove’s Research team in 2022, Diana was a Quantitative Researcher at Squarepoint Capital from 2021–2022 and a Quantitative Engineer at BlueCove from 2019–2021. In 2015, Diana won silver medal in the International Tournament for Young Mathematicians and bronze medal in the European Girls’ Math Olympiad. Diana received her BSc in Applied Mathematics and Computer Science from Lomonosov Moscow State University in 2019. Diana is also a CFA charterholder. We can’t wait to hear from Diana and others on the night, and to welcome another fantastic group of women in the space. There are still a few spots left - email events@durlstonpartners.com if you’d like to attend. 📅 Date & Time: Tuesday 11th November, from 6pm 📍 Location: Mayfair, London Also, remember to join our Women at the Table community on LinkedIn! https://lnkd.in/eb9-cSGB …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 8, 0, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7386304966258503680/', 'You know Christmas is coming when the Regent Street angels go up ✨ (photo right outside of our office). Ready for the chaos of Christmas over the next few months… with the dark nights setting in early, the lights make the city feel a bit more magical. As ever, feeling lucky to work on one of the most iconic streets in London. The team are pushing for a super strong end to the year with plenty lined up for 2026 before switching off properly during the two weeks of bonus Christmas leave everyone gets. I’m taking a slightly longer break myself over Christmas, but between now and then I’m keen to speak with experienced recruiters in our space. We’ve got a ton of exciting stuff happening across London, Dubai, and New York - and a platform you can plug straight into and start billing big right away. At Durlston Partners, we’re a leading tech and trading search firm partnering with some of the world’s top hedge funds, HFTs, fintechs, prop shops, and asset managers, hiring across quant, tech, data, AI/ML, and digital assets. We offer market-leading commission, no thresholds, caps, or desk fees, plus cash bonuses, profit share, and equity opportunity. Desks are genuinely warm, relationships are deep, and our average fee per placement is high, with plenty of deals way north of six figures. All the usual good stuff in terms of benefits: two-week Christmas bonus break, health insurance, wellness allowance, team lunches, and global incentives - it’s a strong setup for ambitious recruiters. Even if you’re not actively looking, always happy to have an informal chat. There’s also the option to relocate to Dubai if sunshine and tax-free commission sound tempting ☀️ hashtag#DurlstonPartners hashtag#Hiring hashtag#Tech hashtag#Quant hashtag#AI hashtag#Recruitment hashtag#Finance hashtag#TeamDP hashtag#London hashtag#Dubai hashtag#NewYork …more', '6mo • Edited • 6 months ago • Edited • Visible to anyone on or off LinkedIn', 11, 0, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7436002724527304704/', '𝗛𝗶𝗿𝗶𝗻𝗴: 𝗔𝗴𝗲𝗻𝘁𝗶𝗰 𝗔𝗜 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 (𝗨𝗦𝗗 100,000–200,000) 𝗔𝗯𝘂 𝗗𝗵𝗮𝗯𝗶, 𝗨𝗔𝗘 | Full-time | Onsite | Relocation Supported An elite AI Quant team in Abu Dhabi is hiring an Agentic AI Engineer to design and scale autonomous, multi-agent AI systems. This is not a generic AI or prompt-engineering role. You’ll build next-generation ML and AI frameworks that power research and trading platforms, working with foundation models, ReAct-style agents, and structured agent orchestration (e.g. LangGraph). 𝗟𝗼𝗼𝗸𝗶𝗻𝗴 𝗳𝗼𝗿: • Hands-on experience with LLMs / foundation models • Strong Python skills in a Linux environment • Experience with multi-agent systems and reasoning-based agents • Multi-GPU / distributed training or large-scale experimentation • Interest in agentic systems, research workflows, and performance-focused engineering No finance background required. 𝗪𝗵𝘆 𝘁𝗵𝗶𝘀 𝗿𝗼𝗹𝗲: Real ownership, flat structure, serious compute, and Abu Dhabi as a core AI hub, not a satellite office. 📩 𝗜𝗻𝘁𝗲𝗿𝗲𝘀𝘁𝗲𝗱? Message dana@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 83, 8, 2, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7349383923036045312/', '𝐒𝐧𝐚𝐩𝐬𝐡𝐨𝐭 𝐨𝐟 𝐧𝐞𝐰 𝐐𝐮𝐚𝐧𝐭 / 𝐏𝐌 𝐨𝐩𝐩𝐨𝐫𝐭𝐮𝐧𝐢𝐭𝐢𝐞𝐬 - 𝐀𝐏𝐀𝐂 / 𝐔𝐒 / 𝐄𝐮𝐫𝐨𝐩𝐞 💻 Role: PM – Fully Automated Options/Futures Strategies 📍 Location: US / Europe Timezone (Remote/Hybrid) 💰 Package: ~$3m 🌟 Details: Leading prop shop offering generous guarantees and PnL splits to experienced PMs and researchers running fully systematic Futures, Options, or Equities strategies across HFT and MFT timeframes. Fully remote in US or Europe. Infra includes an impressive GPU and CPU cluster with sub-100 ns tick-to-trade latency, optimised for rapid deployment and minimal time-to-market. 💻 Role: Fixed Income ETF Trader – New Desk Build 📍 Location: Sydney (Onsite, relocation supported) 💰 Package: $2m – $3m 🌟 Details: A global market maker is launching its first Fixed Income ETF desk in APAC, expanding from a dominant Equities ETF presence. This is a greenfield build with direct ownership of quoting, execution and risk, working closely with quant and tech teams. 💻 Role: HFT Quant Researcher – Fully Systematic Strategies 📍 Location: APAC (Onsite, relocation supported) 💰 Package: $1m – $3m 🌟 Details: Global market maker growing its fully systematic HFT research team. They are seeking entrepreneurial black-box PMs/QRs who can bring scalable, liquid strategies with full IP lift-out potential and guaranteed comp to de-risk the move. 💻 Role: Futures Trader – High/Mid-Frequency Market Making 📍 Location: Chicago / Amsterdam (Onsite) 💰 Package: $650k – $750k 🌟 Details: New build-out of an MFT Futures desk within a highly profitable market-making team. Focused on fully systematic intra-day Futures trading (seconds to hours) across all liquid markets, predominantly Equities. 💻 Role: Quant Researcher – End-to-End Fully Automated 📍 Location: Global (Remote/Hybrid) 💰 Package: $750k+ 🌟 Details: Same team scaling its systematic research bench. Researchers will own strategies end-to-end, deploying double-digit Sharpe market-making strats across Options, Futures and Equities within a flexible pod setup. Fully supported by a high-capacity infra stack. 💻 Role: Rates Trader – Global Rates Desk 📍 Location: London (Hybrid) 💰 Package: £450k – £550k 🌟 Details: Proprietary trading firm adding to its London Rates desk with a focus on STIRs Options (Euribor/SOFR). This is a core team within their global Rates coverage, combining voice and electronic execution with active risk management. For more information about these and our other opportunities, please reach out to me: 👉Xander Oliver👈 📧 xaner@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 10, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7384155886572687360/', 'We’re excited for our upcoming 100 Hedge Funds Event in Dubai (DIFC) on 6th November! The hedge fund scene in the UAE has exploded - now home to over 150 funds across Dubai and Abu Dhabi - and we’ve been fortunate to help build many of them. This event will bring together leaders from across the industry for an evening of conversation, connection, and celebration of the region’s rapid growth. If you’d like to find out more or request an invite, please reach out to events@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 19, 0, 3, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7435640342990819328/', '🚀 Hiring for one of the most elite ultra-low latency HFT firms globally 💲 Multiple $1M–$5M+ roles We’re partnering with a top-tier prop trading firm running ULL high-frequency strategies across global markets, powered by in-house technology, elite research, and a team that includes ICPC, IOI, and IMO champions. 𝐋𝐢𝐯𝐞 𝐦𝐚𝐧𝐝𝐚𝐭𝐞𝐬 𝐢𝐧𝐜𝐥𝐮𝐝𝐞: ➕ Deep Learning Team Lead - Applied AI leadership from elite organisations. ➕ Senior Deep Learning Researcher - Advanced DL and Multi-Agent Reinforcement Learning. ➕ Senior HFT Quant Researchers - HFT expertise required; remote possible. ➕ Senior HFT / MFT Quant Researchers - Ongoing hiring pipeline. These are rare, top-of-market opportunities for candidates operating at the highest level in quant, HFT, and AI. jared@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7345024484556349440/', '🏆 ICPC Finalists? IOI Medallists? Let’s Talk If your background is in competitive programming (ICPC finalists, IOI, IMO, IPhO etc.). Then I have something you can be obsessed with and build it from the ground up, I’m working with a stealthy AI startup that’s doing something pretty incredible. They’re building software infrastructure that allows everyday users to train AI models, powered by the combined computing power of personal devices. Think distributed AI training, made simple. 🌍 London HQ (open) 🧠 Backed by top investors and led by technically elite founders They’re hiring grads (yes, grads!) for: - Software Engineers / ML Engineers - Machine Learning Researcher Must have: Background in competitive programming (ICPC finalists, IOI, IMO, IPhO etc.) 💸 Compensation: Up to £170k base + Equity 🛂 Sponsorship: Yes If you’re a world-class problem solver and want to build from zero with people who move fast and think big, then message me. daniel@durlstonpartners.com hashtag#ai hashtag#graduates hashtag#ml hashtag#icpc hashtag#ioi hashtag#hiring …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7435277978286071808/', 'Two genuinely interesting roles just landed on my desk this morning - Role 1: Jr/Mid Quant Developer (Rust) This team builds the infrastructure that keeps the platform running, ingesting real time market data, consolidating positions and pricing, and making sure PMs, Ops, Risk and Treasury all see clean, reliable information. It’s not a research role and not Python only. This is for someone who enjoys proper engineering. They’re open to developers from Java, C# or C++ backgrounds who want to move into Rust and work closer to trading systems. Strong fundamentals in memory, algorithms and backend architecture really matter here. - Role 2: Senior Quant Developer – Equities A systematic equities fund where technology directly drives performance. You’d be working across research, large scale data processing and live trading systems, partnering closely with quants and owning components that actually impact PnL in production. Strong Python and computing experience is essential, alongside a genuine understanding/experience of equities. Both teams are moving quickly and interview slots are already being lined up. If you’re curious, message me before these processes inevitably get flooded. daniel@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7434915549949726721/', 'An honest take on the market for candidates right now 👇 AI is genuinely booming. Not in a buzzwordy way, the fact that teams are actively hiring way. The loudest demand I’m seeing is for engineers with real GenAI and LLM experience, particularly where it’s being applied to trading, research, and decision making rather than experimentation for experimentation’s sake. Firms want people who can ship, not just talk about prompts. At the same time, nothing has dethroned C++. It’s still king. I’m consistently working with clients looking for strong C++ engineers with experience in low latency systems, exchange connectivity, and performance critical infrastructure. That market hasn’t slowed down, if anything, the bar has just kept rising. Crypto is also no longer a “maybe”. It’s institutional now, and it’s here to stay. The firms operating seriously in this space are building long term platforms, not short term bets, and they’re hiring accordingly. The common thread across all of this? Applied skill. Candidates who can point to what they’ve built, optimised, or deployed are cutting through far faster. Curious to see if others are seeing the same shift. daniel@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7434548318707298305/', 'Keen to speak with C++ Engineers who are interested in relocating to Dubai to work in algorithmic trading. The firm you''ll be joining, values strong tenure in your previous positions, however they''re willing to be open minded about the industry you may have worked in before. If you''ve not worked in HFT before, here are a list of things they''ll be interested to hear you''ve encountered before: - minimising hot-path latency (professionally or in your own time) - building high-throughput systems - reducing jitter - direct hardware interaction This company provides full relocation support and sponsorship to ensure you get up and running in Dubai as easily as possible! 📩 warwick@durlstonpartners.com …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 7, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7376288345464938496/', 'T-minus 1 week until our next run club!! The countdown is on! 🚀 Our next run is just around the corner, and the buzz is real after our amazing first event. Get ready to lace up and hit the pavement again on Tuesday, 30th September! Here are the key details: 𝗧𝗶𝗺𝗲: Meet 6pm sharp 𝗠𝗲𝗲𝘁𝗶𝗻𝗴 𝗣𝗼𝗶𝗻𝘁: Durlston Partners office (Bag Drop) 𝗥𝗼𝘂𝘁𝗲: A scenic loop around St James’s & Green Park. 𝗣𝗮𝗰𝗲: A relaxed, chatty pace. Everyone is welcome, no matter your speed. 𝗣𝗼𝘀𝘁-𝗥𝘂𝗻: We''ll refuel with a pint at a nearby pub, hope you can join! Sign-up: https://luma.com/pzqn2im0 I can''t wait to see you all there for another great one! Let''s go! 🏃‍♀️🏃‍♂️ …more', '7mo • Edited • 7 months ago • Edited • Visible to anyone on or off LinkedIn', 4, 0, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7434236526588428289/', 'Like most, I''ve been watching events unfold over the weekend, and thoughts are with those directly affected. From London, we’ve been in contact with our team in Dubai, as well as clients and candidates across the UAE. Everyone is safe. While the headlines feel heavy, day-to-day life continues for many. There’s understandably a lot of noise online - we’d encourage our network to rely on verified sources and official guidance rather than unconfirmed clips or AI-generated content. For our clients and candidates: We are here. Processes are continuing. Communication lines remain open. We’re thinking of those more directly impacted and hoping for de-escalation and stability as soon as possible. …more', '1mo • 1 month ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
