INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7384156919097356288/', 'We’re excited for our upcoming 100 Hedge Funds Event in Dubai (DIFC) on 6th November! The hedge fund scene in the UAE has exploded - now home to over 150 funds across Dubai and Abu Dhabi - and we’ve been fortunate to help build many of them. This event will bring together leaders from across the industry for an evening of conversation, connection, and celebration of the region’s rapid growth. If you’d like to find out more or request an invite, please reach out to events@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7365673047032307712/', 'If you missed our first Industry Run Club but want to be part of the next one, drop a note to events@durlstonpartners.com and we’ll keep you posted once the next date is locked in.🏃‍♀️🏃‍♂️ hashtag#RunClub hashtag#FinanceAndTech hashtag#NetworkingButFun hashtag#DurlstonPartners hashtag#TeamDP …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'video', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7371535225136517121/', '🚀 We’re hiring in London and Dubai. At Durlston Partners we partner with some of the most exciting names in the fintech, quant and AI/ML space. New joiners hit the ground running thanks to warm desks and long-standing client relationships. What sets us apart? A commission structure that genuinely rewards performance (10-40% with no desk fees, thresholds or draws), extra incentives for new business, meaningful profit share and equity, plus perks like private health & dental, wellness allowances, two bonus weeks off over Christmas, regular socials and international trips. We’re ambitious and high-performing, but also collaborative and fun - the kind of place where you’ll learn fast, earn well, and enjoy coming to work. We’re looking for experienced consultants (3+ years) in tech or quant recruitment who want to take their career to the next level, as well as juniors with 1–3 years’ experience who are curious, driven and keen to plug into a strong platform. If you’re ready to bill big, earn big and be properly rewarded, drop me a message for a confidential chat. shannon@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 14, 1, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7369041585663053827/', 'Quant Recruiters in the US, this one’s for you. I’m working with a rapidly scaling global trading firm who operate fully remotely - they''re looking for an exceptional Quant Recruiter with a strong network of Traders and QRs. This role is fully remote but requires you to be based in the US. Compensation is very competitive, with strong performance-based bonuses on top. Open to speaking with both experienced agency recruiters and those working internally who might be curious! If this sounds like you (or someone you know), please get in touch. Referrals are always welcome, and well rewarded. …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 5, 0, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7323715355636363265/', 'Brilliant write-up of one of the speaker sessions from our Women at the Table event last week! Go Teagan Hill! https://lnkd.in/e8Hbm6ec …more', '11mo • 11 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7432443019674677249/', '"Crypto HFT" really has come a long way in a short time. I remember sitting down with a well known OG in the space back in 2017 which went live with market connectivity written entirely in Python. Back then, you didn''t need to be fast as your compadres in TradFi. After all, the big attraction was the lower barrier to entry as well. Start small and stack your wins*. "What happens when latency becomes more of a concern?" "We''re already limited by API throttling as it is. So we don''t need anything faster than Python." Oh how that''s changed. We''re now at a point where some crypto trading firms are hiring Network Engineers to reduce latency by leveraging microwave links and point-to-point optical links. This means that the programmers are no longer constrained by the limits of 2017 infrastructure and in turn, the companies who are hiring now want programmers whose expertise is in systems which are nanosecond fast (micros at a minimum). For some this is could be considered overkill but to others, this simply looks like future proofing their proprietary infrastructure before the upgrades come from the exchanges. It''s a particularly interesting vantage point to have and in some ways a sad realisation. That low barrier to entry which attracted so many people to crypto less than a decade ago, has increased pretty dramatically. The competition out there is therefore: - Crypto native trading firms (first movers) who upgraded along the way. - TradFi HFTs with the balance sheet to compete with the first movers. 2026 will be interesting indeed! 📲 TG @cryptowarwick 📩 warwick@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7432080646929494016/', '𝗠𝗲𝗲𝘁𝗶𝗻𝗴𝘀 𝗶𝗻 𝘁𝗵𝗲 𝗗𝗜𝗙𝗖 𝗮𝗻𝗱 𝗔𝗗𝗚𝗠 𝘛𝘩𝘪𝘴 𝘸𝘦𝘦𝘬: 𝘋𝘐𝘍𝘊 𝘛𝘶𝘦𝘴𝘥𝘢𝘺 𝘗𝘔, 𝘈𝘋𝘎𝘔 𝘞𝘦𝘥𝘯𝘦𝘴𝘥𝘢𝘺 𝘗𝘔 This year I am scheduling 2 afternoons/evenings each week just for meetings in the ADGM and DIFC, especially in the busy season. This week will be Tuesday in the DIFC and Wednesday in the ADGM. I''m keen to discuss the market we cover, and how we can help both candidates and hiring teams in the region: - Candidates - happy to give an overview of the market, cut through the BS with a realistic plan of attack for your next move and answer any other questions you have. - Hiring teams - give an overview of the firms moving in the market, discuss any hiring challenges, and most importantly, advice on the hiring strategy that can work for your needs. - Launching/new funds - we have assisted multiple funds in building from scratch, all the way from hiring founding team members, to advising on build-out plans and then executing on delivering the best talent. Feel free to reach out if you''re interest - coffee/late lunch/dinner on me! rahn@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7362018976089972738/', '♟ Checkmate. How do you connect with your recruiters? Siva Keefe Savero’s been mixing things up - taking on clients and candidates at chess (and occasionally schooling some of the DP team in the office too). Last week we caught up with a client by racing cars at the F1 Arcade, and next week we’re hosting our first-ever industry Run Club. So whether you’re into chess, F1, running… or just an old-fashioned drink outside a packed pub in central London, we’re here for it. The weather’s looking hot for the next couple of weeks... if you fancy meeting up, drop us a line. Run Club is next Wednesday eve... link below if you want to join us. 🏃‍♀️🏃‍♂️ https://lnkd.in/e_6x2YUb Durlston Partners hashtag#Chess hashtag#F1 hashtag#RunClub hashtag#FinanceAndTech …more', '8mo • Edited • 8 months ago • Edited • Visible to anyone on or off LinkedIn', 21, 0, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7361341267642830848/', 'Due to exceptional client demand, we’re looking for an experienced Quant Recruiter to join the Durlston Partners team. Ideally, you’ll have 2–3+ years’ experience placing into HFTs, prop shops, or other buy-side firms. We want someone who’s hungry, collaborative, and ready to make placements - and be well rewarded for it. We partner with some of the most exciting names in the industry, covering quant, tech, data, AI/ML and digital assets. We work with hedge funds, HFTs, prop shops, fintechs and asset managers globally, with offices in London, New York, and Dubai. Offer genuinely warm desks, deep client relationships, and the platform to set you up for success from day one. You’ll get: market-leading commission with no thresholds, caps, or desk fees, meaningful profit share, cash BD incentives and bonuses, top-tier clients and no internal restrictions on access to them, support to shape your growth, perks like a two-week Christmas break, BUPA cover, £1,200 wellness/phone allowance, regular socials, and global incentives. If this sounds like you or someone you know, drop me a message or email shannon@durlstonpartners.com for a confidential chat. …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 13, 0, 3, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7431718239140958208/', 'Quant Portfolio Manager who''s tired of running risk? We have something for you in the UAE. We''re working with a fully systematic trading firm which is looking at hiring (ex-) Quant PMs, who would be interested in a Data Research seat. I don''t have to tell you why you''re relevant, you already know. What I am selling here is a company which is not going to look at you stepping down from running risk as a step back in your career, they actively want to hire you if you''d like to step back from trading. They value your experience in actually knowing which data research efforts move the proverbial PnL needle and will be just as much about what not to do, as it will be doing what absolutely has to be done. 📩 warwick@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7360627347986784256/', 'Fancy a relocation to Dubai? ☀️🌴 4 of our London team have made the move over the last few years and haven’t looked back... the sunshine is guaranteed, and the tax-free comp is life-changing. We’re urgently looking for someone to join our Dubai team, driven by exceptional client demand across tech and quant finance. You could already be based in Dubai, start in London with a plan to relocate, or we can support a move right away. At Durlston Partners, we’re a high-performing team of 21 with offices in London, New York and Dubai. We work with the most exciting names in tech & trading, hedge funds, HFTs, asset managers, prop shops and fintechs, placing across quant, tech, data, AI/ML, and digital assets. We offer market-leading commission (no desk fees or thresholds), BD incentives, bonuses, and meaningful profit share. Full access to clients and roles from day one (no internal politics or restrictions). Warm desks, amazing team culture, training, socials, and global incentives. If you or someone you know might be keen to join the Dubai office, drop me a message or email: shannon@durlstonpartners.com Sharing a few pics from trips to Dubai... next one coming up soon! …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 47, 1, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7430627329028141056/', 'I specialise in search across the hedge fund and the trading space, focusing on quants, traders, and engineers. I work with a mix of Tier 1 firms and highly selective, lower profile funds that don’t advertise but do serious work. My remit is global, with active mandates across London, New York, Dubai, Singapore, Shanghai, and other key financial hubs. Last year alone, I’ve supported moves to Dubai, placed quants into roles with real ownership and influence, and helped traders step into higher risk, higher impact seats. My approach is straightforward: honest market insight, selective processes, and long term thinking for both candidates and clients. If you’re already operating in the space and open to a discreet conversation or pint, feel free to reach out. daniel@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/vicktandon', 'https://www.linkedin.com/feed/update/urn:li:activity:7354499523877969920/', 'Two incredible weeks here at Durlston Partners. A few senior Quant PMs we represent are on the verge of receiving offers—creative deals are being structured—as the quantitative markets face a turbulent summer. The "long, slow bleed" highlighted in Business Insider has triggered a wave of conversations on both sides. Clients are asking who''s up, who''s down, and how to position themselves in this shifting landscape. At the same time, we''re speaking to an increasing number of top quant PMs, researchers, and technologists who are quietly exploring what''s out there. We are currently actively hiring for 𝐐𝐮𝐚𝐧𝐭𝐢𝐭𝐚𝐭𝐢𝐯𝐞 𝐏𝐨𝐫𝐭𝐟𝐨𝐥𝐢𝐨 𝐌𝐚𝐧𝐚𝐠𝐞𝐫𝐬 (𝐐𝐮𝐚𝐧𝐭 𝐏𝐌𝐬) 𝐚𝐜𝐫𝐨𝐬𝐬 𝐭𝐡𝐞 𝐔𝐒, 𝐄𝐌𝐄𝐀, 𝐚𝐧𝐝 𝐔𝐀𝐄, 𝐚𝐬 𝐰𝐞𝐥𝐥 𝐚𝐬 𝐟𝐨𝐫 𝐦𝐢𝐝-𝐟𝐫𝐞𝐪𝐮𝐞𝐧𝐜𝐲 𝐫𝐞𝐬𝐞𝐚𝐫𝐜𝐡𝐞𝐫𝐬, 𝐬𝐲𝐬𝐭𝐞𝐦𝐚𝐭𝐢𝐜 𝐄𝐓𝐅 𝐭𝐫𝐚𝐝𝐞𝐫𝐬, 𝐚𝐧𝐝 𝐝𝐞𝐞𝐩 𝐥𝐞𝐚𝐫𝐧𝐢𝐧𝐠 𝐥𝐞𝐚𝐝𝐬. Firms are moving fast to secure talent that can bring resilience and innovation in an environment where every basis point matters. Our strength lies in being deeply connected to both clients and candidates—helping firms shape competitive offers while guiding talent toward platforms that have the leadership, infrastructure, and conviction to thrive through market cycles. 𝗧𝗵𝗶𝘀 𝗶𝘀 𝘁𝗵𝗲 𝗿𝗶𝗴𝗵𝘁 𝘁𝗶𝗺𝗲 𝘁𝗼 𝗵𝗮𝘃𝗲 𝘁𝗵𝗼𝘀𝗲 𝗰𝗼𝗻𝘃𝗲𝗿𝘀𝗮𝘁𝗶𝗼𝗻𝘀—𝘄𝗵𝗲𝘁𝗵𝗲𝗿 𝘆𝗼𝘂''𝗿𝗲 𝗹𝗼𝗼𝗸𝗶𝗻𝗴 𝘁𝗼 𝗯𝘂𝗶𝗹𝗱 𝘆𝗼𝘂𝗿 𝘁𝗲𝗮𝗺 𝗼𝗿 𝗲𝘅𝗽𝗹𝗼𝗿𝗲 𝘆𝗼𝘂𝗿 𝗻𝗲𝘅𝘁 𝘀𝘁𝗲𝗽. 𝗟𝗲𝘁''𝘀 𝗰𝗼𝗻𝗻𝗲𝗰𝘁. vick@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 17, 0, 2, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7430534617532772352/', 'Super excited to have VIANN join our Dubai team to help supercharge Ops out there. Luckily we were able to spend some time with her when we were in Dubai earlier this month, and she’s already hit the ground running. Really looking forward to seeing her help us scale properly as the Dubai office continues to grow. Viann is an ICA Certified AML/CFT professional and experienced Head of Operations with over 8 years in regulatory licensing, compliance and operational leadership across regulated sectors in the UAE. She has deep expertise across Ministry of Economy, DMCC and DIFC frameworks, working across company formation, licensing, AML implementation and regulatory engagement for DNFBPs, crypto and fintech firms. She’s also a Global Filipino Award 2025 recipient and was named among the Top 100 Women Leaders in the Middle East (61st Edition) - pretty incredible. Dubai continues to be a huge growth area for us, and we’re growing globally across all offices. If you’re a talented recruiter in our space and would be interested in a confidential chat, drop me a message :) …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 2, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/daniel-frugtniet-hagen-a4943719b', 'https://www.linkedin.com/feed/update/urn:li:activity:7354178221711495168/', 'Tired of hearing about boring software engineering roles? I''m working with a top-tier quantitative firm in London that''s looking for a Software Engineer to join their team. This is a opportunity to tackle complex challenges at the intersection of technology and finance. You''ll partner directly with quantitative researchers to build and implement high-performance trading systems that are put to the test in live markets. They''re looking for a professional with: - 4+ yrs of experience in either C++ or Python. - A genuine passion and understanding of financial markets. - A drive to engineer robust, scalable, and mission-critical systems. If you''re ready for a challenging role where you can make a significant impact, I''d like to hear from you. Send me a DM for a confidential chat. hashtag#cpp hashtag#cplusplus hashtag#python hashtag#hiring hashtag#trading hashtag#finance hashtag#proptrading …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 21, 2, 1, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7369635234721579008/', 'Lots of exciting stuff going on at DP across London, Dubai, and New York - tech, quant, recruiter roles, and our next Women at the Table event on the horizon. 🚀 Big few months ahead and always keen to speak with great people... whether you’re a candidate exploring opportunities, a client hiring, or a recruiter thinking about making a move. …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 2, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7429466978299437057/', 'Happy Lunar New Year from all of us at Durlston Partners 🧧 Wishing our clients, candidates, colleagues and friends who are celebrating a year filled with health, happiness and prosperity. As we welcome the Year of the Horse, we’re looking forward to a year of energy, momentum and continued growth across all of our global offices. 新年快乐 - Gong Xi Fa Cai! …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7347979094971543552/', '🚨 We’re hiring for Dubai 🚨We’re looking for a curious, driven individual to join our growing Dubai team. We’re open on background - this could suit someone with a STEM or research-heavy degree who wants to move into a more commercial role and work with some of the smartest minds in the world. Or someone naturally sharp and ambitious, with a strong interest in finance and tech, who’s keen to build a career in a high-performing environment. Recruitment or sales experience is a plus, but not essential. You just need to be bright, switched-on, and up for a challenge. Must be open to relocating to Dubai (either immediately or with a start in our London office first). At Durlston Partners, we work with some of the most exciting names in the industry (hedge funds, HFTs, AMs, Prop Shops, FinTechs). Warm desks, brilliant clients, and a commission structure that in uncapped, plus BD incentives, profit share, and all the support you need to succeed. Interested? Drop me a message or email shannon@durlstonpartners.com We offer cash for successful referrals so if you know anyone who could be interested, send them my way. …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 34, 0, 3, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7429177815767506944/', 'New role : solving for volatility in a fast-paced market 📊 Options markets move fast - this client''s research moves faster. I am hiring a Quantitative Researcher for a New York options desk. Looking for someone who can bridge the gap between complex derivatives pricing and real-world execution. If you have a PhD/Master’s in a quantitative field and a passion for building robust trading signals, I want to talk. Why this role? 1️⃣ Flat structure, highly collaborative culture. 2️⃣ $150k - $250k base + performance-driven bonuses. 3️⃣ Direct exposure to the full trading lifecycle. Check out the full description and apply! https://lnkd.in/diT9qmu4 jared@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 7, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7346175960758583296/', '🌟 Brilliant intern alert 🌟The amazing Orla Hunt (a current student at the University of Cambridge) is looking for a summer internship within an investment management or corporate legal team, and I wanted to share her details with my network in case anyone might be able to help. Orla has interned with us at Durlston Partners during university holidays over the past four years, and she is truly exceptional - smart, proactive, driven, and a joy to have in the office. She’s currently studying Human, Social and Political Sciences at Cambridge and was recently elected Head of Speakers at the Cambridge Union (where she’s hosted and interviewed high-profile guests like the CEO of Newsweek and the founder of Peachy Den). She’s been part of live pitches to board-level decision-makers in finance, completed multiple legal simulations with top firms, and has a growing network of professionals across both the legal and investment space. If you or someone in your network might be able to offer Orla a short-term internship this summer (or even just a useful conversation) please drop me a message and I’ll connect you. shannon@durlstonpartners.com hashtag#InternshipOpportunity hashtag#InvestmentManagement hashtag#CorporateLaw hashtag#CambridgeUniversity …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 46, 1, 5, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7428815358653792256/', '***3 Urgent Hires*** **Trading OPs Manager - HFT - Hong Kong** - 10 years ideally but flexible - Strong middle and back office operations - Understanding of financial data, experience across the trade lifecycle - Able to start by end of Feb at latest **Senior DevOps Engineer (NYC or SF)** - Strong academic background, ideally CompSci, Maths, or related - 3+ years of DevOps or infrastructure engineering experience, preferably at a high-growth startup - Proficiency in scripting languages (preferably Python) and infrastructure-as-code tools **Software Engineers (NYC or SF)** - Strong academic background - Startup experience ideally - Python, Java, or GO exp - Anyone with Founding Engineer or Co-Founding experience is a big plus! matt@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/has-law-firm/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7396472227401183232/', 'We were delighted to join IG Prime, Durlston Partners, and Paragon Consulting Partners as sponsors of the 100 Hedge Funds gathering in Dubai — an evening that brought together some of the most dynamic minds in hedge funds, trading, fintech, and digital assets. The energy in the room spoke volumes about the UAE’s growing influence as a global financial centre. For HAS Law Firm, it was a valuable platform to connect with the firms and leaders driving this momentum and to support their ambitions with clear, commercially grounded legal advice across regulation, fund structuring, and cross-border matters. A strong event, exceptional turnout, and a great step forward for the community. If your fund or financial venture is expanding in the UAE, we’d be pleased to support your journey and feel free to reach out to Partner Evgeny Yafasov evgeny@has.law hashtag#HedgeFunds hashtag#FinTech hashtag#DigitalAssets hashtag#DubaiBusiness hashtag#UAE hashtag#FinancialServices hashtag#HASLaw hashtag#GlobalMarkets hashtag#InvestmentIndustry hashtag#RegulatoryAdvisory …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 81, 0, 3, 'image', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7428452972117917696/', 'I spoke with a candidate recently who told me I was the first recruiter he’d spoken to in almost 3 years! He''d been passively looking for a while, managing the search entirely through direct applications, and felt he had a pretty good idea on who was hiring in our space. That perspective shifted fairly quickly when we started going through my client list. Within 10 minutes, I presented him with three relevant, high-paying opportunities at firms he didn''t even know existed. The reality of this industry is simple: 👉 The best firms often don''t advertise 👉 The most exciting crypto projects are often still in stealth 👉 Direct applications often get lost in the noise - we get you straight to the decision-maker 👉 You often get a tailored, more streamlined job search If you''re only applying to what you can see, you are likely only seeing a fraction of the market. 📩 Drop me a message if you want to see what else is out there. Durlston Partners @david@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7322524320080044032/', 'What an amazing evening! It was such a pleasure to gather so many brilliant women from across our community for our Women at the Table event. Hosting it in our office made it feel especially intimate - we’re so grateful to everyone who joined and contributed to such thoughtful conversation and connection. We’ll be sharing a speaker debrief soon, but in the meantime, here are a few snapshots from the night. We’re hoping to run these events more frequently, so keep your eyes peeled - and if you’d like to be part of the community, you can click here to join for updates. https://lnkd.in/e8EXxtFm hashtag#WomenAtTheTable hashtag#DurlstonPartners hashtag#WomenInTech hashtag#WomenInFinance hashtag#Community hashtag#Networking hashtag#Fintech …more', '11mo • 11 months ago • Visible to anyone on or off LinkedIn', 11, 0, 1, 'video', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/ghassan-zeidan', 'https://www.linkedin.com/feed/update/urn:li:activity:7395130720148418560/', 'Last week we had the pleasure of co-sponsoring the 100 Hedge Funds event in the DIFC. Great turnout and a pleasure meeting everyone who came. Big thank you to all who attended as well as to the other co-sponsors, and of course Durlston Partners. Looking forward to the next one in Abu Dhabi in the new year. Paragon Consulting Partners ➡️ Internal Audit ➡️ Risk ➡️ Cybersecurity ➡️ Regulation hashtag#Risk hashtag#Resilience hashtag#Regulation hashtag#Cybersecurity hashtag#InternalAudit hashtag#ParagonConsultingPartners hashtag#DIFC hashtag#HedgeFunds hashtag#100HedgeFunds …more', '5mo • Edited • 5 months ago • Edited • Visible to anyone on or off LinkedIn', 62, 6, 3, 'video', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7395018914184982528/', 'Durlston Partners 100 Hedge Funds Event - Dubai 🇦🇪 What an evening! Last week we hosted our 100 Hedge Funds event at Sexy Fish DIFC, and it was absolutely incredible - a massively oversubscribed night bringing together some of the most brilliant minds in the region. The energy in the room was electric and a real reflection of the momentum and appetite for growth in the UAE. It’s an exciting time to be here, and we’re proud to be part of building this community. Huge thank you to our amazing partners - IG Prime, HAS Law Firm, and Paragon Consulting Partners! We’re already planning future events across London, Dubai, Abu Dhabi, and New York, so if you’d like to attend, sponsor, or get involved, drop us a message or email events@durlstonpartners.com and we’ll keep you posted. …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 40, 1, 3, 'video', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7428090587075149824/', 'This just went live. Are you at a stage of life where flexibility really matters? Maybe you’re thinking about getting a dog, starting a family, or just entering a phase where flexibility actually matters. We don’t often see fully remote roles in this industry anymore. The post Covid remote wave has largely passed, which is exactly why this one stands out. This is a genuinely rare opportunity for someone who needs and wants long term flexibility, without compromising on technical challenge, calibre of work and comp. I’m looking for a Software Engineer to join a top-tier HFT offering true remote working. You’ll be: 👉Building and enhancing core trading system infrastructure 👉Working primarily in Python and C++ (roughly 70/30 split) 👉Solving problems around scale, performance, and reliability 👉Supporting systems that process millions of transactions across dozens of venues and currencies The team is made up of some of the strongest engineers in the market, coming from tier 1 firms. It’s a flat structure with real autonomy, you’ll have a voice from day one and the chance to shape the foundations that will power the firm. If flexibility is non-negotiable for you, and the work still needs to be genuinely challenging, this is worth a conversation. Happy to share more privately daniel@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7427656486543175681/', 'A couple of weeks ago, I bumped into a candidate I placed at a hedge fund about two years ago. He was out shopping with his family, tapped me on the shoulder, and we had a quick catch-up. He thanked me for helping him land his role and even introduced me to his mum, which was genuinely very sweet. What made the moment even more special is that he’s since been promoted to CISO at the fund. Before that move, he’d spent 7 years at a top London Quant fund, where he was loyal, consistent, and had repeatedly been promised progression. In reality, promotions were slow, compensation lagged the market, and growth kept getting pushed “to next year”. Leaving felt risky. Familiar environments always do. However, loyalty alone sometimes doesn’t guarantee professional or financial development. At the time, his package moved from: £110k base + £40k bonus (Security Engineer) £180k base + £90k bonus + £40k sign-on. (CyberSec Lead) And who knows what the package looks like now... The point isn’t money for money’s sake, it’s about recognising when staying put is no longer helping you grow. Sometimes the uncomfortable step is the one that changes everything. If you’re thinking about a move in 2026, feel as though you’re stagnating, or simply want to understand what else might be out there, please don’t hesitate to reach out to any of the team for a discreet conversation about the market. Email: Jamie@Durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7427294091589140480/', 'Global mobility is no longer a “nice to have” in hedge funds, it’s a competitive edge. The best firms now hire globally, not locally. Location is optional. Performance isn’t. I’m hiring for roles where the headcount spans multiple jurisdictions, giving top performers choice without compromise: • Quant Developers (Python/C++) – Dubai, London, NY • Middle Office Developers (Python/C++) – Dubai, London, NY • Options Quant Traders & Researchers - APAC, US, Europe • Systematic Researchers – London, NY, Singapore, Dubai • Low-Latency/HFT Engineers (C++) – London, US, EU, remote • Systematic Futures Portfolio Managers – Dubai, US, Switzerland, London Why it works: – Elite talent is global. So are the opportunities. – Flexibility doesn’t mean less impact, it means more. – Firms care about output, not office seats. If you want tier-one challenges, top comp, and the freedom to choose your base, let’s have a confidential chat. jared@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7426931691820199937/', 'London based opportunity to be hire #2 in the Sales Team of a sellside crypto desk, second only to the Head of Sales. You''ll likely be a good fit for this if you''ve worked at a crypto exchange for a few years and are keen to make the leap into a role that would upskill your knowledge around algorithmic execution. They can teach you about execution, they can''t teach you about selling to crypto trading firms, which is why they want you to have done it before! If this sounds like a good fit for you or someone in your network, please reach out via my details below: 📲 TG @cryptowarwick 📩 warwick@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7426569307482095616/', 'You don’t need to resign tomorrow... But now is the time to explore options, benchmark the market, and position yourself properly, not when everyone else does. (even with bonus season coming up). I’m speaking to a lot of candidates who are thinking: "I''ll wait until my bonus lands in Feb/March/April, then I’ll start looking.” Something many candidates underestimate is timing. From first conversation to offer, most hiring processes take 3-6 weeks. Add time for offer discussions, notice periods, and bonus alignment and very quickly: 👉 A conversation started in January 👉 Turns into an offer in late February 👉 With a resignation landing in March Ironically, that’s exactly when many people plan to start looking. By then, the market is typically flooded with candidates coming out of bonus season, visibility drops, and competition increases, even for very strong profiles. Right now, I’m seeing: - New roles coming live daily - Clients finalising 2026 hiring plans - Firms open to buying out bonuses left on the table The candidates who move early don’t rush, they position themselves. They get in front of hiring managers first, understand their options, and make informed decisions rather than reactive ones. If you’re even loosely considering a move this year, now is the smart time to start the conversation before the market becomes saturated. Happy to talk through options quietly and confidentially. daniel@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7426206916118245376/', '𝐅𝐢𝐧𝐝𝐢𝐧𝐠 𝐚 𝐩𝐫𝐨𝐩𝐞𝐫 𝐇𝐅𝐓 𝐞𝐧𝐠𝐢𝐧𝐞𝐞𝐫𝐢𝐧𝐠 𝐫𝐨𝐥𝐞 𝐭𝐡𝐚𝐭 𝐚𝐜𝐭𝐮𝐚𝐥𝐥𝐲 𝐥𝐞𝐭𝐬 𝐲𝐨𝐮 𝐰𝐨𝐫𝐤 𝐫𝐞𝐦𝐨𝐭𝐞𝐥𝐲 𝐢𝐬 𝐭𝐨𝐮𝐠𝐡 🌍 Usually, if you want to work on high-performance trading systems, you’re tied to a desk in London or Amsterdam at least a few days per week. This team operates differently. I’m working with a leading Crypto HFT looking for a Core Developer to join their distributed team. You can be based anywhere in the UK or Europe, building the rails that drive their PnL. 𝐓𝐡𝐞 𝐑𝐨𝐥𝐞: 👉 𝘛𝘦𝘤𝘩 𝘚𝘱𝘭𝘪𝘵: Mostly Python (70%) with C++ (30%) 𝘛𝘩𝘦 𝘎𝘰𝘢𝘭: Building resilient systems that can handle 24/7 crypto markets without falling over. 👉 𝘛𝘩𝘦 𝘝𝘪𝘣𝘦: Flat structure, working directly with Quants and Traders. 𝐖𝐡𝐚𝐭 𝐲𝐨𝐮 𝐧𝐞𝐞𝐝: 👉 You need to have done this before - experience in a Trading firm (HFT, Prop, or Hedge Fund) is a must. 👉 Strong Python skills are key, but you need to be comfortable optimizing in C++ when speed matters. 𝐋𝐨𝐜𝐚𝐭𝐢𝐨𝐧: 🌍 Fully Remote (UK & Europe). 𝐒𝐚𝐥𝐚𝐫𝐲: 💰 They''re regularly attracting engineering from Tier-1 HFTs/Hedge Funds, so they offer a strong base salary + bonus (50-100%+) Contact me: https://linktr.ee/dezihe david@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 3, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7425840753911803904/', 'Wasting absolutely no time, here’s what I’m actively working on right now: - Quant Developer with Fixed Income experience - up to £140k base + bonus - Lead Frontend Engineer at a prop trading firm - building Realtime trading UIs, sweet spot around £130k base - Python Developer (Risk) at a systematic hedge fund - strong ownership, paying up to £300k - Python Developer with C++ at an HFT - fully remote If you’re starting to think about a move, benchmarking comp, or just curious what’s out there, feel free to drop me a message. daniel@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 3, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7425478394139750400/', 'Truly strong HFT C++ engineers don’t tend to be on the market very often. When they are, it’s rarely because of compensation, it’s usually about scope, impact, or proximity to the strategy/PnL itself. The roles attracting the most attention right now are those where engineers sit close to the trading logic: shaping execution behaviour, optimising latency in production, and working directly with the people responsible for risk and returns Across global markets, demand for this level of expertise remains intense, and the selection process on both sides has become far more considered. 𝐎𝐧𝐞 𝐞𝐱𝐚𝐦𝐩𝐥𝐞 𝐰𝐞’𝐫𝐞 𝐜𝐮𝐫𝐫𝐞𝐧𝐭𝐥𝐲 𝐰𝐨𝐫𝐤𝐢𝐧𝐠 𝐨𝐧:: A fully remote Strategy Developer / HFT C++ role at a high-performance trading firm, operating across APAC and European time zones (US also an option). They’re looking for someone who has: ✅Built and owned low-latency, exchange-facing C++ strategies in production ✅Worked directly with quants, traders, and hardware teams to translate research into live performance ✅Optimised across multiple exchange protocols, market data paths, and execution environments ✅Contributed to large-scale re-writes of trading engines where determinism and performance were non-negotiable If you’re operating at this level, you’re probably already working on something interesting, but it’s always worth keeping a pulse on where the most serious teams are investing. james@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7425116046199615488/', 'Durlston Partners is growing and hiring across our London and Dubai offices. With over 10 years’ experience in recruitment, I’ve rarely seen the level of opportunity that exists here. The scale and quality of roles, clients, and outcomes over the past year have genuinely redefined what I thought was possible in this market. We work closely with some of the world’s leading hedge funds, proprietary trading firms, HFTs, and global financial institutions who truly do look for the world''s top talent in the Quant space and Engineering. Why I think you should consider us. I’ve previously led senior mandates for major investment banks and since working with our current client base, I surpassed my largest-ever placement by 2x in August - and then exceeded the August placement by 2x again in December. Feel free to reach out if you fancy exploring a career at Durlston Partners. James Skelt …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7424753644991844352/', 'Covering both the Trading and AI side, here are some opportunities that could be interesting. Trading Side (Anything Options Trading) 📈 🔸Quant Traders, Quant Devs, Quant Researchers. 🔸Global coverage for these (NY, Chicago, London, Sydney, Mumbai, Shanghai, Singapore + Remote) 🔸Mid-Senior levels AI Side 🤖 🔸Mid-Senior Level Engineer: AI Unicorn working on conversational AI (London). 🔸Senior-Staff Level Engineers: AI Unicorn (NY) If you are looking at the market at the moment, feel free to drop me a message. ab@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 2, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7424391296980525056/', 'While there’s an increasing volume of commentary suggesting the “hype” around AI is beginning to cool, we’re not seeing the same pattern in hiring demand across our UK and US client base. If anything, the urgency to hire remains high. What has become more challenging is distinguishing between companies that are simply leveraging the AI narrative and those with the foundations, leadership, and capital to build genuinely scalable, durable businesses, let alone ones that will play a meaningful role in how AI shapes technology, society, and enterprise. Over the past two years, Durlston Partners has focused on building long-term relationships with founders and teams who are doing the latter: organisations investing in robust engineering, commercial reality, and sustainable growth, rather than short-term hype. Here are some of our active roles in AI below. hashtag#London AI Engineer - Trading focused AI Start up - Up to £130k + Equity, flexible working. Agent Software Engineer - GenAI Start up (very well funded) - up to £210k Base + Equity Engineering Manager - GenAI Start up (very well funded) - Up to £280k Base + Equity Product Engineer - AI Start up - Up to £120k + Equity hashtag#nyc Senior Product Manager - NYC - Unicorn Healthcare AI Startup - Up to $250k Base + Equity Solution/Product Engineer - NYC - Real Estate AI Start up - Up to $200k + Equity Senior Data Engineer - NYC - Unicorn Healthcare Start up - Up to $300k Base + Equity Staff Software Engineer - NYC - Unicorn AI Start up - Up to $400k Base + Equity For more information on the above, or if you are looking for advice on how to start your search, negotiating processes around bonuses and non-competes, please get in touch! James@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7424028827753971712/', '***Hiring*** Lead AI Solutions Engineer - NY or London (hybrid) - 8 to 12 years of experience - Experience coding at least last 6 years (if moved off no problem if happy to be hands on again) - Coding with Codex and Github co-pilot experience **Standout** Big 4 engineer MS or PhD preferred working in GenAI Solutions --------------------------------------------------------------------- AI SWE and Engineering Managers - London -Top academics - Mix of big tech + start up experience - Pure engineering experience (Python/TypeScript) - Happy to be on-site in London area 5 days - Engineering Managers must be hands-on and manage team DM if interested in a confidential chat! matt@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 1, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7423666426198003712/', 'In 2026, I''ll be recruiting for: - Quantitative Researchers - Proprietary Traders - C++ Engineers - Data Science/ Data Engineers …for leading HFTs, hedge funds, and proprietary trading firms globally. If you’re considering a move, curious about the market, or just want an informed, confidential conversation about opportunities in quantitative finance and trading, feel free to reach out. js@durlstonpartners.com James Skelt …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 4, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7423304089368961024/', '𝗙𝘂𝗹𝗹𝘆 𝗦𝘆𝘀𝘁𝗲𝗺𝗮𝘁𝗶𝗰 𝗖𝗠𝗘 𝘀𝘁𝗿𝗮𝘁𝗲𝗴𝗶𝗲𝘀 - 𝗣𝗲𝗿𝘀𝗼𝗻𝗮𝗹 𝗮𝗿𝗯𝗶𝘁𝗿𝗮𝗴𝗲 (𝗨𝗔𝗘, 𝗼𝗿 𝗿𝗲𝗺𝗼𝘁𝗲) 𝗛𝗶𝗴𝗵 % 𝗣𝗻𝗟, 𝘀𝗰𝗮𝗹𝗶𝗻𝗴 𝗥𝗶𝘀𝗸, 𝗧𝗮𝘅-𝗲𝗳𝗳𝗶𝗰𝗶𝗲𝗻𝗰𝘆, 𝗻𝗲𝘄 𝗺𝗮𝗿𝗸𝗲𝘁 𝗲𝘅𝗽𝗮𝗻𝘀𝗶𝗼𝗻... We are seeing a large influx of both small and established prop shops to the UAE, with a focus on running fully systematic global strategies. CME Futures strategies have been a huge topic amongst my clients, so I am looking to work with Quants and Traders, who are building and running these strategies to discuss a range of benefits of these potential moves (both to the UAE, as well as to new firms in the same location - US, London, Amsterdam). 𝗢𝘃𝗲𝗿𝘃𝗶𝗲𝘄: - High % PnL splits, great risk scaling timeline - Tax-free location (more tax-efficient for US citizens but not 0%) - Ability to expand to new Futures markets in Europe and APAC - Freedom to work from various offices in the US, Europe and Middle East - UAE specific benefits - cost of living, simple visa setup, safety etc Please reach out if you are a Quant or Trader running fully systematic CME Futures strategies, and we can discuss the global market and some of the unique opportunities in various location. rahn@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7422937896673845248/', '𝗗𝗶𝘀𝗰𝗿𝗲𝗲𝘁, 𝗘𝗹𝗶𝘁𝗲 𝗔𝗜 𝗛𝗙𝗧 𝗤𝘂𝗮𝗻𝘁 𝗥𝗲𝘀𝗲𝗮𝗿𝗰𝗵 𝘁𝗲𝗮𝗺𝘀 𝗶𝗻 𝘁𝗵𝗲 𝗨𝗔𝗘 𝘓𝘢𝘵𝘦𝘴𝘵 𝘓𝘓𝘔𝘴, 𝘈𝘐 𝘈𝘨𝘦𝘯𝘵𝘴, 𝘋𝘦𝘦𝘱 𝘙𝘓, 𝘈𝘥𝘷𝘢𝘯𝘤𝘦𝘥 𝘛𝘪𝘮𝘦-𝘴𝘦𝘳𝘪𝘦𝘴 𝘈𝘯𝘢𝘭𝘺𝘴𝘪𝘴 We are working with a few elite AI-driven HFT Quant teams, who have discreetly set up shop in the UAE, coming from top financial hubs such as NYC, London, Amsterdam and Singapore. They''re here to: - capture talent from migration to the region - leverage the cost-effective compute future of the region (cheaper energy) - position for new market expansion (e.g. US firms expanding in APAC markets) They''re targeting the best talent around, and compensation is highly reflective of this, aligning to Tier 1 global salaries. Now is the time to get in early with the best of the best! Please reach out if you''re working on cutting- edge AI Research or Infrastructure across any industry, or the applications to Quant Research and Trading. rahn@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7422575515082924032/', 'Roles I''m working on: 🟠 𝐃𝐞𝐯𝐎𝐩𝐬 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - Elite Quant Trading Firm - Abu Dhabi - $250k+ 🟠 𝐒𝐞𝐧𝐢𝐨𝐫 𝐃𝐚𝐭𝐚 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - Elite Quant Trading Firm - Abu Dhabi - $200k+ 🔵 𝐂++ 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫𝐬 - HFT - Fully Remote - $250k + bonus 🔵 𝐏𝐲𝐭𝐡𝐨𝐧/𝐂++ 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 - HFT - Fully Remote - $180k + bonus 🟢 𝐐𝐮𝐚𝐧𝐭 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 (𝐏𝐲𝐭𝐡𝐨𝐧) - Hedge Fund - London - £140k + bonus 🟢 𝐃𝐞𝐬𝐤𝐭𝐨𝐩 𝐒𝐮𝐩𝐩𝐨𝐫𝐭 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - Hedge Fund - London - £130k + bonus 🟢 𝐀𝐩𝐩 𝐒𝐮𝐩𝐩𝐨𝐫𝐭 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - Market Maker - London - £120k + bonus 🟢 𝐒𝐞𝐧𝐢𝐨𝐫 𝐒𝐨𝐟𝐭𝐰𝐚𝐫𝐞 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 (𝐏𝐲𝐭𝐡𝐨𝐧) - AI - London - £250k + equity 🟢 𝐒𝐨𝐟𝐭𝐰𝐚𝐫𝐞 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫𝐢𝐧𝐠 𝐌𝐚𝐧𝐚𝐠𝐞𝐫 (𝐏𝐲𝐭𝐡𝐨𝐧) - AI - London - £300k + equity david@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7422213101757935616/', 'I just saw an Instagram post predicting life in 2050 👇 • Phone batteries lasting 100 years using recycled nuclear waste • Humans talking to animals as AI is currently decoding whale languages • Hyper speed trains replacing planes • Real meat grown in labs Honestly… I do and don''t believe all of it will happen. And yet, I’m pretty confident of this one thing: The world will still need C++ developers powering trading firms. Ultra low latency, performance critical systems don’t disappear just because the future looks shiny. If anything, they get more demanding (Hopefully AI doesn''t take over the world 🤞). I’m currently working with clients actively hiring C++ engineers across: 📍 London 📍 New York 📍 Chicago If you’re building high performance trading systems, now or in 2050, let’s talk. daniel@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7421930077271089152/', 'We''re growing and hiring across our London and Dubai offices. One of the main reasons people join us and what surprises them most during interviews is the level of trust and respect we have for each other. We don''t operate in a cutthroat way. We hear horror stories during interviews about practices at other competitors. Someone who recently joined us shared that at their previous firm, just two months after they''d placed a candidate at a market maker, their colleague secretly contacted that same candidate trying to poach them for another placement to collect a fee. This kind of behaviour makes you look incompetent and it damages your reputation for short-sighted gain. But you can’t be blamed if you’re incentivised to do this. If your firm incentivises you to undercut your colleagues like this, they don''t care about you or the quality of service you provide. By comparison, a few years ago I saw an SRE on our system that Marcus Osborne had previously worked with and met for coffee. This was one of those "attach the invoice" to the intro candidates. The candidate hadn''t been contacted in three months. According to our ownership rules, relationships expire after two months, so technically this candidate was fair game and I could have taken over with no issues. Instead, I gave Marcus a heads up (as painful as that was) and sure enough, he placed the candidate a few weeks later for a sizable fee. Why do we operate this way? The favours get repaid. It reduces friction and tension within the team. People stay with the company longer. It''s how we build something sustainable! Screenshot attached of that painful but rewarding exchange with Marcus josh@durlstonpartners.com …more', '2mo • 2 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7421846475682402304/', 'I’m juggling a slate of high-priority roles that refuse to take a winter break and the hiring pace is only picking up. If you or someone in your network is exploring new opportunities, now is the time to connect - these roles won’t stay on ice for long! Solutions Engineers (NYC, Boston, and SF) Options Trader (NYC, Singapore, or London) Quantitative Researcher, DeFi exchanges, Crypto (NYC) Quantitative Researcher - CeFi exchanges/Tradfi principles, Crypto (NYC) Quantitative Developer, Crypto (NYC) Founding Software Engineer (NYC) Senior Software Engineer (NYC) Senior Data Engineer (NYC) BDRs (NYC and Boston) Account Executives (NYC and Boston) Rust Developers (Hong Kong) matt@durlstonpartners.com Matthew Leon …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7328445026202546177/', 'The FAANG-to-Fund Transition Moving from Big Tech to a quant fund isn’t just a career change — it’s a shift in mindset. You move from long development cycles to real-time feedback. From layered abstractions to lean, latency-critical systems. From structured roadmaps to ownership of production from day one. Engineers who thrive in trading don’t just ship features — they optimise for speed, reliability, and impact in every line of code. It’s fast. It’s direct. And for the right mindset, it’s incredibly rewarding. So, ask yourself: are you ready for production-level ownership from day one? If this has resonated with you and you''re interested in exploring a hashtag#remote HFT C++ opportunity - 𝐚𝐩𝐩𝐥𝐲 𝐡𝐞𝐫𝐞👉https://lnkd.in/ejpTWUiv👈 Additionally for more information, feel free to reach out: Xander Oliver xander@durlstonpartners.com …more', '11mo • 11 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7363842181536616448/', 'Weather is looking perfect (20 degrees & sunny) for our very first Industry Run Club this evening ☀️👟 If you haven’t registered but fancy joining, we’d still love to have you... just drop me a message here or email shannon@durlstonpartners.com. 📍 Meeting at the DP London office 🏃‍♀️ Scenic loop through St James’s & Green Park at a relaxed, talking pace (all levels welcome) 🍻 Optional (but encouraged!) post-run drink It’s free to join, super informal, and a great way to get some fresh air, catch up with colleagues, and meet others from across the quant, tech, AI/ML, and digital assets space. See you at the start line! https://lnkd.in/e_6x2YUb …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'article', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7420037826123116544/', 'We’re lucky to receive a high volume of applications, so please understand that we’re only able to reach out directly if your profile is a strong match for one of our current openings. In the meantime, do keep an eye on our website and LinkedIn page for new roles, and apply directly where relevant. You’re also always welcome to email hello@durlstonpartners.com with your CV and a brief note on the types of roles you’re targeting - if something suitable comes up, someone from Durlston Partners will be in touch. Thanks so much for your understanding. …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 2, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7419669770242818049/', 'As our Dubai office continues to grow, we’re looking for an exceptional Office Manager / Team Coordinator to become the lynchpin of the team on the ground. This is a support role at its core, but with huge scope to grow, take ownership, and help shape what we’re building in the region. This person will sit at the heart of the Dubai office, working closely with me (based in London) and alongside our teams in London, Dubai and New York. You’ll be the go-to for keeping things running smoothly day to day, freeing up the team to focus on clients, candidates and growth, while also getting exposure to recruitment, operations, marketing, events and more! Dubai is a key growth hub for us. The office is scaling quickly, client demand is strong, and there’s real opportunity here for someone who’s organised, proactive, switched on, and excited by being part of something that’s still being built - a trusted right-hand, organiser, problem-solver! If you love being in the thick of it, enjoy bringing structure to fast-moving environments, and want a role where you’ll learn a huge amount and grow with the business, I’d love to hear from you. Drop me a message for a confidential chat. shannon@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7362120070136823810/', '🏃‍♀️ Market fun run incoming! 🏃‍♂️Durlston Partners are planning a social run for finance + tech folks in August... very relaxed, talking pace, and all running levels welcome. The plan is to meet at our Regent Street office for a quick bag drop, take a stroll down to the top of The Mall, and do a gentle loop around St James’s and Green Park, taking in a few sights along the way (just did a tester run with Daniel and Siva this lunch)! We might even end up at The Devonshire for a cheeky pint as a reward for all that hard work 🍻 If you fancy joining, drop me or Daniel a message, or email shannon@durlstonpartners.com and we’ll get you signed up. hashtag#RunClub hashtag#LondonNetworking hashtag#FinanceRunClub hashtag#MarketMeetUp hashtag#Wellness hashtag#DurlstonPartners hashtag#WorkWithUs …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 17, 0, 3, 'video', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7419008280527572992/', 'If you’re working for a company that’s planning to grow this year, we’d love to support you. Whether you’re scaling a new team, making a strategic senior hire, or simply want to understand the current talent landscape, drop us a message at hello@durlstonpartners.com. At Durlston Partners, we specialise in hiring across quant, tech, AI/ML, data, trading, and digital assets, partnering with hedge funds, HFTs, asset managers, prop shops, and high-growth fintechs globally. With a 15-year presence in the market, we deliver quickly and accurately - from individual hires to full team build-outs. If you’re hiring in 2025, let’s chat. 👇 hello@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7418645858264543232/', 'We receive a huge number of applications across our website, LinkedIn job ads, and direct emails - thank you to everyone who takes the time to reach out. We always do our best to respond, but the team naturally has to prioritise candidates who match our active roles. That said, we genuinely value building long-term relationships and often connect with people even when the timing isn’t quite right. It’s an extremely busy start to the year, and we know the job market can feel tough - so please be patient with us. We’re here to support where we can, whether that’s with roles now or advice for the future. If you see opportunities that look relevant, please keep applying, and hopefully we’ll have the right one for you soon. …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7418283462878654464/', 'New year, new roles - and we’re hiring across London & Dubai. 🚀 If you''re a recruiter in the tech / quant / trading / AI space and thinking about a move in 2026, now’s the perfect time to have a confidential chat. At Durlston Partners, you’ll get: ✨ Warm desks & immediate access to top-tier clients (no restrictions) ✨ Market-leading commission - no thresholds, no desk fees ✨ A platform where you can genuinely bill big from day one ✨ Clear progression (IC, team-build, or account-led - tailored around you) ✨ Amazing culture - high-performing, supportive, fun ✨ Extras: 2-week Christmas bonus break, top health cover, wellness allowance, team trips (Dubai, Vegas…), Women at the Table events & more We’re gearing up for a huge year across London, Dubai & New York and want to add exceptional people to the team. If you’d like to explore joining us, or just want to understand whether it could be a fit, drop me a message for a confidential chat. shannon@durlstonpartners.com Here’s to a big 2026. 💫 …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7417917311786860544/', '𝐋𝐞𝐚𝐝 𝐀𝐈 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - 𝐓𝐫𝐚𝐝𝐢𝐧𝐠 𝐅𝐢𝐫𝐦 - 𝐋𝐨𝐧𝐝𝐨𝐧 - 𝐔𝐩 𝐭𝐨 £𝟏𝟖𝟎𝐤 𝐁𝐚𝐬𝐞 + 𝐁𝐨𝐧𝐮𝐬 - Durlston Partners We have a unique opportunity with a top Trading client that is looking to hire an experienced AI Solutions Engineer, who will focus on building production ready GenAI solutions as well as improving business engagement and building out the team. The business is highly successful, with excellent performance year in, year out, and would like to drastically scale their AI function. This is a fully hands on role, working with end users to design, build and productionise solutions to improve business performance at scale. This is one of the most important projects within the business, with significant resources available and vast flexibility with tooling you can use/adopt. 𝐑𝐞𝐬𝐩𝐨𝐧𝐬𝐢𝐛𝐢𝐥𝐢𝐭𝐢𝐞𝐬: ▶Design and build and deploy GenAI powered applications using foundational models, including agentic workflows and advanced prompt engineering. ▶Build end-to-end workflow solutions, leveraging modern frameworks (Streamlit, FastAPI, Python). ▶Be responsible for the development and improvement of RAG pipelines and vector databases, as well as focused on embedding models for enterprise search and knowledge retrieval 𝐑𝐞𝐬𝐩𝐨𝐧𝐬𝐢𝐛𝐢𝐥𝐢𝐭𝐢𝐞𝐬: ✅7-15 years experience building production level advanced Python applications ✅Excellent knowledge and experience of LLM intergration using foundational model APIs ✅Advanced prompt engineer/agentic workflows experience ✅Previous experience using AI coding assistants (GitHub Copilot, Claude Code, Cursor etc) 💰£180k + Bonus 🏡3 days WFH For more information, or an off the record discussion, please get in touch! 📧 james@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7417554916015132672/', 'We reward referrals. 💸 Good people know good people - and we massively appreciate it when you connect us. 🙌 If you know someone great in our space - 🔹 Engineers, Quants, Researchers, Traders, PMs, AI/ML talent 🔹 or any strong recruiter who you think would thrive at Durlston Partners send them our way and we’ll reward generously if we place them or hire them internally. The market is already busy, our clients are hiring globally, and we’re continuing to grow our own team - so if someone in your network is quietly exploring options, we''d love an intro. Referrals can be sent to hello@durlstonpartners.com. …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
