INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7416460192537808896/', 'If you''re a Software Engineer with bulletproof CompSci fundamentals, Durlston Partners really does have a pretty sweet assortment of roles for you to choose from. GenAI startups are looking for Python Engineers who can own, build and ship AI agents in London; £140k-240k base + equity. - They''re hiring through 2 distinct pipelines; top class academics (2+ years of experience) or large impact in a tech driven firm. HFT Crypto Trading firms are looking for Rust / C++ Engineers who want to deploy strategies on centralised and decentralised venues; $300k-600k in US / UK / UAE / APAC. Systematic Hedge Funds are keen to onboard Python SWEs / QDs with the current flavour of the month tasting like Engineers with Fixed Income knowledge; £120k-150k base + 50-100% bonus in UK / UAE. Know C++ inside out? The world is your oyster. 📩 warwick@durlstonpartners.com 📲 TG @cryptowarwick …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7416097804898607104/', '𝗨𝗔𝗘 𝗛𝗲𝗱𝗴𝗲 𝗙𝘂𝗻𝗱𝘀 𝗯𝗲𝘆𝗼𝗻𝗱 𝗣𝗼𝗱 𝘀𝗵𝗼𝗽𝘀 𝗔 𝗴𝗿𝗼𝘄𝗶𝗻𝗴 𝗽𝗿𝗲𝘀𝗲𝗻𝗰𝗲 𝗼𝗳 𝗯𝗼𝘂𝘁𝗶𝗾𝘂𝗲 𝗮𝗻𝗱 𝗰𝗼𝗹𝗹𝗮𝗯𝗼𝗿𝗮𝘁𝗶𝘃𝗲 𝗛𝗲𝗱𝗴𝗲 𝗙𝘂𝗻𝗱𝘀 The UAE''s Hedge Fund industry has skyrocketed through the expansion of multi-managers in the region who mostly run pod structures, with Senior PMs being a large bulk of first movers to the region. Now, the landscape is evolving with collaborative businesses setting up in the region. The delay in their setup is understandable as they favour a slightly more mature market than the UAE could offer 3 years ago, but has rapidly formed. We have collaborative and boutique Hedge Fund clients hiring for all of the below here in the UAE: - Portfolio Managers - Quant Researchers - Quant Developers - AI Researchers/Engineers - Data Engineers Please reach out if you''re interested in hearing more about this landscape, expanding your search beyond the more well-known list of funds in the region. rahn@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
