INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7415010658787905536/', '🚀 Software Engineer | Crypto HFT | Remote We are looking for a Software Engineer to join one of the largest players in the global cryptocurrency trading market. The opportunity: Build high-performance trading systems that process millions of transactions across 10+ global locations, 24/7/365. You''ll work with Python and C++ to develop infrastructure powering sophisticated trading strategies across both CeFi and DeFi platforms. What they''re looking for: ✅ 5+ years in software engineering ✅ 3+ years with Python AND C++ ✅ Strong understanding of data structures and algorithms ✅ Passion for solving complex problems at scale ✅ Interest in cryptocurrencies and decentralised finance Work remotely. Tackle unique technical challenges. Direct impact. Interested or know someone who''d be a great fit? 👉 DM me or comment below for more details! ab@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 7, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7414648325381197824/', 'Future proof your investment career, as a first mover in AI’s disruptive strategy systematisation A host of strategies that have been historically discretionary to their core, are being disrupted with a new playbook. With NLP, GenAI and a host of rapidly iterating models, the capabilities of progressive thinking and forward thinking funds are growing quicker than ever before. We work with a host of traditional discretionary funds that are deploying systematised alternatives to their strategies, or entirely new funds, including strategies that have rarely been systematised in the past. If you’re an investment professional with the ability to understand deep fundamental analysis, alongside Quantitave techniques, and keen on sitting alongside the latest in AI, then this could be the opportunity to future proof your career. Please reach out if you’d like more info rahn@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7414285955102089216/', 'Reaching out to my network of Network Engineers (no pun intended 😅) I’m currently partnering with a Crypto HFT in London that is looking for a Senior Engineer to join their infrastructure team. This is a modern hybrid role for someone who sits right at the intersection of hardware, cloud, and code. 𝐖𝐡𝐚𝐭 𝐭𝐡𝐞𝐲 𝐧𝐞𝐞𝐝: 🟢 𝐂𝐨𝐫𝐞: Strong background in BGP, OSPF, Multicast, etc. 🟢 𝐂𝐥𝐨𝐮𝐝: Deep experience with AWS 🟢 𝐂𝐨𝐝𝐞: You can script/automate using Python 🟢 𝐒𝐞𝐜𝐮𝐫𝐢𝐭𝐲: Any exposure to securing infra is a massive plus The best part? Because this is in Crypto, it is unlikely to fall under your current non-compete restrictions, so you can likely make the move immediately. If you are looking for a role that pushes you technically, let’s chat. 📩 Drop me a message. david@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
