INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7413557326973972480/', 'On the hunt for elite engineers in quant finance and crypto These are chances to solve complex problems with the brightest minds in the industry. Here are the roles I''m headhunting for: 1. 𝗣𝘆𝘁𝗵𝗼𝗻 𝗗𝗲𝘃𝗲𝗹𝗼𝗽𝗲𝗿 | London | £150k + Bonus - Join a leading global crypto trading firm. 2. 𝗣𝘆𝘁𝗵𝗼𝗻 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 (𝗖++) | Remote (within Europe) | £120k + Bonus - Work for an innovative crypto HFT firm. 3. 𝗖++ 𝗗𝗲𝘃𝗲𝗹𝗼𝗽𝗲𝗿 | London | Up to £200k + Bonus - Drive high performance trading systems at a top tier crypto firm. 4. 𝗖++ 𝗘𝘅𝗲𝗰𝘂𝘁𝗶𝗼𝗻 𝗗𝗲𝘃𝗲𝗹𝗼𝗽𝗲𝗿 | London | Up to £200k + Bonus - Build ultra low latency systems for a world class quant firm. 5. 𝗖++ 𝗠𝗮𝗿𝗸𝗲𝘁 𝗗𝗮𝘁𝗮 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 | Chicago, NYC, or London - Join the core data team of a major quant firm. 6. 𝗝𝗮𝘃𝗮 𝗗𝗲𝘃𝗲𝗹𝗼𝗽𝗲𝗿 | London | Up to £90k + Bonus - Role with a prominent market maker. 7. 𝗝𝗮𝘃𝗮 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 | London | £100k + Bonus - Join a data driven prop trading firm. If you''re a elite engineer in Python, C++, or Java, my DMs are open. Know a great engineer? Share this to help them find their next big move. daniel@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7413194927183929344/', 'Always on the lookout for talented people - there’s always something interesting that we can discuss! Below is a summary - but you can find out more here 👉 https://linktr.ee/dezihe 🟢Quant Researcher - Multiple Firms - APAC, Europe, US 🟢C++ Developers - HFT - Fully Remote (anywhere in Europe/APAC) 🟡Senior Data Engineers - Quant Trading - United Arab Emirates 🔵Engineering Manager - GenAI Firm - London 🔵Senior FullStack Engineers - GenAI Firm - London 🔵Java Developer - Quant Trading - London 🔵Enterprise Account Executives - AI Tech - London Please feel free to reach out! david@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7412832551259717632/', 'Struggling to find the right software engineering roles in London? You''re not alone. Right now on LinkedIn, there are roughly 600 open software engineer jobs in London. Sounds like a lot? Not when you consider there are over 3,700 candidates publicly listed as "open to work." And that doesn''t even count the passive candidates who are quietly looking for their next move. So, how do you get an edge? This is where a specialist recruiter comes in. Many of my clients in the hedge fund and trading space don''t publicly advertise their roles. They''re building high impact teams and need to maintain a competitive advantage. These are the opportunities you won''t find on job boards. While you could apply to the typical big name firms and compete with hundreds of other applicants, here at Durlston Partners, we can connect you with exciting companies that are pushing the boundaries of technology or get you in with the right person and skip all that red tape. If you''re a software or quant developer skilled in C++, Python, or Java (and maybe even C# – I have a unique role for that!), let''s talk. I can help you understand the hidden job market and explore your options. Reach out to me to learn more! daniel@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7412481481870041088/', 'Happy New Year everyone! 🎉✨Hope you all had an amazing break and are feeling rested, recharged, and ready for 2026. The team is officially back next week, and the market is already moving - plenty of clients picking things up quickly, interviews being scheduled, and new mandates coming in across tech, quant, AI/ML, trading and engineering. If you’re starting the year thinking about a move - or just want to understand what the landscape looks like - drop us a note at hello@durlstonpartners.com and one of the team will be in touch. And if you’re a firm planning to hire early in the year, we’d love to support you. January is always a great time to get ahead of the market. Here’s to a brilliant 2026 - excited for everything that’s coming 🚀 …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7412111556835975168/', 'At Durlston Partners we work with the leading AI firms, Family Offices, Hedge Funds, Sovereign Wealth Funds and HFT’s across Dubai and Abu Dhabi (also London, New York and India). In particular, Portfolio Managers, AI / Software Engineers, Quant Traders, Data Scientists. We have a database curated with over 40,000 of the best candidates, over the past 15 years which gives us a clear edge in the market. We also produce real time market intel and data on demand for our clients. For more information or to discuss your end of year comp, the market for 2025 and 2026, please message me directly. I am Dubai based but in Abu Dhabi and London / New York regularly js@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7411745405417410560/', 'The Quant Trading Shopping List It''s quite an interesting position to be in we hear of clients giving recruiters a list of target firms they''d like to hire from. Typically, 4-5 names appear regularly, however I don''t want to be sued, so use your imagination (or Google); I''ve started calling this the "Quant Trading Shopping List". It''s no secret as to why these firms appear in recruiters'' inboxes, however there are a number of reasons as to why this type of hiring strategy is pretty hard to implement. 1 - Money. I''m sure it''s a nice thought to hold hands with them around a fire and sing kumbaya for your offer that is 25% of their current comp, but the reality is there will be too much of a gap between what you can pay and what they''ll accept. 2 - Prestige. This can of course vary geographically, however it''s only logical that if your target candidate has spent most of their life working as hard as possible to get their foot in the door at a firm held in high regard... they''ll not be in a rush to leave. Compound this with parents being involved in career decisions and all of a sudden, moving to your unknown startup becomes even more of a challenge. 3 - Visas. These firms allocate a large amount of resources to help transfer H1B Visa sponsorships for example, which your target candidates will be well aware of. 4 - Infrastructure. The "kids in a candy store" phenomenom. Access to a mind boggling amount of GPUs or robust ULL connectivity to the world''s largest exchanges. The optimistic amongst you will notice that these brief points above are not insurmountable peaks, simply things to be made aware of when positioning why a candidate should take on the risk to join you. Money? If you can''t compete with cash you have two options. - Broaden your talent pool. - Be wildly transparent about what the upside is. "We allocate X amount of trading revenue to Y bonus pool. Whilst fully discretionary, this typically looks like Z on an annualised basis." Remember, these people didn''t get into the firms they work at through luck alone, so they''ll smell a rat ASAP Rocky if you''re not realistic. Prestige? If your brand is unknown, think outside of the box. - Who are your advisors? - What is the most impressive problem your team/company has solved? Visa? - Broaden talent pool. - Speak with immigration lawyers before saying you can sponsor. Infra? - What are the coolest ways that you''re solving infra related problems vs. these target firms? - Why you''re not interested in the ULL trading game; "be the smartest not the fastest". warwick@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7411020601303142400/', 'I''m seeing a huge shift in the market right now.... If you''ve been following me, you know my world is usually hedge funds and trading firms. But lately, a new wave of clients has been knocking on our door... pure AI firms. 🚀 And they''re not just looking for any talent. They''re hunting for the absolute best Python engineers to make the next generation of AI systems and agents. Some are offering base salaries up to £240k for the right people. 💰 It''s clear that the game is changing. This isn''t just speculation. We''re seeing major players like Goldman Sachs and JPMorgan deploy their own internal AI tools, and 92% of organizations plan to ramp up their GenAI investments. It''s one of the most exciting trends I''ve seen, connecting incredible talent with these pioneering AI companies across London, Europe, and the US. If this caught your attention, reach out, happy to discuss whether these opportunities align with your experience. daniel@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7410658211772620800/', '💭 𝐈𝐦𝐚𝐠𝐢𝐧𝐞 𝐛𝐮𝐢𝐥𝐝𝐢𝐧𝐠 𝐆𝐞𝐧𝐀𝐈 𝐬𝐲𝐬𝐭𝐞𝐦𝐬 𝐚𝐥𝐨𝐧𝐠𝐬𝐢𝐝𝐞 𝐩𝐞𝐨𝐩𝐥𝐞 𝐟𝐫𝐨𝐦 𝐭𝐡𝐞 𝐰𝐨𝐫𝐥𝐝’𝐬 𝐛𝐞𝐬𝐭 𝐐𝐮𝐚𝐧𝐭 𝐓𝐫𝐚𝐝𝐢𝐧𝐠 𝐚𝐧𝐝 𝐅𝐀𝐀𝐍𝐆 𝐟𝐢𝐫𝐦𝐬 - 𝐭𝐡𝐚𝐭’𝐬 𝐭𝐡𝐞 𝐥𝐞𝐯𝐞𝐥 𝐭𝐡𝐢𝐬 𝐭𝐞𝐚𝐦 𝐨𝐩𝐞𝐫𝐚𝐭𝐞𝐬 𝐚𝐭. I’m working with a GenAI start-up in London that’s scaling quickly and looking for several Software Engineers (Python). If you enjoy solving tough technical problems with seriously sharp peers, this one will stand out. 𝐖𝐡𝐲 𝐭𝐡𝐢𝐬 𝐜𝐨𝐮𝐥𝐝 𝐛𝐞 𝐠𝐞𝐧𝐮𝐢𝐧𝐞𝐥𝐲 𝐞𝐱𝐜𝐢𝐭𝐢𝐧𝐠: 🔵 𝐓𝐡𝐞 𝐭𝐞𝐚𝐦 𝐢𝐬 𝐞𝐱𝐜𝐞𝐩𝐭𝐢𝐨𝐧𝐚𝐥: You’d be joining engineers and researchers from Cambridge, Oxford, Imperial + backgrounds across top Trading Firms and Big Tech. It’s a high-calibre, fast-moving engineering culture. 🔵 𝐈𝐭’𝐬 𝐫𝐞𝐚𝐥 𝐟𝐫𝐨𝐧𝐭𝐢𝐞𝐫 𝐰𝐨𝐫𝐤: They’re building core GenAI systems - not wrappers or simple integrations. Expect challenges around distributed systems, performance, model integration, infra, and architecture. 🔵 𝐇𝐢𝐠𝐡 𝐨𝐰𝐧𝐞𝐫𝐬𝐡𝐢𝐩, 𝐥𝐨𝐰 𝐛𝐮𝐫𝐞𝐚𝐮𝐜𝐫𝐚𝐜𝐲: You’ll ship quickly, influence major decisions, and see your work in production fast. Smaller team = real impact. 🔵 𝐘𝐨𝐮’𝐥𝐥 𝐠𝐫𝐨𝐰 𝐟𝐚𝐬𝐭. If you like being around people who elevate your thinking and expect high standards, this is that environment. Interested or want to learn more? Drop me a message and I’ll share the details. david@durlstonpartners.com …more', '3mo • 3 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7410307154168999936/', 'To everyone who celebrates - hope you had an amazing Christmas and are enjoying some well-deserved downtime 🎄✨ If you’re heading into the final week of the year and feeling like 2026 needs a fresh start… we’re here to help. Whether you’re a software engineer, quant, trader, ML/AI specialist, or somewhere in the wider tech/trading ecosystem, we have plenty of exciting opportunities globally. Drop us a line at hello@durlstonpartners.com and one of the team will be in touch. Here’s to a strong finish to the year - and an even better next one 🤝✨ …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7409944773597216768/', 'Merry Christmas to everyone in our network who celebrates 🎄', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 9, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7409574862840827904/', 'Crypto Trading Firms; this candidate could be for you! I had the privilege of speaking with a candidate this week who has a 10+ year track record of launching crypto trading businesses/franchises in LATAM. Someone with a crypto brain but a TradFi heart. Think: doors to central banks being opened, not someone who wants to shill your PnD token. Their reputation in LATAM has been built over decades and they''ll be looking for businesses who pride themselves on black/white attitude to regulations (no grey zones). I''m into my 9th year recruiting for crypto, so it was one of the rare occassions where one of the people I''ve spoken to, had already been generating trading flow for over a year by the time I did my first placement in the industry! What can this person do? - Launch your crypto trading business in LATAM - Scale your existing crypto trading operations - Advise you on your LATAM GTM strategy To discuss further: 📲 TG @cryptowarwick 📩 warwick@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/limexcom/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7323299893303783424/', 'Some of the best ideas in quant finance don’t come from backtests or whitepapers - they come from conversations. Yesterday, our researcher Anh Clifton spoke at Women at the Table, hosted by Durlston Partners . She came back buzzing with ideas - not just about trading or machine learning, but about how much stronger this industry gets when we actually talk to each other. The event brought together an incredible mix of women in finance and tech. They talked about breaking into quant, navigating the culture, and where AI is heading next. It wasn’t just inspiring - it was practical, honest, and energizing. At Limex, we believe the future of fintech will be built by diverse teams solving hard problems together. Anh is a great example of that - whether she’s working on AI-powered trading models or just asking the kind of questions that make all of us think a bit deeper. If you’ve been to an event recently that challenged your thinking or expanded your network - drop it in the comments. We’d love to check it out. hashtag#QuantFinance hashtag#WomenInTech hashtag#Fintech hashtag#AITrading hashtag#Limex hashtag#DiversityInFinance hashtag#QuantFinance …more', '1yr • 1 year ago • Visible to anyone on or off LinkedIn', 16, 2, 2, 'video', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/in/shannon-palmer-18a3219a', 'https://www.linkedin.com/feed/update/urn:li:activity:7323281780441083904/', 'Gorgeous weather for a morning walk ☀️ At Durlston Partners, we encourage the whole team to take a walk at 10am and 3pm - plus take a longer lunch break if they’re heading to the gym or getting some exercise in.. much easier to do when the weather’s like this. I still remember Emily English (who did a couple of brilliant workplace nutrition sessions with us before she blew up - we knew she would!) saying that getting sunlight in your eyes first thing (no sunglasses) is better than two cups of coffee. Walks aren’t just good for your step count either - they boost focus, reduce stress, reset your energy, and are a great way to talk things through away from a screen. We’re big believers in a high-performance culture that doesn’t rely on burnout, and that starts with looking after our team. We are hiring! 📩 Drop me a message or reach out at shannon@durlstonpartners.com if you want to learn more. …more', '11mo • 11 months ago • Visible to anyone on or off LinkedIn', 16, 0, 1, 'video', 1, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7409201274061213696/', '𝐒𝐞𝐧𝐢𝐨𝐫 𝐀𝐈 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - 𝐋𝐨𝐧𝐝𝐨𝐧 - 𝐔𝐩 𝐭𝐨 £𝟐𝟎𝟎𝐤 𝐁𝐚𝐬𝐞 + 𝐄𝐪𝐮𝐢𝐭𝐲 A well backed, AI-start up focused on Gen AI is building out a new London office and is hiring AI Engineers to work on critical production grade agents that will be utilised by millions of users. They’re looking for Software Engineers with 2+ years of experience, strong fundamentals in Python / TypeScript, and an interest in building real-time, reliable, deeply technical AI systems. You’ll work end-to-end: designing agents, evaluating models, solving complex system challenges, and deploying directly with enterprise customers. If you’re looking for a role where you can take true ownership, build at pace, and work alongside exceptional engineers, drop me a message. Happy to share more details confidentially. For more information, please get in touch: James@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 8, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7408838767492358147/', 'Tired of slow, corporate tech? Here''s how to find a Python job that truly challenges you: Look for a role where you''re building, not just maintaining. At Durlston Partners, we are currently headhunting Python Engineers for a top trading team that''s creating ultra fast systems. We''re talking: ✅ No pointless meetings ✅ No outdated tech ✅ A real impact on performance If you''re a Python engineer who enjoys a challenge, this is for you. DM me, apply below, or tag someone who comes to mind. daniel@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7408476342251565056/', 'Thinking of finally buying a Raspberry Pi as a tech recruiter I had an interest in getting one when I was a teenager, and after a lot conversations with engineers, it feels like the right time to actually get started. I spend my days speaking to people who build trading systems, distributed platforms, and automation tooling, which has made me realise how useful it could be get even a little hands-on with the tech they use. A Raspberry Pi seems like a great way to start. It’s cheap, flexible, and I’ve been told that it can be beginner-friendly. For anyone that has owned one: 🟢 What’s the coolest thing you’ve built? 🟢 What beginner project would you recommend? 🟢 Any must-have accessories? Keen to hear your thoughts, and I’ll share whatever I manage to build! david@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 11, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7408110188588605440/', 'What happens if you run this Python code? What gets printed and why? Hint: It’s not what most developers expect at first glance. This tests your understanding of: - How Python handles default argument values - Mutability of objects - When objects are created and stored in memory 💡 If you can clearly explain this behaviour, you probably understand Python deeper than most. I’m working with a trading firm looking for Python Engineers who understand not just how to use the language, but how it works. Drop your answer below 👇 or DM me if this sounds like you. Let’s see who really knows Python daniel@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 5, 4, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7407751579799429120/', 'Today is officially the last day in the office for the DP team as we kick off our two-week bonus Christmas & New Year break 🎄✨ That said… the market absolutely hasn’t slowed down. We still have clients actively hiring across tech, quant, trading, data, and AI/ML - so if you''re exploring a move, do drop hello@durlstonpartners.com a note and one of the team will pick it up ASAP! …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7405932105060282369/', '𝗘𝘅𝗲𝗰𝘂𝘁𝗶𝗼𝗻 𝗧𝗿𝗮𝗱𝗲𝗿 (𝗖𝗿𝗼𝘀𝘀-𝗔𝘀𝘀𝗲𝘁) - 𝗲𝘅𝗽𝗮𝗻𝗱 𝘁𝗼 𝗣𝗼𝗿𝘁𝗳𝗼𝗹𝗶𝗼 𝗖𝗼𝗻𝘀𝘁𝗿𝘂𝗰𝘁𝗶𝗼𝗻 𝗨𝗽 𝘁𝗼 𝟮𝟱𝟬𝗸 𝗦𝗚𝗗 𝗧𝗖 - 𝗦𝗶𝗻𝗴𝗮𝗽𝗼𝗿𝗲 I am working with a fund in Singapore, looking for an Execution Trader, with cross-asset experience, strong Python skills for systematisation and an appetite to expand their knowledge into Portfolio Construction over time. Please let me know if you are interested, or have any strong referrals (if successful, they are well rewarded!) rahn@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 0, 1, 1, 'image', 0, NULL);
