INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7405569716380962816/', 'Tired of DevOps roles that are just about "keeping the lights on"? I''m looking for a Platform & Infrastructure Engineer who wants to do more than just keep the lights on. This is about building from the ground up in a fast-paced, startup environment. Your day? It''s all about high performance and low latency. - You''ll own the trading infrastructure, from system health checks with Grafana to deploying new features with Terraform and GitHub Actions. - You''ll hunt down bottlenecks, shave off microseconds, and build resilient, high-performance systems. - You''ll be at the core of a team that''s pioneering the next generation of trading infrastructure. This isn''t just another DevOps role. You''ll be shaping the future of a protocol that''s changing the game. Sound like you? DM me. Let''s build something incredible. daniel@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7405271477501001728/', 'Everyone thinks hiring slows down in December. They''re wrong. Most people tend to wait until the New Year. But the reality on the ground is different. Right now, teams are "scrambling" to use their 2025 budgets before they reset. It’s effectively a use it or lose it scenario for some, and that means a flurry of hiring activity that most people miss. Here’s what I’m seeing: 1) Firms Looking for an Edge Act Now: While your competition is winding down for the holidays, some firms are already securing talent for January. They have approved headcount and are moving fast to get ahead of the curve. This is especially true in the world I live in with the most respected Hedge Funds, trading firms, and FinTech/AI scale-ups. 2) Less Noise, More Opportunity: Because so many people assume it''s a quiet period, there’s less competition for the best roles right now. This is the time to make a strategic move while everyone else is distracted. 3) Case in Point: I have a prime example on my desk right now. It''s a remote Developer position at a top HFT firm. This isn''t just another job, it''s a chance to build core trading systems in Python and C++, handling millions of transactions in one of the most exciting corners of the market. This is the kind of opportunity that doesn''t wait for the January rush. If you''re a talented engineer who gets what this role is about, we should talk. For everyone else, my advice is simple: don''t wait. The best time to make your next move is now, while the rest of the market is caught off guard. daniel@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7405207302225694720/', '🚀 NYC Head of Quant & Low-Latency Opportunities: A small, high-performing NYC team is looking for top talent to build and run crypto trading strategies. These roles offer hands-on work with live execution, research, and real P&L impact. 💼 Head of Quant Trading (Crypto) 💻 Quantitative Developer – Low-Latency Crypto Full-time, in-office (NYC), competitive compensation with performance bonus. Shoot me a DM if interested! matt@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 12, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7404844940175888384/', '𝗦𝘁𝗿𝗲𝘀𝘀𝗲𝗱 𝗮𝗯𝗼𝘂𝘁 𝘆𝗼𝘂𝗿 𝗻𝗼𝗻-𝗰𝗼𝗺𝗽𝗲𝘁𝗲? 𝗧𝗼𝗽 𝗚𝗲𝗻𝗔𝗜 𝗳𝗶𝗿𝗺 𝗶𝗻 𝗟𝗼𝗻𝗱𝗼𝗻 - $𝟯𝟰𝟬𝗸 𝗯𝗮𝘀𝗲 + 𝗘𝗾𝘂𝗶𝘁𝘆 Short story: Top GenAI firm in London, incredible engineering team (think top 10 global universities, tops of their class, top tech firms etc), looking for best of the best Software Engineers. Great opportunity to move out of finance/trading into a new position, avoiding any lengthy non-competes. 2+ YOE, problem solvers, with strong understanding of multimodal models. High bar, but one of the fastest processes I''ve seen, just 2-3 stages!! Please reach out if you''re interested rahn@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 14, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7404818493218426880/', 'It’s rare to get so many brilliant people in one room as we did at our 100 Hedge Funds event - PMs, researchers, founders, engineers, investors, traders - all willing to share ideas and be part of something bigger! We’re already planning the next wave of events across the UAE, London, and New York - and we’d love to involve as many of you as possible. If you want to attend, sponsor, or collaborate: events@durlstonpartners.com. Catch the highlights here https://lnkd.in/enCX2-ya …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 6, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7404554250275540993/', 'It''s been a pretty crazy few weeks and it doesn''t look like its letting up any time soon. Here are the roles that will be active and will hire over the next month or so. hashtag#London hashtag#Python Python Risk Developer - Hedge Fund - Up to £300k TC Middle Office Developer(Python/C#) - Hedge Fund - Up to £275k Desk Developer - Hedge Fund - Up to £200k Core Developer - Market Maker - Up to £250k hashtag#Cplusplus Trading Systems Developer - Elite Execution platform - Up to £200k Execution Developer - Quant Hedge Fund - Up to £500k Market Data Team Lead - Quant Hedge Fund - Up to £600k hashtag#AI Senior AI Engineer - Trading AI Start Up - Up to £150k + Equity Founding Engineer - GenAI firm - Up to £150k + Equity Software Engineer - Conversational AI Firm - Up to £200k Base + Equity Engineering Manager - Conversational AI Firm - Up to £280k Base + Equity Deep Learning Team Lead/Manager - Prop Trading - Up to $3m TC hashtag#Remote Core Engineer - Python/C++ - Crypto Market Maker - Up to $300k TC Strategy Developer - C++ - Crypto Market Maker - Up to $600k TC C++ Engineer - Market Maker - Up to $200k hashtag#Quant Junior HFT QR - Elite Market Maker(NYC) - Up to $500k TC HFT Quant - Prop Trading(Amsterdam) - Up to $2m TC Multiple HFT Quant Roles in APAC for a Tier 1 Trading firm, if you have experience with HFT Futures, HFT Equities/ETF, Mid Frequency Equities - Up to $3m TC For more information, please get in touch. James@durlstonpartners.com …more', '4mo • Edited • 4 months ago • Edited • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7404482569435496449/', '🔥 Quant Roles 🔥 End of the year is looking to be a very busy one with plenty of opportunities for Traders, Researchers and Analyst across some of our core markets. Below is just a snippet of some exciting roles on my desk. If any of these are of interest or if you know someone who is a good fit, get in touch: jared@durlstonpartners.com 𝐑𝐞𝐦𝐨𝐭𝐞: ➖ Quant Trader (Indian Options) - TradeFi Prop Shop - $100 - 250k + PnL split ➖ Quant Trader (China Futures or European futures/STIRs) - TradeFi Prop Shop - $100 - 250k + PnL split 𝐔𝐀𝐄: ➖ Indian Options Quant Trader – Prop shop - open base + PnL cuts (up to 35%) ➖ Crypto Quant Trader – Prop shop- open base + PnL cuts (up to 35%) ➖ US Futures/CME Quant Trader – Prop shop - open base + PnL cuts (up to 35%) 𝐋𝐨𝐧𝐝𝐨𝐧: ➖ Options Trader (OTC and exchange trading) - Crypto HFT/MM - open base + discretionary bonus ➖ Junior Quant Researcher – Crypto MM - £90k - 110k base + bonus 𝐀𝐏𝐀𝐂: ➖ Fixed Income ETF Trader – MM (Sydney) - open package ➖ Index Arb Quant Researcher – MM (Singapore) - open package ➖ HFT to Intraday Quant Researchers (Equities, ETFs or Futures) – MM (Singapore or Shanghai) - open package jared@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 9, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7404157994843783169/', 'It''s the start of another glorious week here in the UAE, here''s a quick look at opportunities we have for you here! C++ Quant Developer; work in a high-frequency crypto trading team with a strong TradFi HFT DNA. You''ll be improving the performance of algorithmic trading strategies on-exchange and will need to have done so before. 💲 Up to $180k base + multiples of base as bonus (discretionary) 📍 Dubai (relo + visa + flights + 1m rent) DeFi Quant Developer; work directly with the Head of Trading from a niche crypto trading company to deploy fully systematic trading strategies on-chain in Python. 3+ years experience in a similar role, non-negotiable. 💲 Up to $200k base + multiple of base as bonus (discretionary) 📍 Dubai (relo + visa + flights + 1m rent) C++ Engineer; you''ll be building connectivity to new venues. Thanks to the lack of standardised exchanges in crypto, this means you''ll have a constant, challenging stream of work. 💲 Up to $120k base + multiple of base as bonus (discretionary) 📍 Remote or Dubai (full relo provided) C++ Developers; multiple headcount for a team in a systematic trading firm, rebuilding their execution platform in C++. Prior experience in systematic trading is non-negotiable. 💲 300k-400k all in 📍 Dubai (5 days on-site) Algo Execution Developers; multiple headcount for the team building the algorithms (Python or Java) which are deployed on the infrastructure, created by the people in the role just above this. 💲 Peak of $500k all in (subject to experience). 📍 Dubai (5 days on-site) 📩 warwick@durlstonpartners.com 📲 TG @cryptowarwick …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7403772534007123968/', '𝐃𝐨𝐧’𝐭 𝐰𝐚𝐢𝐭 𝐟𝐨𝐫 𝐭𝐡𝐞 𝐉𝐚𝐧𝐮𝐚𝐫𝐲 𝐬𝐭𝐚𝐦𝐩𝐞𝐝𝐞 🐂 It’s a common misconception that hiring stops in December. In reality, it can actually be one of the most strategic times to explore the market. Here is why you should engage in processes now for Q1 2026: 𝐔𝐬𝐞 𝐈𝐭 𝐨𝐫 𝐋𝐨𝐬𝐞 𝐈𝐭 𝐁𝐮𝐝𝐠𝐞𝐭𝐬: Many companies still have headcount they are actively trying to close off this side of the year. 𝐋𝐞𝐬𝐬 𝐂𝐨𝐦𝐩𝐞𝐭𝐢𝐭𝐢𝐨𝐧: While others pause for the holidays, you potentially get the Hiring Manager’s full attention. 𝐁𝐮𝐝𝐠𝐞𝐭 𝐀𝐩𝐩𝐫𝐨𝐯𝐚𝐥𝐬: Firms are signing off 2026 headcounts today to ensure teams are ready to go in January. Some of the most urgent roles I''m working on 👉 https://linktr.ee/dezihe ⭕ Python Quant Developer (Fixed Income/Credit) - London - £140k (base) ⭕ Quant Researcher - Multiple Locations - Up to $850k TC ⭕ C++ Developer - Remote - Up to $250k (base) ⭕ Engineering Manager (Python) - London - Up to £300k (base) ⭕ Senior Python Developer - London - Up to £250k (base) 📉 Beat the rush. DM me to get ahead. david@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 10, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7402644179375255552/', 'The UAE hedge fund ecosystem is scaling and our 100 Hedge Funds event in Dubai proved it. The region isn’t just growing - it’s becoming a global hub. It’s been a privilege for us at Durlston Partners to sit in the middle of this evolution over the last few years, helping build teams across Dubai and Abu Dhabi. We’ve shared the recap, photos, and video here: https://lnkd.in/eeYJyy3P Next up: • 100 Hedge Funds Abu Dhabi – February • 100 Hedge Funds Dubai – March • Women at the Table London – TBC • 100 Hedge Funds London – April • 100 AI Firms London – May If you’d like to attend or partner with us for any of the above, email events@durlstonpartners.com. PS, if you''re interested in a move or if you''re hiring in the region, reach our to our Dubai dream team: Rahnpreet Sandhu Joshwa Shah Vax Bahram Dana Bahram Jared Wolfaardt James Skelt Warwick Poelman (واريك بولمان) …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 12, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7401281448546238464/', 'It''s looking like a busy week, and I''m focusing on roles that could offer an exciting challenge. Here''s a look at what I''m working on: 1. 𝗙𝗼𝘂𝗻𝗱𝗶𝗻𝗴 𝗗𝗲𝘃𝗢𝗽𝘀 & 𝗦𝗼𝗳𝘁𝘄𝗮𝗿𝗲 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿𝘀 - 𝗔𝗜 𝗧𝗲𝗰𝗵 (𝗡𝗬𝗖/𝗦𝗮𝗻 𝗙𝗿𝗮𝗻) This is a chance to get in on the ground floor of the AI revolution. You''ll be building the infrastructure that will power the next generation of technology, a skillset that is in extremely high demand. These roles are not just about coding; they''re about shaping the future of how businesses operate. 2. 𝗗𝗲𝘃𝗢𝗽𝘀 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿𝘀 - 𝗖𝗿𝘆𝗽𝘁𝗼 𝗧𝗿𝗮𝗱𝗶𝗻𝗴 (𝗟𝗼𝗻𝗱𝗼𝗻 & 𝗥𝗲𝗺𝗼𝘁𝗲 𝗘𝗨) The crypto market is maturing at an incredible pace, and HFT firms are leading the charge. In these roles, you''ll gain invaluable experience in a fast-paced, high-stakes environment where your work has a direct impact on the bottom line. 3. 𝗖++ 𝗦𝗼𝗳𝘁𝘄𝗮𝗿𝗲 𝗗𝗲𝘃𝗲𝗹𝗼𝗽𝗲𝗿𝘀 - 𝗖𝗿𝘆𝗽𝘁𝗼 (𝗗𝘂𝗯𝗮𝗶) As quantitative trading expands into new asset classes like crypto, the demand for skilled C++ developers is exploding. This is an opportunity to become a specialist in a rapidly growing and lucrative field. 4. 𝗖++ 𝗦𝗼𝗳𝘁𝘄𝗮𝗿𝗲 𝗗𝗲𝘃𝗲𝗹𝗼𝗽𝗲𝗿𝘀 - 𝗤𝘂𝗮𝗻𝘁 𝗧𝗿𝗮𝗱𝗶𝗻𝗴 (𝗠𝘂𝗺𝗯𝗮𝗶) This is where you can build a career at the intersection of finance and technology. You''ll be developing the high-speed, automated systems that are the backbone of modern financial markets, a skill set that is always in demand. If you''re interested in learning more, let''s connect. ✉️ david@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7401202174757859329/', 'It’s officially Christmas at Durlston Partners 🎄✨ We’re on the three-week countdown to our annual two-week bonus holiday, but the market clearly didn’t get the memo… it is busier than ever! Interviews are flying in, offers are going out, and we’ve even had starters confirmed before year-end - no signs of slowing down at all. If you’re a candidate exploring your next move, our team has a huge amount live right now. Drop your CV to hello@durlstonpartners.com and one of us will be in touch if we have something relevant for your profile. If you’re a client looking to make the most of December and get ahead of the January hiring rush, we’d love to support you. And if you’re a recruiter in our space… we’re hiring for January starts - next year is set to be a big one. Warm desks, brilliant clients, no restrictions on access to roles or clients, no thresholds, no desk fees, and the ability to plug into our platform and bill from day one. Plus proper incentives and rewards for performance. Exciting end to the year strong and even bigger things ahead. 🎄🚀 …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7400919042942738432/', '"I''d love to be working in AI." 🤖 I hear this more and more from engineers in trading - and honestly? The timing has never been better. If that sounds like you, maybe it’s time to explore what’s next. 💭 I’m working with cutting-edge AI tech companies across New York & London, all looking for exceptional engineering talent. People who can bring rigor from finance into a space that’s fast, creative, and full of possibility. If you’re curious what that transition could look like, let’s have a confidential chat. 💬 ab@durlstonpartners.com …more', '4mo • 4 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7399469536615354368/', '💰 Crypto trading is booming, with onchain holdings soaring past $175 billion! 💰 This means a huge demand for DevOps Engineers who can build the high-performance infrastructure to keep it all running. I''m partnering with a top crypto trading firm to find a Fully-Remote DevOps Engineer for a special role. Their team is looking for their first DevOps hire, giving you the freedom to build their entire environment from the ground up. This is a chance to: ✔️Architect and implement the CI/CD strategy from scratch for their low-latency trading apps ✔️Define their Kubernetes and GitOps workflows ✔️Select and implement the best tools for automation and monitoring. ✔️Lay the foundation for how they deploy and manage their infrastructure for years to come If you''re a DevOps Engineer who wants to own the entire process and make a huge impact in the crypto trading space, I''d love to connect. ✉️ david@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7399107133163749376/', '𝐒𝐨𝐟𝐭𝐰𝐚𝐫𝐞 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 – 𝐏𝐫𝐨𝐩 𝐓𝐫𝐚𝐝𝐢𝐧𝐠 – 𝐋𝐨𝐧𝐝𝐨𝐧 – 𝐔𝐩 𝐭𝐨 £𝟏𝟎𝟎𝐤 𝐁𝐚𝐬𝐞 + 𝐁𝐨𝐧𝐮𝐬 One of our long-term clients is looking to add a Java Engineer to their team in London. This is a unique role, working to push real-time trading data from the backend systematic trading systems, to their UI''s used by Traders and Quants. If you''re interested in working in a boutique firm, where you get exposure to the entire tech stack while having the stability of a firm that has posted strong returns for over 20 years. For more information, please get in touch. james@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7398744719759081474/', 'Your next career move might be below 👇 I’m always looking to connect with talented professionals across Software Engineering, Infrastructure, Quant Research, ML, etc. That said, here are some of the most exciting and fast-moving opportunities I’m currently working on: 🖥️ CRYPTO 🖥️ 🟢 Site Reliability Engineer (Linux) - Crypto HFT - Fully Remote, US hours - $450k TC - (HFT/Trading background required) 🟢 Platform Engineer - Crypto HFT - London (Hybrid) - £85k + bonuses 🟢 DevOps Engineer - Crypto Trading firm - Fully Remote (Worldwide) - $120k + bonuses 🤖 AI 🤖 🟡 Founding DevOps Engineer - AI Tech firm - NYC/San Francisco - $350k + equity 🟡 Software Engineers - AI Tech firm – NYC/San Francisco - $500k + equity 🟡 Machine Learning Engineer - AI Start-Up - London - £250k - (Looking for PhDs with ML experience) 📈 TRADING 📈 🔵 DevOps Engineer - Quant Trading - Mumbai - $80k 🔵 C++ Software Developers - Quant Trading - Dubai 🔵 C++ Software Developers - HFT – Mumbai 🔵 Python/C++ Software Developers (Trading/Quant backgrounds) - London, Amsterdam, UAE, Remote - Various positions If you’re open to new opportunities or simply curious about what’s out there, let’s have a chat! 💬 Drop me a message or email me at david@durlstonpartners.com 💬 …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 9, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7398382327976058880/', 'It''s been quite interesting overhearing some of my colleague''s conversations recently here in the UAE, with them dutifully providing more colour on what compensation actually looks like for SWEs & Quants to their candidates. I can''t fault the candidates, their expectations are largely formed by information they''re given. The gap between bid and offer also appears to be exponentially larger of course, if that information if 5+ years old as well. What do you want to tell me then Warwick? Well prep your pitchforks... Riding the gravy train has been over for a long time in the UAE. Double your pre-tax income? What a lovely thought. Triple your pre-tax income? Let me know if your palace needs a gardener and I will leave LinkedIn and recruitment behind forever. The reality is both of these expectations are still pretty wild. The most common structure we see for those relocating from Europe? A sideways move on pre-tax income for Y1 + flights + 1 month hotel stay. We all like to think we''re special but the reality is, there will be plenty of people ready to accept the offer that you just turned down... 169,000 of them in Dubai alone last year for that matter. warwick@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7362120112729911299/', 'Market fun run next week...', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'video', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7397608500245237760/', 'A huge thank you to everyone who joined us at our 100 Hedge Funds event in Dubai earlier this month. The room was packed with brilliant people across hedge funds, trading, fintech, and digital assets, and the energy reflected the momentum building in the region. We’re excited to keep building spaces where this community can connect, collaborate, and share ideas. If you’d like to get involved - whether attending, partnering, or contributing - we’d love to hear from you. Upcoming events: • 100 Hedge Funds – Abu Dhabi (February) • 100 Hedge Funds – Dubai (March) • Women at the Table – London (TBC) • 100 Hedge Funds – London (April) • 100 AI Firms – London (May) To attend, sponsor, or get involved: events@durlstonpartners.com. …more', '5mo • Edited • 5 months ago • Edited • Visible to anyone on or off LinkedIn', 17, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7397291400171565057/', 'Want to shape the infrastructure behind next-gen Crypto trading? Then this one is for you! 🚀 I''m currently working with an elite-level crypto trading firm that is building high performance, ultra-low latency systems to trade digital assets globally. They’re looking for talented Platform Engineer to join their team and help build, maintain, and scale the infrastructure powering their trading systems. Feel free to send me a DM or email at david@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7397283831118209024/', 'Ready to move from a slow moving bank or fintech to the fast paced world of trading? I''m looking for a Platform Engineer for a top tier high frequency crypto trading firm in London. They''ve been early pioneers and are trading billions daily. This isn''t for everyone but you''re probably the right fit if you: - Graduated from a top university with a degree in Comp Sci, Physics, or Maths. - Have experience from high pressure environments in banking, fintech, or other crypto firms. - Deep knowledge of Linux, AWS, and Python. Your mission, if you choose to accept, will be to own the infrastructure for a 24/7 global trading operation, working directly with developers on architecture and performance. Sound like you? DM me. Let''s talk. daniel@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7396921467663261698/', '🚀 Hiring: Full Stack Developer (Java/React) – Post Trade | New York, NY 🏢Our client a global hedge fund that’s scaling its Post Trade Technology team in NYC. They’re looking for a Full Stack Developer who’s passionate about building performant, intuitive tools that help trading, operations, and compliance teams make smarter decisions. You’ll work directly with business users and portfolio managers, owning projects end-to-end - from design to delivery - in a fast-paced, collaborative environment. 🛠️Tech stack: Java, TypeScript/React, Python, Kafka, SQL Server, Oracle, Postgres, Docker. 🔎Ideal background: 5+ years in Core Java + React, solid SQL, and experience in a financial environment (buy/sell side preferred). 📍 Onsite in a modern New York office. 💼 Competitive compensation + strong engineering culture. If you’re curious, collaborative, and want to build tech that makes an impact -let’s chat. ab@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7396559071321141249/', '𝐅𝐫𝐨𝐧𝐭𝐞𝐧𝐝 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - 𝐀𝐈 𝐅𝐢𝐧𝐓𝐞𝐜𝐡 𝐒𝐭𝐚𝐫𝐭-𝐔𝐩 - 𝐔𝐩 𝐭𝐨 £𝟏𝟑𝟎𝐤 𝐁𝐚𝐬𝐞 + 𝐄𝐪𝐮𝐢𝐭𝐲 We''re partnered with an AI firm, looking to solve complex context-dependant problems across the financial services sector that traditional software can''t handle. 𝐑𝐞𝐬𝐩𝐨𝐧𝐬𝐢𝐛𝐢𝐥𝐢𝐭𝐢𝐞𝐬: - Build responsive, performant interfaces in React/TypeScript. - Collaborate with product and backend teams to deliver features end-to-end. - Work with data-visualisation tools (D3.js, Chart.js) and real-time streaming data. - Optimise builds with Webpack/Vite and contribute to CI/CD pipelines on GCP/AWS. - Ensure reliability, security, and scalability across a modular front-end framework. 𝐑𝐞𝐪𝐮𝐢𝐫𝐞𝐦𝐞𝐧𝐭𝐬: - Strong front-end engineering experience (JavaScript/TypeScript, React). - Experience with data-rich or financial web apps. - Familiarity with REST/GraphQL APIs and performance optimisation. 🌍Location: London (Hybrid) 💰Comp: Up to £130k Base + Equity For more information, please get in touch: james@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7395834283426484224/', '🚀 𝐇𝐢𝐫𝐢𝐧𝐠: 𝐌𝐢𝐝-𝐋𝐞𝐯𝐞𝐥 𝐉𝐚𝐯𝐚 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 (𝐋𝐨𝐧𝐝𝐨𝐧)☕ I am working with one of the fastest-growing liquidity providers specialising in Exchange Traded Funds (ETFs), and they are expanding! 🤝 Join a tight-knit team of ~30 expert traders and software engineers. 📍 Location: London 💻 Hybrid: 2 days in-office per week 👨‍💻Tech Stack: Java, SQL, Postgres, AWS, Git 🧠𝐀𝐛𝐨𝐮𝐭 𝐘𝐨𝐮: ✅ 3 - 5 years of experience ✅ Strong Core Java - you’ll be doing a bit of everything: from low-level programming to more standard Java work ✅ Comfortable with databases & cloud services ✅ Proven track record solving complex technical problems If you’re excited by the idea of working in a small, high-impact team at the intersection of technology and markets, this could be your next big move. 📩𝐌𝐞𝐬𝐬𝐚𝐠𝐞 𝐦𝐞 𝐢𝐟 𝐲𝐨𝐮''𝐝 𝐥𝐢𝐤𝐞 𝐭𝐨 𝐥𝐞𝐚𝐫𝐧 𝐦𝐨𝐫𝐞! louis@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 7, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7395471899826495488/', 'This is an exciting one: Founding DevOps Engineer - AI Tech Firm - San Francisco /NYC- $300k (base) 🔹 DevOps Engineer 🔹 Exciting AI Tech Firm 🔹 San Francisco or New York 🔹 $300k (base) + benefits We’re currently working with a well-established AI Tech firm with a strong track record and continued growth. They’ve been hiring talent from exceptional backgrounds (Big Tech, Top Universities, Trading, AI Tech Start-Ups, etc.) and are now looking for a Founding DevOps Engineer to take full ownership of their infrastructure and automation. You’ll help scale their AI systems, build reliable high-performance platforms, and work closely with ML and data teams to bring models into production. This is a chance to shape the DevOps space in a company that’s already proven itself. david@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 10, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7395109520345026560/', 'What do Julius Caesar and George Boole have in common? Julius Caesar might have been the world’s first recruiter and one of the best! He is credited with the earliest documentation of strategic recruiting and pioneering one of the earliest known employee referral programmes, offering soldiers a third of their salary for recruiting other soldiers Centuries later, George Boole gave us the ANDs, ORs, and NOTs that are now behind every Boolean search. That''s how both men shaped modern-day recruitment. From swords to search strings, the mission’s the same: find great talent and build something that lasts! Dana Bahram …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7394018650019614720/', 'Busy start to the week, and there are some really exciting roles I’m working on! Here’s a quick look at the most urgent openings - but even if nothing below feels like an exact match, I’m always happy to chat with strong engineers/grads: 🌍 Remote ◼️ Senior SRE (US hours) – Crypto | Background in HFT/Quant Trading/Crypto required ◼️ DevOps Engineer (EU hours) – Crypto 🌍 London: ◼️ Software Developers (C++/Python) – Elite AI start-up | Top education & experience at challenging firms ◼️ C++ Software Developers – Quant Trading/HFT ◼️ Python Developers – Quant Trading/HFT 🌍 Amsterdam: ◼️ Senior SRE - HFT | Background in HFT/Quant Trading essential 🌍 UAE: ◼️ C++ Software Engineer – Quant Trading 🌍 India: ◼️ DevOps Engineer – Quant Trading ◼️ C++ Software Engineer – Quant Trading If you’re exploring your next move in Trading, Crypto, or AI, please reach out! ✉️ david@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7393293819770929152/', 'One of the perks of recruiting for India-based roles is I finally get to use the word "lakhs" in conversation and brush up on my currency conversion math skills at the same time. First, I''m hiring a C++ Software Engineer in Mumbai or Dubai (up to $120K USD / ₹1 crore) to build a greenfield trading system for equities and options. You''ll need strong C++ expertise with low-latency systems and demonstrated ownership of projects from start to finish. Second, we have a Python Middle Office Developer role that''s fully remote from anywhere in India (up to $130K USD / ₹1.1 crore). You''ll need advanced Python skills and previous experience facing middle office and trading desks in a hedge fund or securities firm. Ping me if interested. Referrals welcome and well rewarded! josh@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7392931426578624512/', 'Having spoken to countless engineers over the years, it’s clear that the best people don’t just want a job - they want a challenge. That’s one of the reasons I’ve enjoyed working closely with firms in the Trading (and now also Crypto and AI) space. These industries are unique. They demand world-class engineering, they move incredibly fast, and they constantly push people to think in ways they haven’t before. The bar is high, but so are the rewards. I’m currently working with a handful of elite firms in London hiring Python & C++ Software Engineers. You’ll be exposed to high-performance systems where every millisecond counts, solving deep technical challenges with some of the brightest minds around. These environments are fast-paced, meritocratic, and your impact will be immediate. These firms are ideally looking for: ✔️ Strong academic background (e.g. Degrees/PhDs from top global universities) ✔️ Proven experience in demanding environments (Trading, Crypto, AI, start-ups, etc.) ✔️ A genuine passion for technology. Someone who doesn’t see the job as just writing code, but has an interest in solving problems, experimenting with new ideas, and pushing the limits of what’s possible ✔️ A mindset for impact If you’re interested, please feel free to reach out to me directly on LinkedIn, or email me: david@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 9, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7392569061962047488/', 'Hiring across hedge funds, HFTs & deep tech start-ups 1. Frontend Engineer @ Hedge Fund (London) 🧠 Build data-rich UIs in React/TypeScript for PMs, Traders & Quants 🧠 Hedge fund/trading experience required 💰 Up to £170k base (data viz specialists especially valued) 2. Middle Office Developer @ Hedge Fund (London) 🧠 Mission critical systems: Risk, PnL, full trading lifecycle 🧠 Python & C# essential 💰 Up to £300k TC 3. C++ Quant Developer @ HFT (Dubai or Mumbai) 🧠 Greenfield trading systems build in equities & options 🧠 Strong C++ / competitive programming background 💰 $100k – $140k base 4. Site Reliability Engineer @ Crypto HFT (Remote: US/Canada, EST hours) 🧠 Linux, AWS, Python, Kubernetes, Grafana, Terraform, Ansible 🧠 Low-latency trading systems experience a plus 💰 Up to $400k USD TC 5. Principal Engineer @ Deep Tech Start-up (London) 🧠 8+ years experience in Rust, C++ or Java 🧠 Solid Computer Science fundamentals and Tech Product knowledge required 💰 Up to £150k base + Equity Ping me if interested! Referrals welcome and rewarded josh@durlstonpartners.com hashtag#DPDMCC …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7392244410987618304/', 'I posted a C++ role and got 6,634 applications... That’s not a typo. The reality is, no hiring manager or recruiter can sift through 6,000+ CVs. Your application gets a quick glance, at best. I see the same mistakes again and again: → CVs that only list responsibilities, not achievements. → Zero data to back up experience. That’s why you’re not hearing back. Your goal isn''t just to apply. It''s to make it impossible to be ignored by hiring managers or recruiters. Here’s how: 1. Quantify everything. Don''t say: "I optimized the system." Say: "I reduced latency by 20% by optimizing the system." Numbers prove your value. 2. Open source or side projects. Contributing to open source C++ projects or competitive programming demonstrates initiative, passion, and technical skill in a way CV bullet points rarely capture. 3. Tailor your CV. If the job mentions "market data," and you have that experience, make sure those words are on your CV and explained what you did. Stop being another number. Start being the solution. Your experience is valuable. Make sure we see it. daniel@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 6, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7391478101576417281/', '𝗨𝗔𝗘 𝗛𝗲𝗱𝗴𝗲 𝗙𝘂𝗻𝗱 𝗧𝗶𝗺𝗲𝗹𝗶𝗻𝗲 - 𝘁𝗵𝗲 𝟱 𝘀𝘁𝗮𝗴𝗲𝘀 𝗼𝗳 𝗴𝗿𝗼𝘄𝘁𝗵 Funds are still relocating, but the playbook is evolving, it’s no longer just internal moves from other offices. I have been fortunate to be a part of this across Dubai and Abu Dhabi, and here is how I categorise the stages that most funds follow. 1️⃣ First wave - investor relations teams have had a historic presence in the region to build deep relationships with the vast capital base in the region. 2️⃣ Second wave - a few PMs and small teams acting as first movers, testing the waters for funds, or using their track record to push for relo and setup in a more tax-efficient location. Funds can also be incentivised to setup a physical location with the ''FOMO'' of missing out on the LP relationships that other funds are expanding with a physical investment and trading presence. 3️⃣ Third wave - big flows of PMs relocating, driven by a variety of factors and the proven success of the second wave. This cements the location as a densely front-office dominated location, with teams requiring the relo of their QRs, developers, analysts etc. 4️⃣ Fourth wave - filling out full teams, occasionally building out more substantial middle and back office teams to move away from being seen as a satellite office to a full standalone. A key step to move the needle (and make head-hunters like me happy) is local talent and BD teams, moving away from relying on London and NYC. 5️⃣ Fifth wave (yet to come) - shifting core global functions from NYC, London, and other hubs to the UAE in some cases. The more cost effective nature of the region makes it attractive to build out significant functions here. We have seen many funds setup offices in Eastern Europe and India to capitalise on top tech talent, but the UAE hits a perfect sweet spot in the maturity vs cost matrix, as well as time zone. The UAE is no longer just a satellite office location or an experiment, it''s standing up on its own merits as a global hub for financial services. Most funds are in the 2nd and 3rd stages, with a few first movers into the 4th. More posts to come on what this looks like for individuals, deciding between funds at various stages, and how the relocation requires a different job search approach at times! 𝗡𝗼𝘁𝗲: the pic is the Museum of the Future in Dubai, I thought the steps up to the future metaphor was relevant to the above! I''d recommend it to anyone visiting as a family day out, with an interesting view on the past and future of the UAE and society as a whole. rahn@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7391387498855366656/', 'We’ve had an absolutely insane response to our 100 Hedge Funds event this Thursday in Dubai - we’re now officially at capacity. 🙌🔥 The guest list is world-class, with leaders from global hedge funds and prop shops, single and multi-family offices, institutional allocators, systematic and quant funds, digital asset firms, venture and fintech platforms, regulators, and advisors - plus founders, CIOs, PMs, Heads of Trading, Chief Risk Officers, quant researchers and developers, and capital formation and investor relations leads all confirmed. The momentum in this region right now is exceptional and we’re so excited to bring this community together. If you missed out this time, don’t worry - we’ll be hosting the next one in Abu Dhabi in a couple of weeks, so drop me a message if you’d like to join us there. 🇦🇪✨ Can’t wait for Thursday. …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 13, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7391070410903269376/', 'Two years ago, Tom Curtin invited me to Imperial College London''s Department of Computing undergraduate Project Showcase. We''d been running CV and interview workshops there, and this felt like the natural next step. The standard was incredible. After the showcase, I grabbed time with as many of them as I could to chat about what was next. Most already had internships or grad roles lined up (no surprises there), but I stayed in touch anyway. Fast forward to this summer. One of those students reached out for coffee to talk through their next move. We explored a few directions and landed on one that felt right: an AI Engineer role at a hedge fund. They absolutely nailed the interview process and got the offer! Sometimes the best relationships take a couple of years to come full circle. If you''re graduating from Imperial College Computing and want to explore opportunities in Software Engineering or Quantitative Research across London, drop me a message! josh@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7390375822345527296/', 'A few helpful facts for parents looking into education in the UAE: 6 of Dubai’s private schools are ranked amongst the top 100 globally this year - Dubai College - Nord Anglia International School Dubai - Jumeirah College - JESS Dubai - Repton School - Swiss International Scientific School 227 Private Schools in Dubai 208 Private schools in Abu Dhabi 5% - 16% from Dubai College achieve a place at Oxford or Cambridge Fees range from $ 3,500 to $ 17,500 per term. Please connect/follow for more Dubai / UAE insights Dana Bahram …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 9, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7390028536876527616/', '**Huge Growth Opportunities** ~ Founding DevOps Engineer (NYC) - First DevOps hire! - Strong AWS experience, Python, CI/CD - DevOps/Infrastructure engineering - Experience at a startup, small-midsize preferred - Strong software engineering fundamentals, ability to debug/optimize systems ~ Multiple Software Engineers (NYC or SF) - Python, Java, or GO exp - 1-3+ years of experience ~ Full Stack SWE (NYC or SF) - Python + React exp - 1-3+ years of experience ~ Data Engineer (NYC) - Experience building ETL pipelines - Founding engineer or co-founding experience is a plus ~ AI Operations (NYC) - Recent grads with STEM degrees (3.6/4.0 GPA or higher) ~ SDR (NYC) - Recent grads with some sales background ~ General Manager - Healthcare (NYC) - Lead and develop a high-performing cross-functional team - 8+ years of experience, including leadership roles at early-stage startups and in high-growth environments - consulting background is a plus ~ Mid-Market Account Executive Location: NYC / Chicago / Boston / SF Compensation: OTE $320k ($100k base) - Minimum 2+ years in a quota-carrying role at a SaaS startup - Proven track record of achieving an annual quota of $800k+ ~ Enterprise Account Executive Location: NYC / Chicago / Boston / SF Compensation: OTE $370k ($115k base) - Minimum 2+ years in a quota-carrying role at a SaaS startup - Proven track record of achieving an annual quota of $1.2M+ ~ Strategic Account Executive Location: NYC / Chicago / Boston / SF Compensation: OTE $430k ($130k base) - Minimum 4+ years in a quota-carrying role at a SaaS startup - Proven track record of achieving an annual quota of $1.6M+ DM if interested (*no third parties please*) matt@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 4, 2, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7389666143873024000/', 'Here are the 4 hottest tech focused roles I''m headhunting for right now: 1. 𝗙𝗿𝗼𝗻𝘁𝗲𝗻𝗱 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 @ 𝗮 𝗹𝗲𝗮𝗱𝗶𝗻𝗴 𝗟𝗼𝗻𝗱𝗼𝗻 𝗛𝗲𝗱𝗴𝗲 𝗙𝘂𝗻𝗱 ➟ Build data-rich UIs in React/TypeScript for PMs, Traders & Quants. ➟ Up to £170k base for someone with deep data viz experience. ➟ Hedge fund/Trading experience needed & based in London. 2. 𝗣𝘆𝘁𝗵𝗼𝗻 & 𝗖# 𝗗𝗲𝘃𝗲𝗹𝗼𝗽𝗲𝗿 @ 𝗮 𝘁𝗼𝗽 𝗻𝗲𝘄 𝗛𝗲𝗱𝗴𝗲 𝗙𝘂𝗻𝗱 ➟ Work on mission critical systems: Risk, PnL, and the full trading lifecycle. ➟ Based in London, strong Python + C# is a must. 3. 𝗠𝗶𝗱𝗱𝗹𝗲 𝗢𝗳𝗳𝗶𝗰𝗲 𝗗𝗲𝘃𝗲𝗹𝗼𝗽𝗲𝗿 @ 𝗮 𝗺𝗮𝗷𝗼𝗿 𝗠𝗮𝗿𝗸𝗲𝘁 𝗠𝗮𝗸𝗲𝗿 ➟ Process millions of daily transactions from dozens of global exchanges. ➟ Fully remote in India, requires Python and an interest in crypto. 4. 𝗦𝗶𝘁𝗲 𝗥𝗲𝗹𝗶𝗮𝗯𝗶𝗹𝗶𝘁𝘆 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 @ 𝗮 𝗵𝗶𝗴𝗵-𝗳𝗿𝗲𝗾𝘂𝗲𝗻𝗰𝘆 𝗗𝗶𝗴𝗶𝘁𝗮𝗹 𝗔𝘀𝘀𝗲𝘁 ➟ Join a global team where milliseconds matter. ➟ Deep experience with Terraform, Ansible, and low-latency systems is crucial. ➟ Remote across the US & Canada. These are career-defining opportunities to work. Sounds like your next move? Send me a DM. daniel@durlstonpartners.com …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7389317302602866688/', 'You know Christmas is coming when the Regent Street angels go up ✨ (photo right outside of our office). Ready for the chaos of Christmas over the next few months… with the dark nights setting in early, the lights make the city feel a bit more magical. As ever, feeling lucky to work on one of the most iconic streets in London. The team are pushing for a super strong end to the year with plenty lined up for 2026 before switching off properly during the two weeks of bonus Christmas leave everyone gets. I’m taking a slightly longer break myself over Christmas, but between now and then I’m keen to speak with experienced recruiters in our space. We’ve got a ton of exciting stuff happening across London, Dubai, and New York - and a platform you can plug straight into and start billing big right away. At Durlston Partners, we’re a leading tech and trading search firm partnering with some of the world’s top hedge funds, HFTs, fintechs, prop shops, and asset managers, hiring across quant, tech, data, AI/ML, and digital assets. We offer market-leading commission, no thresholds, caps, or desk fees, plus cash bonuses, profit share, and equity opportunity. Desks are genuinely warm, relationships are deep, and our average fee per placement is high, with plenty of deals way north of six figures. All the usual good stuff in terms of benefits: two-week Christmas bonus break, health insurance, wellness allowance, team lunches, and global incentives - it’s a strong setup for ambitious recruiters. Even if you’re not actively looking, always happy to have an informal chat. There’s also the option to relocate to Dubai if sunshine and tax-free commission sound tempting ☀️ …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 5, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7389298367862050816/', 'Keen to speak Traders who have succesfully run either of the below strategies in crypto (15-30%+ APY). We have a crypto prop trading client looking to allocate a huge amount of capital via SMAs. In return you get: - The best trading fees - Colo / Direct line connectivity - Fast execution: double digit micros tick-to-trade, - Reliable platform (three nines) 📩 warwick@durlstonpartners.com 📲 Telegram: @cryptowarwick Warwick Poelman (واريك بولمان) …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7388899886890504192/', 'Just two weeks to go until our next Women at the Table event in partnership with BlueCove. We’re excited to announce our next speaker, Rachel Brown. Rachel is an Engineer in BlueCove’s Quant Engineering team, where she plays a central role in shaping the firm’s data strategy. She has designed and implemented BlueCove’s Extract, Transform, and Load (ETL) pipeline for the firm’s Data Warehouse and works closely with teams across the business to unify data services that underpin investment and research processes. Before joining BlueCove in 2025, Rachel led the data function at Fulcrum Asset Management, overseeing a major transformation of the firm’s data ingestion, validation, and delivery pipelines. Prior to this, she worked as a data science consultant within HSBC’s Capital Finance and Investment Bank, and she began her career with an internship at Coutts & Co, a UK-based private bank. Rachel holds an MEng in Engineering from Imperial College London. We’re looking forward to hearing from Rachel and the other incredible women at BlueCove as they share their experiences and insights on the night. 📅 Date & Time: Tuesday 11th November, from 6pm 📍 Location: Mayfair, London …more', '5mo • 5 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7387808904916652032/', '𝗘𝗾𝘂𝗶𝘁𝘆 𝗶𝗻 𝗮 𝗖𝗿𝘆𝗽𝘁𝗼 𝗛𝗙𝗧 (𝗽𝗿𝗼𝗳𝗶𝘁 𝘀𝗵𝗮𝗿𝗶𝗻𝗴 𝗶𝗻 𝗮 𝗹𝗲𝗮𝗻, 𝗮𝗹𝗿𝗲𝗮𝗱𝘆 𝗽𝗿𝗼𝗳𝗶𝘁𝗮𝗯𝗹𝗲 𝘁𝗲𝗮𝗺) Owning a piece of a prop trading firm is a very quick way to build wealth, especially with the incredible returns seen in HFT, and a model designed for profit sharing. We are working with a prop firm in Dubai, running Crypto HFT strategies. They want the person who backs themselves, and the team they join, who are already profitable but very lean. Base will be approx $100k but this is incredibly upside aligned. Please reach out if you''re interested rahn@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 8, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7387446527541157888/', 'Very, very cool role for a crypto native investment firm; you''ll be Head Honcho for all things market-making, serving as the conduit between the projects the firm has invested in and advising them on who their best trading partners will be. This role would fit people from a variety of backgrounds but the non-negotiable is that you''ve worked for a crypto-native trading firm, offering market-making services before. Possible backgrounds? - Strategy @ crypto-native MM - Trading @ crypto-native MM - Sales @ crypto-native MM - Marketing @ crypto-native MM - Consulting background, before working in crypto-native MM (any function) The great news is that this firm has the relationships already; what they need is someone to take ownership of the providing best in class advisory solutions to their projects. 📍 Remote 💲 Up-to $200k base (subject to experience) + Equity + Bonus 📩 warwick@durlstonpartners.com 📲 TG @cryptowarwick …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7387405020159320064/', 'We’re getting close! Our 100 Hedge Funds Event is coming up in just a couple of weeks, 6th November in Dubai (DIFC), and we’ve had an epic response so far. The hedge fund scene in the UAE has exploded in recent years, now home to 150+ funds across Dubai and Abu Dhabi, and we’ve been fortunate to help build many of them. This event will bring together leaders from across the industry for an evening of conversation, connection, and celebration of the region’s rapid growth. There are still a few spots left - if you’d like to attend or find out more, drop us a line at events@durlstonpartners.com. …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 9, 1, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7386721750970994688/', 'Ever built something so good the traders thought you were one of them? Want the chance to? I’m working with a team that sits right in the heart of the action, building high-performance UIs that drive trading decisions, not just visualise them after the fact. It’s fast moving, real time, and highly collaborative, meaning you’ll work directly with PMs, quants, and engineers to shape how data flows and decisions get made. Think market data, pricing models, strategy analytics, all surfaced cleanly and intuitively. You’ll need to be fluent in React/TypeScript, and if you’ve worked with streaming data, real-time apps, or care deeply about performance and UX, this’ll suit you. It’s 5 days onsite in London (but before you scroll, it’s the kind of seat where you want to be in the room). Drop me a message if you want to hear more! Or, if you''re a frontend dev who’s secretly always wanted to be called a quant;) karolis@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7386672762519527424/', 'Just over three weeks to go until our next Women at the Table event in partnership with BlueCove. We’re delighted to announce our next speaker, Diana Fomina, CFA, Quantitative Researcher. Diana is a member of BlueCove’s Quantitative Research team where she works to develop and build the models required for the firm’s investment process. Prior to joining BlueCove’s Research team in 2022, Diana was a Quantitative Researcher at Squarepoint Capital from 2021–2022 and a Quantitative Engineer at BlueCove from 2019–2021. In 2015, Diana won silver medal in the International Tournament for Young Mathematicians and bronze medal in the European Girls’ Math Olympiad. Diana received her BSc in Applied Mathematics and Computer Science from Lomonosov Moscow State University in 2019. Diana is also a CFA charterholder. We can’t wait to hear from Diana and others on the night, and to welcome another fantastic group of women in the space. There are still a few spots left - email events@durlstonpartners.com if you’d like to attend. 📅 Date & Time: Tuesday 11th November, from 6pm 📍 Location: Mayfair, London Also, remember to join our Women at the Table community on LinkedIn! https://lnkd.in/eb9-cSGB …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 8, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7386355622130196480/', '**Massive Growth Opportunities in New York, Austin, & Chicago** Our client is a leading global market maker looking to grow their teams: New York: ~Machine Learning Engineer (Experienced) ~Machine Learning Research Engineer (Experienced) ~HPC Engineer (Experienced) ~Software Engineer C++ (Experienced) ~AI Agents Developer (Experienced) ~Software Engineer - Equities/ETFs (Experienced) Austin: ~Software Engineer, Hardware Research (Experienced) ~Software Engineer, Hardware Development ~Hardware Engineer (Experienced) ~AI Agents Developer (Experienced) ~FPGA Engineer (Experienced) ~Multiple Internships and recent Graduate Quantitative Developers/Software Engineers Chicago: ~Software Engineer, Developer (Experienced) ~FPGA Engineer (Experienced) ~Network Engineer (Experienced) ~Senior Software Engineer (Experienced) For more info: 📩 matt@durlstonpartners.com or DM me …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7385993223304880128/', '🚨 Urgent Hire: Front-End Engineer at a Global Macro Hedge Fund 🚨 I’m working with a leading global macro hedge fund managing billions in assets urgently looking for a Front-End Engineer (with the official title of Quant Developer) to take ownership of front-end design and implementation. This isn''t your typical front-end role. You''ll be at the heart of the trading floor, working directly with portfolio managers and quants. You will be tasked to build the high-performance, real-time interfaces and data visualization tools that are critical for shaping trading decisions in a fast-paced environment. This role offers a unique opportunity to have a direct and immediate impact on the firm''s P&L. You''ll be doing more than just coding, you''ll be solving complex problems and building the tools that give the firm its competitive edge. 💻 Tech Stack: React, TypeScript, UI/UX, real-time dashboards, complex data visualization. 📍 Location: London If you’re interested (or know someone exceptional), get in touch today, strictly confidential. daniel@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7385630824278380544/', 'I get asked a lot about the cost of living in Abu Dhabi and Dubai. Understandably, if you’re considering a move to the UAE, one of the first questions is ‘what’s it going to cost me and my family?’ And once you’re here, you’re thinking ‘can I cover rent, schooling, bills, groceries, and still have money left over to enjoy life and save?’ You want to live a better life than where you moved from. When comparing cities, it’s important not to look at cost of living in isolation. You have to combine it with the rent index to see the full picture. Take Abu Dhabi for example. Day-to-day life such as transport, groceries, childcare and eating out is significantly cheaper than London. But rent changes the equation. When you look at the global cost of living index together with rent: - Dubai comes out similar to Bristol or Edinburgh. - Abu Dhabi is closer to Birmingham or Liverpool. Not quite the crazy expensive story people often imagine. If you’re thinking about a move, it’s worth doing your own research and digging into property prices in the areas you’d want to live. josh@durlstonpartners.com hashtag#DPDMCC …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 12, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7385264638650757120/', '𝐈𝐬 𝐃𝐚𝐭𝐚, 𝐂𝐥𝐨𝐮𝐝 𝐭𝐞𝐜𝐡𝐧𝐨𝐥𝐨𝐠𝐢𝐞𝐬, 𝐇𝐞𝐥𝐩𝐢𝐧𝐠 𝐭𝐡𝐞 𝐩𝐥𝐚𝐧𝐞𝐭 𝐚𝐧𝐝 𝐇𝐲𝐛𝐫𝐢𝐝 𝐰𝐨𝐫𝐤𝐢𝐧𝐠 𝐚𝐩𝐩𝐞𝐚𝐥𝐢𝐧𝐠 𝐭𝐨 𝐲𝐨𝐮? - 𝐃𝐚𝐭𝐚 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - £𝟔𝟎𝐤 + 𝐁𝐨𝐧𝐮𝐬 - 𝐋𝐃𝐍 We are working with a highly innovative and trusted ESG partner for top tier investors, providing a one-stop-shop for their sustainability requirements at portfolio level. They aim to achieve consistent financial returns while improving people''s lives and protecting the planet. Their rapid growth in the past 12 months is attributed to their investment in talent at all levels. They plan to become the key player in the European ESG data and ratings industry, while maintaining full operational independence and benefitting from strong distribution synergies offered by their partnership with a leading B2B WealthTech platform. They are hiring into their data focused engineering function to build a completely greenfield system using a very modern technology stack. 𝐓𝐞𝐜𝐡 - Python, AWS + More 𝑹𝒆𝒒𝒖𝒊𝒓𝒆𝒎𝒆𝒏𝒕𝒔: 🌍1 - 4 years professional experience as a Software Engineer 🌍Stem Degree 🌍Passion for working with data and interest in sustainability 🌍Strong Python, SQL, Cloud Experience (AWS) If you or anyone you know could be interested. Please reach out to have a private conversation. ✉ Louis@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7384906056663015424/', 'I''m not looking for a standard trader... I''m looking for a algorithmic problem solver. Someone who is comfortable wearing many hats and wants to explore the boundaries of the on-chain design space. ➟ Build and maintain systems that drive on-chain searching. ➟ Design and implement trading strategies. ➟ Contribute across codebases in Python, Rust, or Go. ➟ Understand blockchain fundamentals. ➟ Recent graduate with up to 2 years’ experience ➟ Degree in CompSci, Maths, or Physics from a top 100 university But a resume only tells half the story. Real expertise is shown, not just listed. Think you''re the right fit? Try this: "If ETH trades at a 1% premium on one exchange and a 1% discount on another, what factors would you consider before arbitraging?" If you know the answer, don''t comment below. DM it to me. daniel@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 1, 0, 'image', 0, NULL);
