INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7383867946210656256/', '✨ We’re super excited for our next Women at the Table event — this time in partnership with the brilliant team at BlueCove. Our first speaker will be Rhea Potdar 👇 Rhea is Head of Systems Engineering at BlueCove where she leads a team of Engineers focussed on deliveries to scale the firm across various business lines and building the systems through which BlueCove’s firmwide investment process runs. Prior to joining the firm in 2019, Rhea worked as a Software Engineer at Goldman Sachs from 2013 - 2019 in Controllers Technology and Investment Banking Technology, latterly as Vice President of Debt Capital Markets Technology. Rhea received her Masters of Engineering in Computer Science from Imperial College London in 2013. Can’t wait to hear from her! This evening will be a fantastic opportunity to reconnect with others in the space, meet new faces, and hear directly from some of the talented women in BlueCove’s Engineering and Quant Research teams as they share their technical insights and career journeys. 💡 About BlueCove: Founded in 2018, BlueCove is a scientific asset management firm bringing together leading investment and engineering professionals to research, develop and deploy state-of-the-art scientific investment processes in fixed income management. 📅 Date & Time: Tuesday 11th November, from 6pm 📍 Location: Mayfair, London We have a few spots left - email events@durlstonpartners.com ASAP to register your interest. …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7383815101096566784/', '🚀 Junior Python Data Developer Our client is a leading ESG Partner for top-tier financial institutions on sustainability initiatives. What they offer: 🏢 Hybrid working (2 days in London office) 📈 Genuine ownership & diverse projects 🌱 Meaningful work driving ESG impact What you need: • 1+ years Python experience (strong Pandas) • Solid SQL & AWS/cloud skills • CS/Maths degree • Thrives in small team environments This isn''t your typical corporate role - you''ll get exposure to end-to-end technical functions, while working on projects that actually matter. Interested or know someone who might be? Drop me a DM! ab@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 11, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7383452714652966912/', 'C++ Engineers (*LDN / HK) - Algo Trading exp not a must-have I''m working with a company which is building a "first of its kind" product for crypto trading. This product is aimed squarely at institutions, offering them unrivalled access to liquidity through a platform that looks, feels and performs as if it''s TradFi. This team runs the end-to-end design and implementation of an ULL trading core, which is written (multithreaded) in the latest version of C++. They tune this very core for microsecond response times and deploy it globally. You do not need to have worked in finance before, however you can expect the interview process to cover very low-level programming concepts. What you''ll be able to work on? - Venue connectivity (various protocols) - Kernel bypass networking (DPDK, RDMA) - Lock-free/lockless data structures - Hardware accelerated code If you want to see the business impact of what your code actually does, you''ll be at the heart of the action, side-by-side with quants and infra engineers and occasionally interacting with external users of this platform as well. The Founder of this venture is focused on profitability, not becoming rich through funding rounds. He treats equity like gold-dust, so you can rest assured that your portion is not diluted in future funding rounds. One billionaire investor took the whole seed round. 1️⃣ Flat structure. 2️⃣ Novel problems to solve. 3️⃣ Opportunity to become an equity partner. 📩 warwick@durlstonpartners.com 📲 TG @cryptowarwick *candidates for London must be based in the UK; 4 days in office *candidates for HK must be HK residents / not require sponsorship …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7383090310056194048/', 'The quickest way to move from theory to high-frequency trading. We''re looking for aspiring algo traders (grads to 2 years industry experienced) with strong Python skills to join a top market maker in London. This is your chance to dive into HFT, liquidity provision, and trading. Forget corporate bureaucracy and legacy systems. You''ll get to own your own desk, develop your own trading algorithms, and learn at an unprecedented speed with guidance from the founders themselves. This isn''t just about writing code; it''s about making a real impact and seeing your strategies come to life. They want you to act like an owner, and your incentives (including equity!) will be completely aligned with the company. Ready to make an impact? Drop me a message or comment below to find out more! daniel@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 11, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7382727923813941248/', '𝐖𝐡𝐚𝐭 𝐢𝐟 𝐀𝐈 𝐜𝐨𝐮𝐥𝐝 𝐬𝐜𝐚𝐥𝐞 𝐰𝐢𝐭𝐡𝐨𝐮𝐭 𝐍𝐕𝐈𝐃𝐈𝐀? We’ve partnered with a well-funded start-up that is challenging the AI industry’s reliance on traditional hardware suppliers by building distributed systems to train large-scale models at a fraction of the cost. The team is building a cutting-edge software platform using Python and requires strong coders with expert-level problem-solving ability. Comp is fixed at $240k base + Equity Ideally looking for people with 1-4 years of experience. For more information, please get in touch! james@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
