INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7382006954132541440/', 'I get asked a lot about the cost of living in Abu Dhabi and Dubai. Understandably, if you’re considering a move to the UAE, one of the first questions is ‘what’s it going to cost me and my family?’ And once you’re here, you’re thinking ‘can I cover rent, schooling, bills, groceries, and still have money left over to enjoy life and save?’ You want to live a better life than where you moved from. When comparing cities, it’s important not to look at cost of living in isolation. You have to combine it with the rent index to see the full picture. Take Abu Dhabi for example. Day-to-day life such as transport, groceries, childcare and eating out is significantly cheaper than London. But rent changes the equation. When you look at the global cost of living index together with rent: - Dubai comes out similar to Bristol or Edinburgh. - Abu Dhabi is closer to Birmingham or Liverpool. Not quite the crazy expensive story people often imagine. If you’re thinking about a move, it’s worth doing your own research and digging into property prices in the areas you’d want to live. josh@durlstonpartners.com hashtag#DPDMCC …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7381999427927879680/', 'I''m working with a high-frequency trading startup which is launching its first international office in Hong Kong. This company needs to hire 2 C++ Engineers in HK, who care deeply about building low-latency, mission critical systems. Whilst prior experience of finance is not required, you will be expected to demonstrate a strong understanding of how to shave off micros from latency and maintain maximum uptime (in a cloud based environment). The great news? This isn''t going to be the same list of well-known HFTs who you may constantly be contacted about. These really are ground zero hires for the company. This means two important things however: 1️⃣ You don''t need sponsorship in HK 2️⃣ You''re comfortable working remotely on an initial basis 📩 warwick@durlstonpartners.com 📲 TG @cryptowarwick …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 1, 0, 'image', 0, NULL);
