INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7380912216075554816/', '𝐀𝐈 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - 𝐅𝐢𝐱𝐞𝐝 𝐈𝐧𝐜𝐨𝐦𝐞 𝐇𝐞𝐝𝐠𝐞 𝐅𝐮𝐧𝐝 - 𝐋𝐨𝐧𝐝𝐨𝐧 - 𝐔𝐩 𝐭𝐨 £𝟏𝟑𝟎𝐤 + 𝐁𝐨𝐧𝐮𝐬 Short feedback loops, technical freedom and combining proprietary AI systems with the latest in off-the-shelf products - if this is something that would interest you, I have the role for you. The firm, a leading Fixed Income Hedge Fund, has recently built an impressive AI team tasked with building end-to-end solutions, predominantly for the Research and Investment side of the business. High-impact projects, leveraging custom products built internally as well as the latest products offered by the large AI firms. 𝐑𝐞𝐪𝐮𝐢𝐫𝐞𝐦𝐞𝐧𝐭𝐬: ✅4-7 years as an AI engineer or building AI systems, ideally from the ground up. ✅Excellent GenAI experience, and architecture knowledge ✅Previous experience building RAGs and Agentic workflows ✅Strong Python, SQL, Fast API and LangChain skills. ✅Ideally, some business analysis exposure. 𝐖𝐡𝐚𝐭 𝐝𝐨 𝐭𝐡𝐞𝐲 𝐨𝐟𝐟𝐞𝐫? 💰Up to £125k Base + Bonus, + Excellent benefits. 🏡2 days WFH ⚙️Working in a team that has complete technical freedom and significant resources. 📈Have responsibility for building products that will directly impact the success of the business and be adopted globally. For more information, please get in touch at james@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7380549828390309889/', 'For the Linux expert who thrives in low-latency environments A proprietary trading firm in London seeing explosive growth (over 30% in the last 6 months!). They''re seeking an elite Senior Systems Engineer to make a real impact on their high-performance, low-latency systems. This is for you if: ➟ You''re a Linux expert with cloud experience. ➟ You have a background in trading or low-latency environments. ➟ You''re comfortable mentoring and engaging with senior stakeholders. The role offers a competitive base salary (£100-150k) plus a significant performance-based bonus. This is a chance to drive innovation where technology is the business. Think you''re the right fit? Send me a DM with your CV. daniel@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 3, 1, 0, 'image', 0, NULL);
