INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7379821288598552576/', 'The 5 BIGGEST trends to look out for in the trading industry The market for elite software engineers in trading is hotter than ever but I''m seeing incredible roles at top-tier firms sit still. Here are 5 trends I''m seeing right now from my desk: 𝟭. 𝗥𝘂𝘀𝘁 𝗶𝘀 𝘁𝗵𝗲 𝗡𝗲𝘄 𝗙𝗿𝗼𝗻𝘁𝗶𝗲𝗿 → It’s consistently ranked the 𝗺𝗼𝘀𝘁 𝗹𝗼𝘃𝗲𝗱 language by developers. → Tech-driven hedge funds and HFT firms are calling it "the new C++ in finance," using it to build entirely new greenfield trading platforms. → The talent shortage is so severe that some firms are hiring engineers with 𝗻𝗼 𝗽𝗿𝗶𝗼𝗿 𝗥𝘂𝘀𝘁 𝗲𝘅𝗽𝗲𝗿𝗶𝗲𝗻𝗰𝗲 - just a strong C++ background and a desire to learn. 𝟮. 𝗖++ 𝗥𝗲𝗺𝗮𝗶𝗻𝘀 𝗞𝗶𝗻𝗴 (𝗙𝗼𝗿 𝗡𝗼𝘄) → Let''s be clear: C++ is still the backbone, creating a "never ending conveyor belt" of roles across finance. → But while the 𝘲𝘶𝘢𝘯𝘵𝘪𝘵𝘺 of jobs is in C++, the most cutting-edge, high-impact opportunities are increasingly leaning towards Rust. 𝟯. 𝗧𝗵𝗲 ‘𝗜𝗱𝗲𝗮𝗹’ 𝗣𝗿𝗼𝗳𝗶𝗹𝗲 𝗪𝗲''𝗿𝗲 𝗟𝗼𝗼𝗸𝗶𝗻𝗴 𝗙𝗼𝗿 → 𝟮+ 𝘆𝗲𝗮𝗿𝘀 of experience at a leading hedge fund or proprietary trading firm. → You’ve worked hands-on with 𝗖++, 𝗣𝘆𝘁𝗵𝗼𝗻, 𝗼𝗿 𝗥𝘂𝘀𝘁 to build and support live trading systems. → You’ve made a key impact, whether it''s through significant optimisation work or building systems from the ground up. → You’re a graduate from a highly-rated university (Top 100). 𝟰. 𝗧𝗵𝗲 ‘𝗔𝗹𝘁𝗲𝗿𝗻𝗮𝘁𝗶𝘃𝗲’ 𝗛𝗶𝗴𝗵-𝗣𝗼𝘁𝗲𝗻𝘁𝗶𝗮𝗹 𝗣𝗿𝗼𝗳𝗶𝗹𝗲 → You’re not in finance. You’re at a 𝗕𝗶𝗴 𝗧𝗲𝗰𝗵 firm working on complex problems. → You have deep experience with 𝗹𝗼𝘄-𝗹𝗮𝘁𝗲𝗻𝗰𝘆 𝗼𝗽𝘁𝗶𝗺𝗶𝘀𝗮𝘁𝗶𝗼𝗻 and large-scale distributed systems. → Your core systems knowledge in C++ or a similar language is world-class. 𝟱. 𝗔𝘁𝘁𝗶𝘁𝘂𝗱𝗲 𝗶𝘀 𝗬𝗼𝘂𝗿 𝗚𝗿𝗲𝗮𝘁𝗲𝘀𝘁 𝗔𝘀𝘀𝗲𝘁 → The best firms are betting on raw talent over specific experience. → They want engineers who are eager to solve hard problems and learn fast. → A willingness to bridge the gap from C++ to Rust can put you ahead of everyone else. And what’s the bottom line? ↳ The gap between demand and supply for this specific talent is huge. ↳ This isn’t just about filling a role; it''s about building the core infrastructure that will define the future of global trading and crypto. The opportunity is massive for those who fit the mould. If this sounds like you, my DMs are open. …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 5, 1, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7379458894450040832/', '🖥️ Technical Partnership Managers (Algo Trading Devs/Support considered) 💲 Base salaries: $220k & $250k 💸 Bonuses: 100-200% 📍 APAC & UAE I''ve had some interesting back and forth with these two clients on trying to define the job title for two very similar roles. So rather than focusing on the title itself, let''s focus on what the role entails. The reporting line for these positions, will be into the business, however you''ll be seen as the critical link between the firm''s trading systems and external crypto exchanges. This role could therefore suit somebody who was previously a technologist! Ideally, you''d be someone that gets just as excited by API documentation and latency optimisation, as you are about negotiating fees. What you''ll be doing: - Handling technical integrations with CEXs - Securing optimal fees, access and colo packages (where relevant) - Working closely with dev teams to improve trading system performance to avoid bottlenecks (incl. troubleshooting) - Handle exchange specific nuances and product launches For more information, please contact me via the info below: 📲 TG @cryptowarwick 📩 warwick@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7379164437615775745/', 'Another great Run Club last night – the sun (and temperature) gods were definitely on our side! 🌞 Always such a good way to catch up with market peers while getting some exercise in and making the most of these lighter evenings before autumn / winter properly kick in! If you’d like to join the next one, you can sign up to our community here: https://luma.com/pzqn2im0 hashtag#RunClub hashtag#FinanceAndTech hashtag#Community hashtag#NetworkingButFun hashtag#TeamDP …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7379096496539090944/', '🚀 Software Engineer - Ultra-Low Latency Systems 📍London Building systems where microseconds matter? We''re recruiting for a cutting-edge HFT firm seeking engineers to work on high-performance execution systems. You''ll need: ➡️5+ years software development experience ➡️Strong C++ skills ➡️Passion for performance optimisation ➡️Experience with low-latency or real-time systems What''s exciting: ✅ Work on some of the world''s fastest trading systems ✅ Collaborate with brilliant quant researchers ✅ Solve complex technical challenges at extreme scale ✅ Excellent compensation package Interested? DM me for details 👇 ab@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7378790836014096384/', 'Women at the Table is back, and this time we’re teaming up with BlueCove! Join us for an evening of great conversation, fresh connections, and real technical and career insights from women at the forefront of quant research and engineering. BlueCove is a scientific asset management firm founded in 2018. BlueCove brings together leading investment and engineering professionals to research, develop and deploy state-of-the-art scientific investment processes applicable to fixed income management. You can find out more about BlueCove on their website: https://www.bluecove.com/. We’re thrilled to be partnering with them for this one. Spaces are limited – email events@durlstonpartners.com to register your interest. …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7378734107368792064/', '** 𝐄𝐱𝐜𝐥𝐮𝐬𝐢𝐯𝐞 𝐌𝐚𝐧𝐝𝐚𝐭𝐞 ** 𝟐𝐱 𝐏𝐲𝐭𝐡𝐨𝐧/𝐂# 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫𝐬 - 𝐁𝐨𝐮𝐭𝐢𝐪𝐮𝐞 𝐅𝐮𝐧𝐝 - 𝐔𝐩 𝐭𝐨 £𝟐𝟎𝟎𝐤 𝐓𝐂 - 𝐋𝐨𝐧𝐝𝐨𝐧 One of London''s best performing Hedge Funds, is looking to add two Engineers to their Middle Office/Core Team. Must haves: ✅Excellent Python skills ✅Basic C# knowledge (can work with request/response queries) ✅CompSci background (must have excellent core Software Engineering skills) ✅Good attitude to code testing/reviews, especially for deploying critical code For more information, please get in touch at james@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7378698229468782592/', '☀️ Bright sunshine all day and set for a beautiful evening for our Run Club tonight! We’ll be meeting at 6pm at DP London HQ for a bag drop and heading out around 6:15pm (if you’re running a little late, don’t worry - we’ll share a number so you can catch us on the route). It’s a scenic Royal Parks loop followed by a well-deserved pint (or non-alc bev) at one of our locals. 🍻 If you’re in the area with your gym kit and fancy making the most of the September sun, come and join us! Drop me a message or grab one of the final spots here: https://luma.com/pzqn2im0 …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 0, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7378389935462043649/', '18 degrees and sunny for our second market 5k TOMORROW! The countdown is on and there are still a few spots left! 𝗪𝗵𝗲𝗻: We meet tomorrow, Tuesday 30th September, at 6pm sharp. 𝗥𝗼𝘂𝘁𝗲: A scenic loop around St James’s & Green Park. 𝗣𝗮𝗰𝗲: Super relaxed and chatty. Everyone is welcome, no matter your speed. 𝗧𝗵𝗲 𝗕𝗲𝘀𝘁 𝗣𝗮𝗿𝘁: We''ll refuel with a pint at a nearby pub afterwards! Hope you can join. The buzz after our first event was amazing, and I can''t wait to hit the pavement again. Sign-up here for the final spots: https://luma.com/pzqn2im0 hashtag#runclub hashtag#networking hashtag#finance hashtag#tech hashtag#hedgefund hashtag#trading …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7378371733638135808/', 'Stop maintaining old systems. It doesn''t build your career... Too many engineers are stuck maintaining ancient systems, their impact diluted by layers of bureaucracy. They''re updating systems that were cutting-edge a decade ago. A new hedge fund is on the rise, tech-first, agile, and engineered for impact. I''m exclusively representing a firm founded by some of the sharpest minds in the industry, now looking for a Python Developer with C# experience in London to build the core of their new platform. This is a opportunity to: → Impact mission-critical systems. → Work with top traders and quants. → Use a modern stack (Python, C#, cloud) without the red tape. They need a developer with 3-6 years of experience who wants to make their mark, not just do a job. If you''re ready to build the lighthouse, send me a confidential DM or apply in the comments. Know someone perfect for this? Tag them below. daniel@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7378035792402874368/', '𝐅𝐫𝐨𝐧𝐭-𝐄𝐧𝐝 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 – 𝐑𝐞𝐚𝐥-𝐓𝐢𝐦𝐞 𝐓𝐫𝐚𝐝𝐢𝐧𝐠 𝐒𝐲𝐬𝐭𝐞𝐦𝐬 - 𝐋𝐨𝐧𝐝𝐨𝐧 - 𝐔𝐩 𝐭𝐨 £𝟏𝟎𝟎𝐤 + 𝐁𝐨𝐧𝐮𝐬 Our client, a boutique prop trading firm specialising in ML is looking for Front-End Engineer to design and build rich, intuitive, high-performance UIs for a proprietary trading environment. You will work on: • Tick-by-tick market visualisation tools to see strategies in action in real time • Real-time monitoring and management dashboards for trading strategies and systems • Tools for risk, PnL, backtesting and regulatory reporting • High-performance interfaces that bring trading, strategy and infrastructure data together seamlessly You will collaborate directly with traders, quants and engineers, gaining full codebase access in a small, high-calibre team where your work will be deployed into production quickly. Tech stack and skills: • React (essential) and TypeScript • Strong CS fundamentals, design patterns, algorithms, performance tuning • Experience with automated testing and UI best practices • Bonus: trading platform, real-time systems, Java/Python or market knowledge If you are passionate about creating exceptional UIs for high-performance systems and want to see your work have an immediate impact, get in touch. 📩 Message me directly at james@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 5, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7377646938516635649/', '𝐘𝐨𝐮𝐫 𝐜𝐨𝐝𝐞 𝐜𝐨𝐮𝐥𝐝 𝐬𝐡𝐚𝐩𝐞 𝐛𝐢𝐥𝐥𝐢𝐨𝐧𝐬 𝐢𝐧 𝐝𝐚𝐢𝐥𝐲 𝐭𝐫𝐚𝐝𝐢𝐧𝐠 – 𝐑𝐞𝐦𝐨𝐭𝐞 (𝐔𝐊 𝐨𝐫 𝐄𝐮𝐫𝐨𝐩𝐞) – £𝟐𝟓𝟎𝐊+ 𝐓𝐂 We’re hiring a Senior Data Engineer to build and optimise petabyte-scale pipelines for a leading global algo trading firm in the digital asset space. 𝐓𝐡𝐞𝐲’𝐫𝐞 𝐥𝐨𝐨𝐤𝐢𝐧𝐠 𝐟𝐨𝐫 𝐚 𝐝𝐚𝐭𝐚 𝐩𝐨𝐰𝐞𝐫𝐡𝐨𝐮𝐬𝐞 𝐭𝐨: 🔹 Build and optimise high-throughput, real-time pipelines 🔹 Create analytics tools and research infrastructure 🔹 Collaborate with an elite trading team in a 24/7 market 𝐘𝐨𝐮’𝐥𝐥 𝐧𝐞𝐞𝐝: ✔ Python + AWS ✔ Large-scale, real-time data pipeline experience ✔ Strong background in time-series data analysis 💡 𝐅𝐥𝐚𝐭 𝐜𝐮𝐥𝐭𝐮𝐫𝐞. 𝐅𝐮𝐥𝐥 𝐚𝐮𝐭𝐨𝐧𝐨𝐦𝐲. 𝐆𝐥𝐨𝐛𝐚𝐥 𝐢𝐦𝐩𝐚𝐜𝐭. 📩 Message me to learn more about this exclusive opportunity. louis@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7377646942102913024/', 'Tired of stuffy networking events? Come join the first-ever Durlston Partners Run Club and experience the benefits of running together: - 𝗖𝗼𝗺𝗺𝘂𝗻𝗶𝘁𝘆 & 𝗖𝗼𝗻𝗻𝗲𝗰𝘁𝗶𝗼𝗻: Network with like-minded people in finance and tech in a relaxed, no-pressure setting. The post-run pint at The Devonshire is a great bonus! - 𝗠𝗼𝘁𝗶𝘃𝗮𝘁𝗶𝗼𝗻 & 𝗦𝗰𝗲𝗻𝗲𝗿𝘆: Stay accountable with a group and enjoy a scenic run with a Buckingham Palace cameo, a nice change from your usual route. - 𝗔𝗹𝗹 𝗟𝗲𝘃𝗲𝗹𝘀 𝗪𝗲𝗹𝗰𝗼𝗺𝗲: We''ll be going at a talking pace, so it''s perfect for everyone, whether you''re a seasoned runner or just starting out. Our next on is in London on Tuesday - drop me a message if you can make it. daniel@durlstonpartners.com …more', '6mo • 6 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7377284565138161664/', '𝐈𝐭’𝐬 𝐟𝐫𝐨𝐧𝐭-𝐞𝐧𝐝… 𝐛𝐮𝐭 𝐰𝐢𝐭𝐡 𝐭𝐢𝐜𝐤-𝐛𝐲-𝐭𝐢𝐜𝐤 𝐝𝐚𝐭𝐚 𝐟𝐥𝐲𝐢𝐧𝐠 𝐚𝐭 𝐲𝐨𝐮 𝐢𝐧 𝐫𝐞𝐚𝐥 𝐭𝐢𝐦𝐞. 𝐒𝐭𝐢𝐥𝐥 𝐢𝐧𝐭𝐞𝐫𝐞𝐬𝐭𝐞𝐝? You’ll work on tick-by-tick market visualisations, real-time dashboards, and high-performance trading tools, where milliseconds matter. 𝐈’𝐦 𝐥𝐨𝐨𝐤𝐢𝐧𝐠 𝐟𝐨𝐫 𝐬𝐨𝐦𝐞𝐨𝐧𝐞 𝐰𝐡𝐨: ⚡ Has strong CS fundamentals (algorithms & data structures) ⚡ Can work in React/TypeScript but loves tackling performance challenges ⚡ Maybe even dabbles in C++ or other low-level languages for fun ⚡ Thrives in real-time, high-performance environments (gaming, graphics, etc.) If that sounds like you (or someone you know), drop me a message and I’ll share the details. London | Competitive package louis@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7376971473908887553/', 'H-1B changes - why the UAE is the obvious choice Recent H-1B changes have left many either unsure about their future move to the US, or unsure of their future under their current visa. They''re now thinking that life could be easier, with better long-term economic and political stability elsewhere, without fear of major disruptions to what originally was many people''s dream move. Opportunity for a thriving career is blooming in the UAE, and we are finding many people from Asia and Europe moving to the region for: - Top roles, with expanding firms - Tax efficiency - Simple and clear visa requirements - Quality of life - Proximity to Europe and Asia Reach out if you need more info rahn@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7376918478802550784/', '𝐂𝐮𝐬𝐭𝐨𝐦 𝐋𝐋𝐌 𝐚𝐫𝐜𝐡𝐢𝐭𝐞𝐜𝐭𝐮𝐫𝐞/𝐚𝐥𝐠𝐨 𝐨𝐩𝐭𝐢𝐦𝐢𝐬𝐚𝐭𝐢𝐨𝐧 > 𝐀𝐏𝐈 𝐰𝐫𝐚𝐩𝐩𝐢𝐧𝐠 We’re looking for a Senior AI Scientist to join a small, elite algo-focused team working on: • Agentic systems • Multimodal AI • LLMs from 0-1 optimised for real-world impact, not just API integration This is a research-driven culture for people who roll up their sleeves, think differently, and learn constantly, fully backed by multi-billion-dollar capital, zero bureaucracy, and the resources to take ideas from concept to deployment. Hybrid in Abu Dhabi/Dubai/Top-of-market tax-free comp/Quick relocation, 4 streamlined interview stages 𝐖𝐞’𝐫𝐞 𝐢𝐧𝐭𝐞𝐫𝐞𝐬𝐭𝐞𝐝 𝐢𝐧 𝐩𝐫𝐨𝐟𝐢𝐥𝐞𝐬 𝐰𝐢𝐭𝐡: • 5+ years in developing, fine-tuning & deploying LLMs • End-to-end algorithmic problem-solving • RAG/agent system expertise • Deep understanding of NLMs & MLMs • RL/PPO experience For more information please get in touch: james@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7376544695575023616/', 'Every recruiter is talking about the H-1B visa changes. Let''s cut the noise. I''ve taken some time to gather information and understand how this could affect people. Here are the brutal truths about the new H-1B rules and what they mean for my network: 1. 𝗧𝗵𝗲 $𝟭𝟬𝟬,𝟬𝟬𝟬 𝗳𝗲𝗲 𝗶𝘀 𝗿𝗲𝗮𝗹. But it''s not for everyone. It''s a one time fee for 𝘯𝘦𝘸 H-1B visa applications. 2. 𝗜𝘁 𝗼𝗻𝗹𝘆 𝗵𝗶𝘁𝘀 𝗻𝗲𝘄 𝗮𝗽𝗽𝗹𝗶𝗰𝗮𝗻𝘁𝘀. The fee applies to petitions filed on or after September 21, 2025, for individuals residing outside the United States. 3. 𝗖𝘂𝗿𝗿𝗲𝗻𝘁 𝘃𝗶𝘀𝗮 𝗵𝗼𝗹𝗱𝗲𝗿𝘀 𝗮𝗿𝗲 𝘀𝗮𝗳𝗲. If you have a valid H-1B, you aren''t affected. You can still travel, and the fee doesn''t apply to renewals or extensions. 4. 𝗧𝗵𝗶𝘀 𝗰𝗼𝘂𝗹𝗱 𝗸𝗶𝗹𝗹 𝘁𝗵𝗲 𝘃𝗶𝘀𝗮 𝗹𝗼𝘁𝘁𝗲𝗿𝘆. Last year, over 470,000 people applied for 85,000 spots. This fee will force companies to be extremely selective. The focus will shift to only the most critical, high-value hires. 5. 𝗧𝗵𝗲𝗿𝗲''𝘀 𝘀𝘁𝗶𝗹𝗹 𝗮 𝗴𝗿𝗲𝘆 𝗮𝗿𝗲𝗮. Immigration lawyers have flagged open questions, especially for those changing employers or traveling after filing for an extension. Official guidance on this is still unclear. 6. 𝗬𝗼𝘂𝗿 𝗰𝗮𝗿𝗲𝗲𝗿 𝘀𝘁𝗿𝗮𝘁𝗲𝗴𝘆 𝗻𝗲𝗲𝗱𝘀 𝘁𝗼 𝗮𝗱𝗮𝗽𝘁. With the US raising the barrier, where should you look? - 𝗟𝗼𝗻𝗱𝗼𝗻: The market is hot. A hiring surge in the financial sector means competitive salaries and more opportunities. - 𝗗𝘂𝗯𝗮𝗶: The big draw is zero income tax. It''s a booming, safe city where you can take on more responsibility earlier in your career. However, be aware the market is competitive, and it can be tough to land a role from overseas. How does this news affect your career plans? Tell me your thoughts in the comments ⬇️ ♻️ Repost to help your network understand what''s really happening. daniel@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 4, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7376261586371493888/', 'We’re growing our Dubai team! 🌴 This is a brilliant opportunity to work closely with Rahnpreet Sandhu, who has been instrumental in building a strong book of business across Dubai and Abu Dhabi. You’ll step into an environment where mentorship and knowledge-sharing are front and centre. The focus? Placing some of the brightest minds in the space – Quant Researchers, Analysts, Research Associates, AI/Data Scientists, Deep Learning Quants, Research Scientists, and Portfolio Managers – into some of the most sophisticated institutions in the region, from systematic hedge funds to family offices and high-frequency trading firms. We’re looking for someone ambitious, curious, and keen to learn. You’ll have the space, support, and time to properly get to grips with the market, develop your skills, and grow into an independent, high-performing recruiter. Here’s what the first three years could look like with us: Year 1: Build your network across the UAE and London while learning how the pieces fit together in a systematic trading business, and make your first placements. Year 2: Take ownership – work on the opportunities that excite you most, leveraging the strong foundation you’ve built. Year 3: Be in a position where your earnings could comfortably cover a deposit on a property. If this sounds like you (or someone in your network), email shannon@durlstonpartners.com for a confidential chat. …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 11, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7376257807697727488/', 'Our first run club was a massive success, so we''re doing it again on September 30th! This is a space for professionals in FinTech, Hedge Funds, Quant, and AI to connect beyond the desk in a refreshing way. All fitness levels are welcome; it''s about connection, not competition. The energy at the last event was incredible, and we''re buzzing for the next one. 🚀 Want in? All info for the next run is in the Durlston Partners Run Club group. Join via the link in the comments. Lace up and we''ll see you there. 🏃‍♂️🏃‍♀️ daniel@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 2, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7375842555676213248/', '𝐌𝐋 𝐐𝐮𝐚𝐧𝐭 𝐑𝐞𝐬𝐞𝐚𝐫𝐜𝐡𝐞𝐫 (𝟏-𝟑 𝐲𝐞𝐚𝐫𝐬 𝐞𝐱𝐩) - 𝐏𝐫𝐨𝐩 𝐓𝐫𝐚𝐝𝐢𝐧𝐠 𝐟𝐢𝐫𝐦 - 𝐋𝐨𝐧𝐝𝐨𝐧 - 𝐔𝐩 𝐭𝐨 £𝟑𝟎𝟎𝐤 𝐓𝐂 Are you a mathematically gifted Python whiz with a passion for trading and ML? A top prop trading firm is seeking a Junior Quantitative Researcher for a top-performing Quant team. You''ll work on cutting-edge strategies, own projects from day one, in a highly entrepreneurial culture. 𝐖𝐡𝐚𝐭 𝐲𝐨𝐮''𝐥𝐥 𝐧𝐞𝐞𝐝: ⚙️Strong stats/ML background (MSc/PhD preferred) ⚙️Advanced Python skills ⚙️Experience designing signals for market making or HFT/MFT ⚙️From a top-tier uni (Yandex SDA, NES, HSE, OxBridge, grandes écoles) ⚙️Ready to relocate to London, if not already here (Can sponsor) 𝐎𝐟𝐟𝐞𝐫: Up to £150k base + Excellent Bonus Big responsibility and learning curve Hybrid work, top-tier office & perks For more information, please get in touch at james@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 5, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7375480165109481472/', 'In prop trading, data is everything. Every trade and every microsecond of advantage relies on perfect, real-time data. That’s why I''m excited to be working with a leading prop trading firm to find a Senior Data Engineer who is ready for true ownership. This is a career-defining move: ✅ Full Ownership: Design and build mission-critical trading and market data infrastructure. ✅ High-Impact: Work on low-latency distributed data pipelines in a high-autonomy, fast-paced culture. ✅ Flexibility & Rewards: This is a fully remote role (UK/Europe) with a competitive salary, performance bonus, and team off-sites. We''re looking for someone with strong Python and SQL skills and experience with real-time, high-volume trading data. Experience with Clickhouse, C++, or Terraform is a big plus! Sound like your next challenge? Send me a DM or apply in the comments! daniel@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7375114009261535232/', '𝗪𝗲𝗲𝗸𝗲𝗻𝗱 𝗰𝗮𝗹𝗹 𝘁𝗼 𝗱𝗶𝘀𝗰𝘂𝘀𝘀 𝗮 𝗺𝗼𝘃𝗲 𝘁𝗼 𝘁𝗵𝗲 𝗨𝗔𝗘 - 𝗦𝗮𝘁𝘂𝗿𝗱𝗮𝘆/𝗦𝘂𝗻𝗱𝗮𝘆 𝗛𝗲𝗱𝗴𝗲 𝗙𝘂𝗻𝗱𝘀, 𝗤𝘂𝗮𝗻𝘁 𝗦𝗵𝗼𝗽𝘀, 𝗦𝗼𝘃𝗲𝗿𝗲𝗶𝗴𝗻𝘀, 𝗙𝗮𝗺𝗶𝗹𝘆 𝗢𝗳𝗳𝗶𝗰𝗲𝘀, 𝗣𝗿𝗼𝗽 𝗦𝗵𝗼𝗽𝘀 𝗲𝘁𝗰 If you''re interested in discussing a move to the UAE, but struggle for time during the week, I have put some time aside for the next few Saturdays and Sundays to call and discuss: - What a move looks like logistically? - What opportunities are there for you in the region? - Specifics on life in the UAE - Any other questions or reservations that you have. Happy to share additional relevant materials after our call for your consideration. Please let me know if you are interested and I can provide my availability: rahn@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 2, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7374770492580446208/', 'Remote opportunities are alive and well in the crypto world! C++ Engineers with backgrounds in automated trading are in high demand for roles ranging from exchange connectivity to trading strategy optimisation. Rust Engineers with backgrounds in building high-performance mission-critical systems are being considered without existing crypto experience to build DEXs or building connectivity for DeFi strats to run on DEXs. We''ve even got a remote Data Engineering role (Python/ClickHouse) which is worth mentioning as well! Quite a unique blend of company sizes and trading strategies at the moment; some with as few as 10 employees who LOVE to hire engineers that enjoy wearing multiple hats, others with more distinct descriptions for how they can leverage your unique area of expertise. If you''d like a confidential chat about assessing which options might be available, please let me know and I can shoot you my calendly link! 📩 warwick@durlstonpartners.com 📲 TG @cryptowarwick …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7374359769807073280/', 'The countdown is on! 🚀 Our next run is just around the corner, and the buzz is real after our amazing first event. Get ready to lace up and hit the pavement again on Wednesday, 30th September! Here are the key details: 𝗧𝗶𝗺𝗲: Meet 6pm sharp 𝗠𝗲𝗲𝘁𝗶𝗻𝗴 𝗣𝗼𝗶𝗻𝘁: Durlston Partners office (Bag Drop) 𝗥𝗼𝘂𝘁𝗲: A scenic loop around St James’s & Green Park. 𝗣𝗮𝗰𝗲: A relaxed, chatty pace. Everyone is welcome, no matter your speed. 𝗣𝗼𝘀𝘁-𝗥𝘂𝗻: We''ll refuel with a pint at a nearby pub, hope you can join! Sign-up: https://luma.com/pzqn2im0 I can''t wait to see you all there for another great one! Let''s go! 🏃‍♀️🏃‍♂️ …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL);
