INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7372573511975870464/', 'Snapshot of open roles across Infrastructure in High Frequency Trading, Market Making, Systematic Hedge Funds and Prop Trading globally 📡 Network Engineers London or UAE | 2x roles | Physical + AWS Cloud | £80–130k base + bonus Fully Remote | Routing protocols, cloud services | Up to $180k TC Singapore | Low-latency, RF, hardware | Up to 250k SGD + bonus 🔧 DevOps / SRE UAE | Junior + Senior DevOps Engineers | $150–300k TC Remote in UAE | DevOps Engineer | Up to $120k base + tokens London | Senior DevOps Engineer | AWS, Kubernetes | Up to £140k + bonus Chicago or New York | Site Reliability Engineer | Python, CI/CD | $400k TC 🧱 Platform Engineering London | Platform Engineer | Multicloud, Python/Bash | Up to £120k + bonus 🔍 Interested or know someone great? Drop me a DM - happy to chat! josh@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7372211126949912576/', '𝐌𝐲 𝐭𝐡𝐨𝐮𝐠𝐡𝐭𝐬 𝐨𝐧 𝐭𝐡𝐞 𝐀𝐈 𝐥𝐚𝐧𝐝𝐬𝐜𝐚𝐩𝐞 𝐢𝐧 𝐇𝐞𝐝𝐠𝐞 𝐅𝐮𝐧𝐝𝐬 𝐚𝐧𝐝 𝐓𝐫𝐚𝐝𝐢𝐧𝐠 𝐟𝐢𝐫𝐦𝐬: The conversation around AI in Hedge Funds is evolving fast. While some worry "the ship has sailed", we’re seeing more funds than ever actively building world-class AI teams, from agentic solutions and RAGs to LLM engineering and conversational AI platforms. At the same time, our AI candidate network, including top AI Lab alumni, talents with H-Index 20+, and those who’ve worked under renowned supervisors, is driving innovation across both established funds and ambitious startups. Recent industry data shows that over 85% of hedge funds now leverage GenAI tools, and firms serious about AI are generating up to 3% higher annualized returns. The reality: it’s not too late to make a mark in this space, especially if you’re at the frontier of engineering for agentic trading, advanced NLP, or scaling LLM systems. 𝐈𝐟 𝐲𝐨𝐮''𝐫𝐞 𝐚 𝐟𝐢𝐫𝐦 looking to apply AI internally to enhance decision-making, automation, or market insights, let’s connect. 𝐈𝐟 𝐲𝐨𝐮’𝐫𝐞 𝐚 𝐜𝐚𝐧𝐝𝐢𝐝𝐚𝐭𝐞 developing AI solutions for institutional finance, I''d love to hear from you. james@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7371848769232855040/', '🚀 𝐀𝐫𝐞 𝐲𝐨𝐮 𝐚 𝐋𝐨𝐰-𝐋𝐚𝐭𝐞𝐧𝐜𝐲 𝐂++ 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 𝐢𝐧 𝐇𝐅𝐓 𝐰𝐡𝐨''𝐬 𝐭𝐢𝐫𝐞𝐝 𝐨𝐟 𝐜𝐨𝐦𝐦𝐮𝐭𝐢𝐧𝐠? I''m working with one of the top high-frequency trading firms in the world. They''re hiring C++ engineers at all levels to help build ultra-performant, low-latency systems. The best part? It''s fully remote, globally. 🌍 No relocation. No office. Just elite engineering from wherever you are. 🔧 You''ll work on systems optimised down to the picosecond level - this is true cutting-edge infrastructure. 💰 Compensation is wide open and highly competitive, based on experience and impact. 📩 Reach out for a confidential conversation, or feel free to refer someone great: Louis@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 8, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7371531056837074944/', 'Our first run club was a massive success, so we''re doing it again on September 30th! This is a space for professionals in FinTech, Hedge Funds, Quant, and AI to connect beyond the desk in a refreshing way. All fitness levels are welcome; it''s about connection, not competition. The energy at the last event was incredible, and we''re buzzing for the next one. 🚀 Want in? All info for the next run is in the Durlston Partners Run Club group. Join via the link in the comments. Lace up and we''ll see you there. 🏃‍♂️🏃‍♀️ https://lnkd.in/eE-ymYVC hashtag#durlstonpartners hashtag#runclub hashtag#finance hashtag#technology hashtag#hedgefund hashtag#trading hashtag#london …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7371486370059427840/', 'Not all DevOps roles are created equal; some exist for those who enjoy building infrastructure 𝙖𝙣𝙙 writing code that ships (not stuck in a queue of tickets). Who, I hear you ask? A very early-stage crypto trading firm (remote-first, lean team, scaling rapidly) is hiring a DevOps Engineer to help own and evolve its infrastructure as it grows. You’ll split your time 50/50 between DevOps and hands-on backend development (Rust and Python), running on AWS and eventually K8. You’d be joining a sharp but low-ego team working on delta-neutral DeFi strategies, with the kind of culture where you’re trusted to run with things, but still have people to bounce ideas off at 2 am, if you''re a night owl. Remote is fine. Dubai is better (yes, there’s a hacker house near the beach, no, this isn’t a joke). If you’ve got 2+ years in DevOps, write clean code, and want to help scale something from the ground up, drop me a message. karolis@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7371120214404653057/', '🚨 Hiring: AI Solutions Engineer | London (Hybrid) Join a small, high-impact AI team inside a global asset manager ($1.4tn+ AUM) that''s building real GenAI tools - already 16 in production. You’ll work across research, sales, and operations, using Python, LLMs, RAG, LangChain, and more to solve real business problems. 👩‍💻 60% coding / 20% architecture / 20% business analysis 🧠 GenAI-heavy stack 📍 London Office 👉 No finance experience needed - just strong engineering skills and a practical mindset. DM me or apply directly if interested! ab@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 16, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7370716308138790912/', 'Tired of hearing about boring software engineering roles? I''m working with a top-tier quantitative firm in London that''s looking for a Software Engineer to join their team. This is a opportunity to tackle complex challenges at the intersection of technology and finance. You''ll partner directly with quantitative researchers to build and implement high-performance trading systems that are put to the test in live markets. They''re looking for a professional with: - 4+ yrs of experience in either C++ or Python. - A genuine passion and understanding of financial markets. - A drive to engineer robust, scalable, and mission-critical systems. If you''re ready for a challenging role where you can make a significant impact, I''d like to hear from you. Send me a DM for a confidential chat. daniel@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 8, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7370482232098074625/', 'Due to exceptional client demand, we’re looking for an experienced Quant Recruiter to join the Durlston Partners team. Ideally, you’ll have 2–3+ years’ experience placing into HFTs, prop shops, or other buy-side firms. We want someone who’s hungry, collaborative, and ready to make placements - and be well rewarded for it. We partner with some of the most exciting names in the industry, covering quant, tech, data, AI/ML and digital assets. We work with hedge funds, HFTs, prop shops, fintechs and asset managers globally, with offices in London, New York, and Dubai. Offer genuinely warm desks, deep client relationships, and the platform to set you up for success from day one. You’ll get: market-leading commission with no thresholds, caps, or desk fees, meaningful profit share, cash BD incentives and bonuses, top-tier clients and no internal restrictions on access to them, support to shape your growth, perks like a two-week Christmas break, BUPA cover, £1,200 wellness/phone allowance, regular socials, and global incentives. If this sounds like you or someone you know, drop me a message or email shannon@durlstonpartners.com for a confidential chat. …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 3, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7370104741676236800/', '𝐈𝐬 𝐃𝐚𝐭𝐚, 𝐂𝐥𝐨𝐮𝐝 𝐭𝐞𝐜𝐡𝐧𝐨𝐥𝐨𝐠𝐢𝐞𝐬, 𝐇𝐞𝐥𝐩𝐢𝐧𝐠 𝐭𝐡𝐞 𝐩𝐥𝐚𝐧𝐞𝐭 𝐚𝐧𝐝 𝐇𝐲𝐛𝐫𝐢𝐝 𝐰𝐨𝐫𝐤𝐢𝐧𝐠 𝐚𝐩𝐩𝐞𝐚𝐥𝐢𝐧𝐠 𝐭𝐨 𝐲𝐨𝐮? - 𝐒𝐞𝐧𝐢𝐨𝐫 𝐃𝐚𝐭𝐚 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - £𝟖𝟓𝐤 + 𝐁𝐨𝐧𝐮𝐬 - 𝐋𝐃𝐍 We are working with a highly innovative and trusted ESG partner for top-tier investors, providing a one-stop shop for their sustainability requirements at the portfolio level. They aim to achieve consistent financial returns while improving people''s lives and protecting the planet. Their rapid growth in the past 12 months is attributed to their investment in talent at all levels. They plan to become the key player in the European ESG data and ratings industry, while maintaining full operational independence and benefitting from strong distribution synergies offered by their partnership with a leading B2B WealthTech platform. They are hiring for their data-focused engineering function to build a completely greenfield system using a modern technology stack. 𝐓𝐞𝐜𝐡 - Python, SQL, AWS + More 𝑹𝒆𝒒𝒖𝒊𝒓𝒆𝒎𝒆𝒏𝒕𝒔: 🌍3y+ professional experience as a Software/Data Engineer 🌍 Hands-on experience with Machine learning and Generative AI 🌍 STEM Degree 🌍Passion for working with data and interest in sustainability 🌍Strong Python, SQL, Cloud Experience (AWS) If you or anyone you know could be interested. Please reach out to have a private conversation. ✉ Louis@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7369731104326524928/', '♟ Checkmate. How do you connect with your recruiters? Siva Keefe Savero’s been mixing things up - taking on clients and candidates at chess (and occasionally schooling some of the DP team in the office too). Last week we caught up with a client by racing cars at the F1 Arcade, and we''ve recently hosted our first-ever industry Run Club. So whether you’re into chess, F1, running… or just an old-fashioned drink outside a packed pub in central London, we’re here for it. The weather’s looking hot for the next couple of weeks... if you fancy meeting up, drop us a line. …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7369300769155624961/', '𝐔𝐫𝐠𝐞𝐧𝐭 𝐫𝐨𝐥𝐞 - 𝐒𝐞𝐧𝐢𝐨𝐫 𝐃𝐚𝐭𝐚 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - 𝐒𝐮𝐬𝐭𝐚𝐢𝐧𝐚𝐛𝐢𝐥𝐢𝐭𝐲 𝐈𝐧𝐯𝐞𝐬𝐭𝐦𝐞𝐧𝐭 𝐅𝐢𝐫𝐦 - 𝐔𝐩 𝐭𝐨 £𝟗𝟎𝐤 - 𝐆𝐞𝐧𝐞𝐫𝐨𝐮𝐬 𝐖𝐅𝐇 The firm is hiring a Senior Data Engineer to play a key role in building scalable data systems and deploying real-world GenAI applications, including LLM-powered RAG systems and agentic workflows, in support of impactful ESG insights. ✅ Python, SQL, cloud (AWS preferred) ✅ Experience shipping GenAI or ML models to production ✅ Passion for data-driven sustainability ✅ Hybrid (2 days in-office – London) For more information, please get in touch james@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 6, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7368945864255361025/', '🚨 𝐒𝐢𝐜𝐤 𝐨𝐟 𝐜𝐨𝐫𝐩𝐨𝐫𝐚𝐭𝐞 𝐠𝐫𝐢𝐝𝐥𝐨𝐜𝐤? 𝐉𝐨𝐢𝐧 𝐚 𝐭𝐨𝐩 𝐡𝐞𝐝𝐠𝐞 𝐟𝐮𝐧𝐝 𝐰𝐡𝐞𝐫𝐞 𝐲𝐨𝐮𝐫 𝐜𝐨𝐝𝐞 𝐚𝐜𝐭𝐮𝐚𝐥𝐥𝐲 𝐬𝐡𝐢𝐩𝐬. 𝐈’𝐦 𝐡𝐢𝐫𝐢𝐧𝐠 𝐟𝐨𝐫 𝐚 𝐅𝐮𝐥𝐥 𝐒𝐭𝐚𝐜𝐤 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 𝐭𝐨 𝐡𝐞𝐥𝐩 𝐫𝐞𝐢𝐧𝐯𝐞𝐧𝐭 𝐓𝐫𝐞𝐚𝐬𝐮𝐫𝐲 𝐓𝐞𝐜𝐡 💻💸 𝐈𝐟 𝐲𝐨𝐮: 🧠 Love solving real business problems with Java, React, and SQL 🔍 Enjoy working closely with trading teams to automate and streamline processes ⚡ Want to build systems that power decisions across a multi-asset treasury operation 🌍 Thrive in a fast-paced, collaborative environment with global teammates 👀 And want a rooftop terrace in the heart of the West End to recharge in between... 𝐓𝐡𝐞𝐧 𝐥𝐞𝐭’𝐬 𝐭𝐚𝐥𝐤... You''ll be joining a friendly team of 80+ technologists and working directly with folks who truly value good systems and clean code. Perfect for engineers who like ownership, impact, and getting things done. Shoot me a message if you''re curious, even if you''re just exploring! louis@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 7, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7368583824059813888/', 'We had the amazing Paris Norriss in the office last week for a talk on grit and resilience – and the team were hooked. In 2025, Paris broke records by running seven marathons across seven continents in just 5 days and 21 hours – despite having only ever run one marathon before. This came not long after he rowed 4,800km across the Pacific Ocean in 2023, raising £150,000 for marine conservation. Through The Grit Code, Paris turns these extreme challenges into practical lessons on thriving under pressure, pushing limits, and staying resilient – themes that couldn’t be more relevant to the work we do at Durlston Partners. It was inspiring, motivating, and a great reminder that grit and determination are the foundation for success in every area of life. If your team could use a dose of perspective and motivation, I’d highly recommend reaching out to Paris. hashtag#Resilience hashtag#Motivation hashtag#GritCode hashtag#TeamDP hashtag#Inspiration …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 14, 2, 18, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7368583500477775873/', 'Tired of just maintaining systems? I’m not just looking for a DevOps engineer. And I''m not just looking for a Rust or Python developer. I’m looking for a builder. Someone who sees infrastructure and code as two sides of the same coin. I''m working with an early-stage stealth crypto trading firm focused on market-neutral strategies. This is for someone who wants to build systems, not just maintain them. This might be for you if: - You want a true 50/50 DevOps/Development hybrid role. - You have a strong background in AWS and ownership. - You have development skills in Rust or Python. - You''re familiar with Kubernetes. - Top academics/industry experience This is a full-time, remote (or Dubai-based) role and requires 2-3 years of experience. Crypto experience commercially or projects is a must. If you’re the builder I’m looking for, send me a DM. daniel@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 1, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7368239047124611073/', 'Happy Labor Day to our colleagues and friends in the U.S. 🇺🇸 A well-deserved long weekend to recognise all the hard work that goes in day after day. If you’re in the U.S. and spending your Labor Day thinking about your next move, our team would love to help. We’re busy with live roles across the U.S. (and globally if you fancy a relocation). Drop a note to hello@durlstonpartners.com and one of the team will be in touch if we have something relevant. …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 4, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7368217308395106304/', '**𝐔𝐫𝐠𝐞𝐧𝐭 - 𝐂𝐨𝐫𝐞 𝐂++ 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 - 𝐇𝐅𝐓 - 𝐑𝐞𝐦𝐨𝐭𝐞 - 𝐔𝐩 𝐭𝐨 $𝟒𝟎𝟎𝐤 𝐓𝐂** One of our top Trading clients is looking for Core Developers to focus on the more advanced parts of Trading Systems Development: - Lock-free data structures and memory-safe concurrency. - Custom market data feed handlers for high-throughput ingestion. - Zero-copy networking, kernel bypass (e.g. DPDK, Solarflare). - Precision timestamping and deterministic behaviour under load. - Compile-time computation (template metaprogramming, constexpr). - NUMA-aware design and cache line optimisation. - Binary protocol parsing for exchange-specific APIs. For more information, please get in touch at james@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 16, 5, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7367858700847304704/', '🚀 𝗙𝗨𝗟𝗟 𝗦𝗧𝗔𝗖𝗞 𝗝𝗔𝗩𝗔 𝗗𝗘𝗩𝗘𝗟𝗢𝗣𝗘𝗥 - 𝗡𝗘𝗪 𝗬𝗢𝗥𝗞 Global multi-strategy hedge fund seeks talented developer for front office team. What you''ll do: Fast paced environment, building trading tools working directly with Portfolio Managers and Quants on Fundamental Equities platform for their NY office. Tech stack: hashtag#Java | hashtag#TypeScript/ hashtag#React | hashtag#Python | hashtag#Kafka | hashtag#SQL Why join: ✅ Established global fund with strong performance history ✅ Collegial culture ✅ Hybrid working You need: ➡️ 3+ years Core Java experience ➡️ Fund/bank background preferred ➡️ Strong SQL skills ➡️ Bachelor''s (or equivalent) Degree in Computer Science ➡️ Located in New York or open to relocation Interested? Drop me a message! 💬or email ab@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 2, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7367492535188877313/', 'We’re always speaking to brilliant people in the market... whether you’re actively looking or just exploring what might be next longer-term, we’re open to having that conversation. We’ve built our business around long-term partnerships, and we know the best moves often come from quiet, early conversations... not when someone’s urgently on the move. That said, we also receive hundreds of messages and applications every day, and as a small team it''s not always possible to respond to everyone. If you''d like to be considered, please email your CV (along with your ideal role and location) to hello@durlstonpartners.com. We’ll make sure it gets in front of the right person (/ people), and if we’re working on something that aligns with your experience, someone will be in touch. We understand the job market is tough right now, and we genuinely do our best to respond to and support as many candidates as we can. We may not always reply immediately, or at all if the timing isn’t quite right, but we’re always building relationships with the long term in mind. And if we don’t end up speaking this time around - wishing you all the best with your search. Have a great week, everyone! hello@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7367111272376463360/', '𝐈𝐬 𝐃𝐚𝐭𝐚, 𝐂𝐥𝐨𝐮𝐝 𝐭𝐞𝐜𝐡𝐧𝐨𝐥𝐨𝐠𝐢𝐞𝐬, 𝐇𝐞𝐥𝐩𝐢𝐧𝐠 𝐭𝐡𝐞 𝐩𝐥𝐚𝐧𝐞𝐭 𝐚𝐧𝐝 𝐇𝐲𝐛𝐫𝐢𝐝 𝐰𝐨𝐫𝐤𝐢𝐧𝐠 𝐚𝐩𝐩𝐞𝐚𝐥𝐢𝐧𝐠 𝐭𝐨 𝐲𝐨𝐮? - 𝐒𝐞𝐧𝐢𝐨𝐫 𝐃𝐚𝐭𝐚 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - £𝟖𝟓𝐤 + 𝐁𝐨𝐧𝐮𝐬 - 𝐋𝐃𝐍 We are working with a highly innovative and trusted ESG partner for top-tier investors, providing a one-stop shop for their sustainability requirements at the portfolio level. They aim to achieve consistent financial returns while improving people''s lives and protecting the planet. Their rapid growth in the past 12 months is attributed to their investment in talent at all levels. They plan to become the key player in the European ESG data and ratings industry, while maintaining full operational independence and benefitting from strong distribution synergies offered by their partnership with a leading B2B WealthTech platform. They are hiring for their data-focused engineering function to build a completely greenfield system using a modern technology stack. 𝐓𝐞𝐜𝐡 - Python, SQL, AWS + More 𝑹𝒆𝒒𝒖𝒊𝒓𝒆𝒎𝒆𝒏𝒕𝒔: 🌍3y+ professional experience as a Software/Data Engineer 🌍 Hands-on experience with Machine learning and Generative AI 🌍 STEM Degree 🌍Passion for working with data and interest in sustainability 🌍Strong Python, SQL, Cloud Experience (AWS) If you or anyone you know could be interested. Please reach out to have a private conversation. ✉ Louis@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7366733899181342721/', '𝗛𝗲𝗮𝗱 𝗼𝗳 𝗛𝗙𝗧 𝗧𝗿𝗮𝗱𝗶𝗻𝗴 𝗢𝗽𝗲𝗿𝗮𝘁𝗶𝗼𝗻𝘀 I am working with a top HFT, looking to build out a Trading Operations function from scratch, aimed at being a consolidate PnL-driven function. You''ll be the first hire, and can scale a team over time. They need people who are highly technical (Python, C++, Linux, R exp), understand HFT strategies very deeply and have great communication skills. This team will span traditional markets and crypto. Location: Dubai/Remote Please reach out if interested rahn@durlstonpartners.com …more', '7mo • 7 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7366043014198116352/', '𝗦𝗲𝗻𝗶𝗼𝗿 𝗗𝗮𝘁𝗮 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿 (𝗥𝗲𝘀𝗲𝗮𝗿𝗰𝗵 𝘁𝗲𝗮𝗺) 𝗥𝗲𝗺𝗼𝘁𝗲 𝗶𝗻 𝘁𝗵𝗲 𝗨𝗦 - 𝗨𝗽 𝘁𝗼 $𝟮𝟬𝟬𝗸 𝗯𝗮𝘀𝗲 + 𝗕𝗼𝗻𝘂𝘀 I am working with a discreet yet reputable global fund, who are looking for a Senior Data Engineer hire to work alongside their Investment teams, to build impressive data infrastructure to fuel research. This will involve working closely with various financial datasets (either in a buy or sell side role), and requires experience with market data ingestion. They are looking for someone with: - 6+ YOE - Python + SQL experience - Cloud experience(e.g. AWS/Azure) - Modern Data Stack (e.g. snowflake) - Experience with Financial Datasets exp. (Bloomberg, Refinitiv etc) - Terraform The process will be fairly swift and they are looking to hire ASAP! Please reach out if this is of interest! Referrals are much appreciated and well rewarded. rahn@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 8, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7365299330632589312/', 'Senior Data Engineer | Leading ESG Analytics Company | London Are you passionate about using cutting-edge technology to drive positive change? Join a fast-growing ESG analytics company that''s helping top-tier investors achieve consistent returns while improving lives and protecting our planet. 🌍 Our client is looking for a Senior Data Engineer role at a fast-growing ESG analytics company in London. They need someone with Python/SQL skills and GenAI experience to build scalable data solutions for sustainable investing. What''s great: ➜ ֎ Work with GenAI, RAG systems, and ML in production ➜ 💥 Small collaborative team with high impact ➜ 🏠 Hybrid working ➜ 🛠️Tech stack: Python, AWS, PostgreSQL, LLMs (No sponsorship is not available for this role) Interested in a quick chat? Apply below or reach out directly. ab@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7364936952288026624/', '𝐔𝐫𝐠𝐞𝐧𝐭 𝐫𝐨𝐥𝐞 - 𝐒𝐞𝐧𝐢𝐨𝐫 𝐃𝐚𝐭𝐚 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 - 𝐒𝐮𝐬𝐭𝐚𝐢𝐧𝐚𝐛𝐢𝐥𝐢𝐭𝐲 𝐈𝐧𝐯𝐞𝐬𝐭𝐦𝐞𝐧𝐭 𝐅𝐢𝐫𝐦 - 𝐔𝐩 𝐭𝐨 £𝟗𝟎𝐤 - 𝐆𝐞𝐧𝐞𝐫𝐨𝐮𝐬 𝐖𝐅𝐇 The firm is hiring a Senior Data Engineer to play a key role in building scalable data systems and deploying real-world GenAI applications, including LLM-powered RAG systems and agentic workflows, in support of impactful ESG insights. ✅ Python, SQL, cloud (AWS preferred) ✅ Experience shipping GenAI or ML models to production ✅ Passion for data-driven sustainability ✅ Hybrid (2 days in-office – London) For more information, please get in touch james@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 11, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7364657653794381825/', 'Two incredible weeks here at Durlston Partners. A few senior Quant PMs we represent are on the verge of receiving offers - creative deals are being structured - as the quantitative markets face a turbulent summer. The "long, slow bleed" highlighted in Business Insider has triggered a wave of conversations on both sides. Clients are asking who''s up, who''s down, and how to position themselves in this shifting landscape. At the same time, we''re speaking to an increasing number of top quant PMs, researchers, and technologists who are quietly exploring what''s out there. We are currently actively hiring for 𝐐𝐮𝐚𝐧𝐭𝐢𝐭𝐚𝐭𝐢𝐯𝐞 𝐏𝐨𝐫𝐭𝐟𝐨𝐥𝐢𝐨 𝐌𝐚𝐧𝐚𝐠𝐞𝐫𝐬 (𝐐𝐮𝐚𝐧𝐭 𝐏𝐌𝐬) 𝐚𝐜𝐫𝐨𝐬𝐬 𝐭𝐡𝐞 𝐔𝐒, 𝐄𝐌𝐄𝐀, 𝐚𝐧𝐝 𝐔𝐀𝐄, 𝐚𝐬 𝐰𝐞𝐥𝐥 𝐚𝐬 𝐟𝐨𝐫 𝐦𝐢𝐝-𝐟𝐫𝐞𝐪𝐮𝐞𝐧𝐜𝐲 𝐫𝐞𝐬𝐞𝐚𝐫𝐜𝐡𝐞𝐫𝐬, 𝐬𝐲𝐬𝐭𝐞𝐦𝐚𝐭𝐢𝐜 𝐄𝐓𝐅 𝐭𝐫𝐚𝐝𝐞𝐫𝐬, 𝐚𝐧𝐝 𝐝𝐞𝐞𝐩 𝐥𝐞𝐚𝐫𝐧𝐢𝐧𝐠 𝐥𝐞𝐚𝐝𝐬. Firms are moving fast to secure talent that can bring resilience and innovation in an environment where every basis point matters. Our strength lies in being deeply connected to both clients and candidates - helping firms shape competitive offers while guiding talent toward platforms that have the leadership, infrastructure, and conviction to thrive through market cycles. 𝗧𝗵𝗶𝘀 𝗶𝘀 𝘁𝗵𝗲 𝗿𝗶𝗴𝗵𝘁 𝘁𝗶𝗺𝗲 𝘁𝗼 𝗵𝗮𝘃𝗲 𝘁𝗵𝗼𝘀𝗲 𝗰𝗼𝗻𝘃𝗲𝗿𝘀𝗮𝘁𝗶𝗼𝗻𝘀 - 𝘄𝗵𝗲𝘁𝗵𝗲𝗿 𝘆𝗼𝘂''𝗿𝗲 𝗹𝗼𝗼𝗸𝗶𝗻𝗴 𝘁𝗼 𝗯𝘂𝗶𝗹𝗱 𝘆𝗼𝘂𝗿 𝘁𝗲𝗮𝗺 𝗼𝗿 𝗲𝘅𝗽𝗹𝗼𝗿𝗲 𝘆𝗼𝘂𝗿 𝗻𝗲𝘅𝘁 𝘀𝘁𝗲𝗽. 𝗟𝗲𝘁''𝘀 𝗰𝗼𝗻𝗻𝗲𝗰𝘁. vick@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7364574571762515969/', '🔍 YTD Talent Trends: Portfolio Managers & Traders (based on Durlston Partners'' 2025 LinkedIn updates) 2025 has been a busy year across both systematic and discretionary trading. Here’s a snapshot of what we’re seeing: Hedge Fund & HFT Hiring Sprint Capital is flowing into multi-strat and systematic firms. There’s strong demand for PMs, quants, and engineers - especially those with track records and platform experience. Engineers and ML talent continue to move from Big Tech to finance in search of more meaningful work and better comp. Global Buildouts for Quant PMs Top-tier quant funds are expanding across New York, London, Singapore, India, UAE - and increasingly open to remote pods. Live track record and strong tech skills are table stakes. Summer Surge Across Strategies Hiring hasn’t slowed — EM Rates/FX, Equity Vol, Options, Commodities, Power, Macro, and US Cash Equities remain active. Also strong demand for QR, ML, and engineering talent. Global Reach, Deep Network Durlston’s been at this over a decade. PMs, researchers, engineers — we know the people and the firms. Offices in London, NYC, and Dubai with reach across Europe, Asia, and the Gulf. We speak to the market daily and are always happy to share insight — whether you''re building a desk or weighing your next move. — Sources: 🔹 HFT & HF growth: https://lnkd.in/d_UfSvVH 🔹 Global systematic PM hiring: https://lnkd.in/dmuYjk5m 🔹 Summer roles snapshot: https://lnkd.in/dEEe49vW 🔹 Durlston overview: https://lnkd.in/dqmjWZY6 vick@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7364212216625000448/', 'Senior Data Engineer required for FinTech Scale-up 🌍 A rapidly growing FinTech scale-up at the forefront of sustainable investing is looking for a Senior Data Engineer to help build and scale their ESG analytics platform. Trusted by top-tier financial institutions across Europe, they combine financial performance with measurable positive impact on people and the planet. Join a small, collaborative team in a greenfield environment where your work will directly shape the future of sustainable finance. More details below: 🔧 Tech stack: Python, AWS & SQL 📊 Focus: Data pipelines, backend services, and scalable infrastructure 🧠 Hands on experience with ML and Gen AI 🌱 3-4+ years’ experience in data/software engineering 📍 Hybrid – London-based with flexible WFH (Min 1 day onsite) 💷 Package: Competitive salary + bonus + great benefits You''ll be part of a small, collaborative team working on greenfield projects that have real-world impact. ❌ Please note: sponsorship is not available for this role Interested? Apply in the comments! daniel@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 11, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7364208171638214659/', 'An absolutely brilliant evening yesterday for our very first Industry Run Club. Perfect weather, beautiful views, and even better conversations - a great mix of reconnecting with familiar faces and meeting new ones across the finance and tech space. If you’d like to join us next time, drop a note to events@durlstonpartners.com and we’ll make sure you’re on the list for future events. Huge thanks to Daniel Frugtniet Hagen for sparking the idea and leading the initiative, and to Louis Esquerré-Gow and Teagan Hill for their support in making it happen. …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 20, 4, 3, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7363849810145148929/', 'We''re working with a trading firm in the UAE which is looking to scale their infrastructure team. Full relocation offered. This team deploys the firm''s systematic trading infrastructure to AWS and wants to speak with hands-on Cloud Infra / DevOps Engineers who love building infra from scratch. Typically a successful team addition will look like someone comfortable with: - CI/CD experience - Strong networking skills (managing core components, layer 0) - Leveraging K8s for containerisation - Cloud security practices - Using Prometheus / Grafana for observability / monitoring Whilst experience working in finance before is not a prerequisite, what is important is that you''ve built infrastructure from scratch before which has maximum uptime and can handle huge amounts of data. 📩 warwick@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
