INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7363230722607726595/', 'Looking like perfect running conditions for our very first industry run club this Wednesday! ☀️🏃‍♀️🏃‍♂️ If you’d like to join us but haven’t registered yet, you can sign up via the Eventbrite link below 👇 All levels are welcome - it’s a relaxed, social run followed by a well-deserved drink afterwards 🍻 A great way to get your steps in, get the blood pumping, and have some interesting chats with people across the industry... whether that’s catching up with colleagues or making new connections. Any questions at all, just drop me a message! https://lnkd.in/evzegfgn …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7363121251298484225/', 'Keen to speak with Heads of OTC Sales (Crypto) in the US. This is the first OTC Sales hire for a very well capitalised business. Ideally NY, Chi considered for the right person. 📩 warwick@durlstonpartners.com 📲 TG @cryptowarwick …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7362755084264304640/', 'Some of the most exciting career moves never get advertised. They happen quietly - through conversations that started long before anyone was actively looking. If you’re content in your role but starting to think about what’s next, maybe things are slowing down, a reorg is looming, or you’re just not being stretched the way you’d like - it’s a good time to start chatting. You don’t need to be desperate or ready to move tomorrow. The best time to speak to a recruiter is when you’re not in a rush, when you can take your time, build a relationship, and get a proper read on what the market’s doing. Then, when something genuinely interesting comes up, you’re already ahead of the game. If you’d like a casual, no-pressure chat about what’s happening in the market (or what might be out there), hello@durlstonpartners.com. …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7362441753825558528/', 'Getting a C++ job in HFT is tough. Getting a top-tier one is another level. The world of HFT moves in nanoseconds and standard C++ knowledge won''t get you a top-tier role here. To land those multi 6 figure jobs, you need to go deeper ⚙️ 𝗖𝗼𝗿𝗲 𝗣𝗲𝗿𝗳𝗼𝗿𝗺𝗮𝗻𝗰𝗲 & 𝗠𝗼𝗱𝗲𝗿𝗻 𝗖++ - It''s not just about knowing C++17 or newer features. It''s about mastering their real-world performance implications. - You need a deep, practical understanding of object-oriented programming, not just the theory. - A solid foundation in data structures and algorithms is non-negotiable for solving complex problems at speed. - Knowing the internals of the STL, how containers like std::vector or std::unordered_map actually work under the hood is critical for optimization. 🚀 𝗟𝗼𝘄-𝗟𝗮𝘁𝗲𝗻𝗰𝘆 & 𝗖𝗼𝗻𝗰𝘂𝗿𝗿𝗲𝗻𝗰𝘆 - Lock-free programming isn''t just a buzzword, it''s a common HFT interview topic and considered ''experts territory.'' - Really understanding multithreading, mutexes, and producer consumer problems in practice, not just theory. 🔩 𝗛𝗮𝗿𝗱𝘄𝗮𝗿𝗲 & 𝗦𝘆𝘀𝘁𝗲𝗺𝘀 - Low-latency isn''t just about code, it''s about the machine. Deep knowledge of processor design, networking (TCP/UDP), and kernel optimisation is key. - You need complete control over memory management, it''s a core reason C++ dominates HFT. 🏗️ 𝗔𝗱𝘃𝗮𝗻𝗰𝗲𝗱 𝗔𝗿𝗰𝗵𝗶𝘁𝗲𝗰𝘁𝘂𝗿𝗲 & 𝗗𝗲𝘀𝗶𝗴𝗻 - Advanced concepts like move semantics, smart pointers, and lambda functions are daily tools. - Low-level system design is a big part of the conversation. You''ll be expected to be familiar with factory and singleton design patterns. - Techniques like branch reduction and prefetching are used to shave off every possible nanosecond. Obviously it can differ from firm to firm but from my experience recruiting for leading prop trading firms and hfts, the gap is clear. The top firms aren''t just hiring C++ developers; they''re hiring performance engineers who live and breathe low latency. ♻️ Repost to help other C++ engineers level up daniel@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 18, 3, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7362126674072649732/', 'Happy Friday! 🌞 This will be the view next Wednesday evening if you join us for our very first industry run club 🏃‍♀️🏃‍♂️ We’re bringing together people from across the quant, tech, AI/ML, and digital assets sectors for a relaxed, social run – a chance to get some fresh air, see a bit of London, and connect with others in the industry. 🕡 Departure from DP London at 6.30pm 🏞 Route: Scenic loop through St James’s & Green Park at a talking pace – all levels welcome 🍻 Post-run: Optional drink at a local pub It’s completely free – just register via the link below so we know to expect you. https://lnkd.in/evzegfgn …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 6, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7362079363476987904/', '🚨 Quantitative Researcher | UAE 🇦🇪 We''re working exclusively with a prestigious quant fund in The UAE that’s looking to expand its high-calibre Research and Strategy team. This is a rare opportunity to work directly with an experienced PM, gaining full exposure to the entire trading lifecycle across systematic fixed income and macro strategies. What They’re Looking For: They want a curious, driven quant with strong technical skills and ideally some background in fixed income or macro. You should enjoy solving complex problems, be confident working independently, and ready to get stuck in from day one. If you’re considering a move to the UAE before year-end and want to join a fund with real growth potential, I’d love to share more details. 📩 teagan@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 12, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7361701880298622976/', '𝗔𝗜/𝗠𝗟 𝗶𝗻 𝗤𝘂𝗮𝗻𝘁 𝗙𝘂𝗻𝗱𝘀 (𝗦𝗼𝘃𝗲𝗿𝗲𝗶𝗴𝗻𝘀, 𝗙𝗮𝗺𝗶𝗹𝘆 𝗢𝗳𝗳𝗶𝗰𝗲𝘀, 𝗛𝗙𝗧𝘀 𝗮𝗻𝗱 𝗛𝗲𝗱𝗴𝗲 𝗙𝘂𝗻𝗱𝘀) 𝗗𝘂𝗯𝗮𝗶, 𝗔𝗯𝘂 𝗗𝗵𝗮𝗯𝗶 𝗼𝗿 𝗟𝗼𝗻𝗱𝗼𝗻 We have too many opportunities to list, but the overall focuses and builds are as below, please reach out if any are relevant/of interest: 𝗗𝗮𝘁𝗮 𝗳𝘂𝗻𝗰𝘁𝗶𝗼𝗻𝘀 - pre/post training data, leveraging alt data, focus on scalability etc. Financial and alt data can be very messy and has gaps, requiring additional cleaning, normalising etc. Alt data include Satellite imagery for analysis of retail parking usage or commodities supplies, media data for NLP Sentiment Analysis, or even geological data to predict weather and the impact on commodities/related equities. 𝗔𝗹𝗽𝗵𝗮 𝗚𝗲𝗻𝗲𝗿𝗮𝘁𝗶𝗼𝗻 - automated feature discovery, dimensionality reduction, predictive modelling etc. NLP is a huge part of this now, leveraging various textual data sources, and focused on Sentiment Analysis, Event Detection, Topic Modelling etc. 𝗠𝗟 𝗣𝗼𝗿𝘁𝗳𝗼𝗹𝗶𝗼 𝗖𝗼𝗻𝘀𝘁𝗿𝘂𝗰𝘁𝗶𝗼𝗻 - constructing portfolios effectively and signal combination. 𝗣𝗼𝗿𝘁𝗳𝗼𝗹𝗶𝗼 𝗠𝗮𝗻𝗮𝗴𝗲𝗺𝗲𝗻𝘁 - ML for Factor investing, Dynamic Portfolio Rebalancing. Explainable AI & Causality are both are key for lower frequency and more capital intensive strategies, where understanding longer term risk is key to managing the book. 𝗥𝗶𝘀𝗸 𝗠𝗮𝗻𝗮𝗴𝗲𝗺𝗲𝗻𝘁 - anomaly detection to detect unusual market movements for systematic risk, unsupervised learning models on macro data to predict default risk, volatility and crashes. Deep Learning to capture complex dependencies and tail events. 𝗘𝘅𝗲𝗰𝘂𝘁𝗶𝗼𝗻 - mostly using Deep RL, either for HFT or optimal execution of larger books, aiming to reduce market impact and transaction costs. RL Agents are effective for optimal trajectory planning to execute large orders over time, creating optimal sizes, timing, venues etc. Microstructure analysis can dissect the dynamics of order books and make short term predictions. 𝗜𝗻𝗳𝗿𝗮𝘀𝘁𝗿𝘂𝗰𝘁𝘂𝗿𝗲 - performant, scalable, reliable infrastructure to support these models is key, handling real-time data ingestion, with low-latency inference and secure model deployment. Please reach out if any of the above is of interest to you: rahn@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7361386976651923458/', 'T-minus 1 week until our market 5k run! Mixing up the usual post-work routine with something a bit different… join us for the very first Durlston Partners Run Club 🏃‍♀️🏃‍♂️ A relaxed, social run to bring together people from across the finance and tech space! 🗓 Date: Wednesday 20 August ⏰ Time: 6:30pm 📍 Route: Scenic loop around St James’s & Green Park 👟 Pace: Talking pace - genuinely all levels welcome 🍻 Post-run vibes: Optional (but encouraged) pint at The Devonshire It’s completely free, super low-key, and open to anyone in the industry who fancies doing something a bit different after work. Want to join? Register via EventBrite (link below): https://lnkd.in/evzegfgn …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 7, 1, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7361354609468002305/', 'Stop scrolling… 🚨 Looking for your next big move? Now’s the perfect time to explore. I’m actively hiring for LIVE roles at some of the world’s most exciting hedge funds, HFTs, and trading firms, from crypto pioneers to elite quant houses. Whether you specialise in Python, C++, Java, Rust, or Data, top-tier talent is in serious demand right now. Here''s a snapshot: 🐍 Python • Crypto Market Maker – Python Developer | London • Family Office – Quant Developer | Abu Dhabi • Hedge Fund – Trading Systems Engineer | Abu Dhabi 🧠 C++ • Crypto Market Maker – C++ Developer | London • Quant Trading Firm – Strategy Developer | Fully Remote (US) • HFT / Hedge Funds – C++ Developer | Remote / Amsterdam / NYC / Chicago ☕ Java • Quant Hedge Fund – Senior Java Developer (Securities/Crypto) • Multi-Strategy Fund – Full Stack Java Engineer (Equities/Credit) • Crypto Exchange – Senior Software Engineer | Fully Remote (EMEA) 🦀 Rust • Crypto Market Maker – Junior Rust Developer (DeFi) | London • Multiple Trading Firms – Rust Developer | London / Remote 📊 Data • Hedge Fund – Senior Data Engineer / Data Scientist | UAE • Multi-Strategy Fund – Python Data Engineer | London / NYC If you’re curious about what’s out there, let’s have a confidential chat. daniel@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 10, 2, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7360992226270740480/', 'If you''re early in your career and writing Rust (or wanting to have the chance to) is your idea of fun, read on. One of the most active crypto market makers in the world is hiring a Junior Core Engineer to join their DeFi team. You’ll work on backend infrastructure powering real trading strategies (not dashboards, not internal tools). You’ll need: 1. A first-class degree in Computer Science from a top university 2. Solid backend engineering experience (systems/infra, not data science/ML) 3. At least two of the following: Rust (strongly preferred), Python, or hands-on exposure to DeFi systems The team is sharp, the code is clean, and the work sits at the heart of real-time trading on-chain. Not quite the right fit? I’ve also got a fully remote role with a Crypto HFT who are happy to support you if you’re the type who wants to chase the sun. If you''re curious, I’m happy to chat about anything related to this world (Rust, rollups, or relocations), even if you''re not ready to apply. Just drop me a message. karolis@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7360626065993547776/', 'The buzz around Dubai is getting seriously loud 🔥 And we''re seeing it happen in real-time. If you''ve been following the finance world... You know the headlines. This isn''t just a trend, it''s a shift, and Dubai is quickly becoming a major global hub. The top funds we''re partnered with are building their core teams. Specifically, they need: 1. 𝗦𝗼𝗳𝘁𝘄𝗮𝗿𝗲 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿𝘀 2. 𝗗𝗮𝘁𝗮 𝗔𝗻𝗮𝗹𝘆𝘀𝘁𝘀 & 𝗗𝗮𝘁𝗮 𝗘𝗻𝗴𝗶𝗻𝗲𝗲𝗿𝘀 3. 𝗤𝘂𝗮𝗻𝘁𝘀 (especially with experience in systematic strategies like ML/AI applied to macro, rates, and FX) If you''re a world-class engineer or quant and want to be part of this, reach out to Vikram Tandon or myself. Let''s talk. 🚀 Daniel@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7360203252455337984/', '**𝐖𝐞𝐞𝐤𝐥𝐲 𝐋𝐢𝐯𝐞 𝐑𝐨𝐥𝐞 𝐔𝐩𝐝𝐚𝐭𝐞** Even with it being the holiday period, plenty of our clients are pushing forward with hiring. Please see below a brief overview of some of our most urgent roles hashtag#London Senior Vol Quant Analyst (Python) - Hedge Fund - Up to £500k TC Senior Developer, Prime Brokerage(Java) - Hedge Fund - Up to £400k TC Risk Tech Developer(React) - Hedge Fund - Up to £130k Base + Bonus Full Stack Equities Developer(Java/React) - Hedge Fund - Up to £300k TC Core Developer (Python) - Market Maker - Up to £150k Base + Huge Bonus hashtag#NYC GPU/HPC Expert (C++/Python) - Quant Fund - Up to $1m TC+ Strategy Developer(C++) - Quant Fund - Up to $800k TC Data Engineer(Python) - AI Start up - Up to $320k Base + Equity SWE (Java/Python) - AI Start up - Up to $340k Base + Equity Founding DevOps Engineer(Python) - AI Start Up - Up to $260k Base + Equity hashtag#Remote Head of FX Trading (XAF/XOF Sales) - FinTech Start up - Open on compensation Strategy Developer(C++) - HFT - Up to $650k TC Trading Systems Developer(C++) - HFT - Up to $250kTC API Engineer (Rust/C++) - Crypto Trading Firm - up to $400k TC For more information on the above, or if you would like a discreet chat about how to handle your search, please get in touch at James@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 11, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7359901264551243776/', 'Not just another analyst role.... Forget your usual 9 to 5. Here’s what your new Tuesday could look like. You walk into a buzzing office in the heart of London’s financial district. The team is deep in conversation about a new feature that will streamline risk analysis for a major hedge fund. Your mission? To dive under the hood of the most modern, cross-asset trading and risk management platform on the market. One moment you’re configuring the system to meet a client’s unique needs, the next you’re on a call with a top-tier asset manager, guiding them through the implementation process. Your desk is next to the Head of the team. There are no layers of bureaucracy here. You have a direct line to leadership and your ideas are heard, debated, and implemented. This is a place for the curious. A place where you’ll be pushed to learn about the latest tech and the intricacies of financial markets. It’s a onsite role because this team thrives on that collaborative spark. This isn’t just about technical know how. It’s about building the solutions that will shape the future of an entire industry. Sound like your kind of Tuesday? Apply in the comments Daniel@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 6, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7359901266644213761/', 'The momentum in the region continues to build. With nearly 200 hedge fund relocations over the past 5 years, the UAE—and Dubai in particular - has become a serious hub for global finance. Great to see Hudson Bay and others spotlighted by Bloomberg and the broader interest in what’s happening on the ground. We’re seeing more clients and candidates lean into the growth here, and it’s only just getting started. We’re actively hiring across strategies - particularly in ML/AI tied to macro, rates, FX, and other systematic approaches. Reach out if you want to be part of the growth. Let’s see where the second half of the year takes us. vick@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 4, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7359538946734755840/', 'Are you a Quant looking to be a part of a new prop desk from scratch? They aren''t expanding their core business. They''re building a new proprietary trading desk from the ground up. This is a chance to join a new venture, backed by the infrastructure and resources of an established firm, as they move into directional trading in FX and futures. Here’s what they’re looking for in a Quantitative Researcher: 1. Alpha Research Experience ➟ One year plus is essential. This is a big focus. ➟ PhD graduates with exceptional internships will be considered. 2. A Must-Have Skill ➟ An outstanding background in traditional statistics. ➟ This is the absolute foundation for this position. 3. Technical Proficiency ➟ Python is the main language you''ll be using. ➟ Experience with Java is a nice-to-have. 4. Specific Trading Background ➟ They are only looking for directional trading experience. ➟ Market-making backgrounds won''t be a fit for this specific role. And equally important... This isn''t just about fitting a spec. It''s about the opportunity to: ✅ Work directly with the Head of the new desk. ✅ Build and research strategies from end-to-end. ✅ Be a foundational member of a well-funded new team. It''s a chance to make a real impact from day one. Think you''re the right fit? Send me a message. Let''s discuss it. daniel@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7359172728953704448/', 'We''ve had gorgeous weather this summer in London - always feel lucky heading into the office on such an iconic street. The DP team (me especially) has fully bought into the M&S cookie hype & we’re picking them up far too frequently 🍪 We’re hiring! 1️⃣ A junior recruiter who’s open to relocating to Dubai (curious, switched-on, ambitious) 2️⃣ A senior quant recruiter (HFT / systematic focus) 3️⃣ And we’re always open to chatting with experienced consultants who can plug into the platform and hit the ground running At Durlston Partners, we work with some of the most exciting names in the industry with offices in London, New York and Dubai. You’ll have warm desks, immediate access to top-tier clients, and support tailored to your goals -whether that’s being a top-billing IC, leading a team, or growing major accounts. We offer market-leading commission, BD incentives, meaningful profit share, plus all the extras you’d expect: incredible team culture, regular socials - lunches, cookies, deliveroos, wellness perks, and trip incentives (our last one was Vegas). shannon@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7358857866025263104/', 'T minus 2 weeks until the very first DP / industry Run Club! 🏃‍♀️🏃‍♂️ We’re swapping the usual post-work routine for something a bit different… a relaxed, social run to bring together people from across the finance and tech space. 🗓 Wednesday 20 August ⏰ 6:30pm 📍 Scenic loop around St James’s & Green Park 👟 Talking pace - all levels welcome 🍻 Post-run drink at The Devonshire (optional… but encouraged) According to the 2-week forecast, it’s looking like sunshine - so if you fancy getting some fresh air, meeting great people, and earning your midweek pint, we’d love to have you join. It’s completely free and open to anyone in the industry, just register below: https://lnkd.in/evzegfgn Tag a friend or colleague who should be on that start line with you 👇 hashtag#RunClub hashtag#FinanceAndTech hashtag#LondonRunClub hashtag#NetworkingButFun hashtag#HedgeFunds hashtag#FinTech hashtag#DurlstonPartners hashtag#TeamDP Daniel Frugtniet Hagen Shannon Palmer Danny Placinta …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 13, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7358776355041222656/', 'Junior Quants, are you looking to have real impact from day one? We’re working with a leading electronic trading firm that’s quietly building out a new directional trading desk, and they’re hiring a junior Quantitative Researcher to help drive it forward. This is a rare opportunity to join at the ground level of a prop trading effort, working directly with the Head of Trading on alpha signal research in FX and futures. You’ll be part of a small, high-calibre team where your work won’t just be noticed, it’ll shape the future of the desk. They’re looking for bright, motivated individuals with a passion for research, strong statistical foundations, and the drive to build something new. If you''re the kind of person who enjoys solving complex problems and thrives in a fast-paced environment, this is a serious growth opportunity. DM me if you''d like to learn more. …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 15, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7358447937233768448/', '🚨 𝐍𝐞𝐰 𝐑𝐨𝐥𝐞𝐬 𝐚𝐭 𝐚 𝐋𝐞𝐚𝐝𝐢𝐧𝐠 𝐌𝐮𝐥𝐭𝐢-𝐒𝐭𝐫𝐚𝐭𝐞𝐠𝐲 𝐇𝐞𝐝𝐠𝐞 𝐅𝐮𝐧𝐝 - 𝐋𝐨𝐧𝐝𝐨𝐧 🚨 I''m hiring across multiple teams for a top-tier hedge fund. If you''re passionate about building robust systems in fast-paced front office environments, take a look: 👨‍💻 𝐑𝐢𝐬𝐤 𝐓𝐞𝐜𝐡 - 𝐑𝐞𝐚𝐜𝐭 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 >3+ years'' experience >Front-end focused (React & Java) >Building dashboards to report risk metrics 👩‍💻 𝐅𝐮𝐥𝐥 𝐒𝐭𝐚𝐜𝐤 𝐉𝐚𝐯𝐚 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 - 𝐄𝐪𝐮𝐢𝐭𝐢𝐞𝐬 >3+ years'' experience >Java & React (ideally 50/50 split) >Front office exposure, working directly with PMs globally 💼 𝐅𝐮𝐥𝐥 𝐒𝐭𝐚𝐜𝐤 𝐉𝐚𝐯𝐚 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 - 𝐂𝐫𝐞𝐝𝐢𝐭 >3+ years’ experience >Heavily backend (90/10 Java/React) >Direct interaction with Credit PMs globally 💰 𝐉𝐚𝐯𝐚 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 - 𝐓𝐫𝐞𝐚𝐬𝐮𝐫𝐲 >3+ years’ experience >Core backend development for treasury systems ⚡ 𝐑𝐚𝐩𝐢𝐝 𝐀𝐩𝐩𝐥𝐢𝐜𝐚𝐭𝐢𝐨𝐧 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 - 𝐂𝐨𝐦𝐦𝐨𝐝𝐢𝐭𝐢𝐞𝐬 >5+ years'' total experience, 2+ in RAD >Strong Python, SQL, Excel & web scraping >Front office, fast-paced trading support 📩 Interested or know someone exceptional? Drop me a message or reach out at louis@durlstonpartners.com - happy to share more. …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 11, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7358085554166472704/', 'Markets aren’t cooling down. Volatility continues to drive activity across the board. Whether it''s macro shifts, earnings, or positioning, things have stayed busy. Our clients are deep in it—firing on all cylinders across quant and systematic strategies globally. Feels like no one’s slowing down this summer. Recent articles are calling this environment “choppy but rich with opportunity,” especially for systematic funds. We’re seeing the same—teams are staying sharp, and capital is still moving where the edge is real. Let’s keep the momentum going. If you''re building, scaling, or just keeping an ear to the ground, always happy to connect. A few standout roles we’re hiring for: – Systematic PMs – Global Fully automated strategies across futures, equities, options, and crypto. Mid/high-frequency. – Crypto Quant Traders – London HFT market making in spot, perps, and futures. – Quant Devs, Infra Engineers, ML Researchers Python/C++ roles in New York, Chicago, Abu Dhabi, London, and Amsterdam. – FPGA, NLP, Execution Research, Business Analysts Roles spanning buy side, hedge funds, and crypto-native teams. If you''re scaling, hiring, or just want to hear what’s out there, happy to connect. 📩 hello@durlstonpartners.com or drop me a note directly - vick@durlstonpartners.com. Stay cool, stay sharp. …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 6, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7357723163964624896/', 'He left one of the biggest names in the game... From an HFT everyone in the industry knows… to a fund hardly anyone’s heard of. A smaller team, less shine, fewer perks, and it didn’t make sense. So why did he do it? “I was tired of being one cog in a thousand. I wanted to build something where I could actually see the needle move.” Now, he’s not just contributing, he’s owning. Architecting systems end to end. Making technical calls that directly impact trading. Sitting one desk away from the people taking risk, not buried five layers deep in a silo. Not the comp. Not the comfort. The impact. There’s a quiet trend happening, engineers from the most elite shops are choosing smaller, sharper environments, not for status, but for scope. Because long-term success isn’t just about being at the best firm. It’s about becoming the kind of engineer funds build around. Before you make your next move, ask yourself, am I gaining real autonomy or just chasing brand equity? Am I building meaningful depth, or getting boxed in as a specialist? Does this role develop my skills or just looks good on my CV? Big names open doors. But they’re not the only doors worth walking through. If you''re looking for a role where you can have real impact, feel free to reach out, happy to chat. daniel@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 16, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7357360773595103232/', '🚨 We’re hiring for Dubai 🚨We’re looking for a curious, driven individual to join our growing Dubai team. We’re open on background - this could suit someone with a STEM or research-heavy degree who wants to move into a more commercial role and work with some of the smartest minds in the world. Or someone naturally sharp and ambitious, with a strong interest in finance and tech, who’s keen to build a career in a high-performing environment. Recruitment or sales experience is a plus, but not essential. You just need to be bright, switched-on, and up for a challenge. Must be open to relocating to Dubai (either immediately or with a start in our London office first). At Durlston Partners, we work with some of the most exciting names in the industry (hedge funds, HFTs, AMs, Prop Shops, FinTechs). Warm desks, brilliant clients, and a commission structure that in uncapped, plus BD incentives, profit share, and all the support you need to succeed. Interested? Drop me a message or email shannon@durlstonpartners.com We offer cash for successful referrals so if you know anyone who could be interested, send them my way. …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 8, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7356964442363863040/', 'Summer Slowdown? Not Quite. While the summer months often bring a natural lull, many of our clients are still actively hiring. Some key themes we saw from H1: 📈 Continued hedge fund expansion into the UAE We’ve seen a noticeable uptick in firms establishing or growing their presence in Abu Dhabi and Dubai. For candidates, this has opened up exciting new avenues. Many of those we’ve introduced to top-tier funds in Europe and the US have also landed offers in the UAE, drawn by the region’s tax advantages, lifestyle, and increasing relevance as a financial hub. 🤖 Rising demand for AI/ML talent This year has marked a significant push into applied ML. A growing number of firms, both traditional and tech-driven have begun building out dedicated machine learning teams, with a strong emphasis on production-grade applications and LLM integration. ML expertise is quickly becoming a defining feature of high-impact candidates. 🚀 Start-up funds continuing to scale with highly targeted, strategic hires While early-stage funds remain selective, they’re actively hiring when they see the right fit. We’ve seen demand particularly for individuals with a “founder mindset” who can operate across multiple domains and help shape the fund’s DNA in its formative years. As client hiring becomes more focused and deliberate, it can feel quieter on the opportunistic front, but there''s plenty happening under the surface. If you''re in London (or passing through), I’d love to grab a coffee. Whether you''re actively exploring or just want to chat, I’m always happy to connect and share market insights. Feel free to message me directly (teagan@durlstonpartners.com) or drop a comment below 👇 …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7356711494006251520/', 'We’re always speaking to brilliant people in the market... whether you’re actively looking or just exploring what might be next longer-term, we’re open to having that conversation. We’ve built our business around long-term partnerships, and we know the best moves often come from quiet, early conversations... not when someone’s urgently on the move. That said, we also receive hundreds of messages and applications every day, and as a small team it''s not always possible to respond to everyone. If you''d like to be considered, please email your CV (along with your ideal role and location) to hello@durlstonpartners.com. We’ll make sure it gets in front of the right person (/ people), and if we’re working on something that aligns with your experience, someone will be in touch. We understand the job market is tough right now, and we genuinely do our best to respond to and support as many candidates as we can. We may not always reply immediately, or at all if the timing isn’t quite right, but we’re always building relationships with the long term in mind. And if we don’t end up speaking this time around - wishing you all the best with your search. hello@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 6, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7356636008634847232/', '𝗛𝗲𝗮𝗱 𝗼𝗳 𝗢𝗧𝗖 𝗙𝗫 𝗧𝗿𝗮𝗱𝗶𝗻𝗴 - 𝗘𝗠 (𝗖𝗲𝗻𝘁𝗿𝗮𝗹/𝗪𝗲𝘀𝘁𝗲𝗿𝗻 𝗔𝗳𝗿𝗶𝗰𝗮𝗻) - 𝗥𝗲𝗺𝗼𝘁𝗲 I am working with a very well-backed firm, leveraging an incredible cross-border platform, and now looking to capture FX volumes and drive liquidity in Central and Western African nations. This hire will have full remit to set up and lead an OTC FX Trading desk, working closely with the biggest liquidity providers in the region. Remote - UTC (0-3) e.g. London to Dubai Compensation: Strong Base + Upside (Equity/Commission) rahn@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 6, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7356262313311490049/', '🚨𝐔𝐫𝐠𝐞𝐧𝐭 𝐌𝐚𝐧𝐝𝐚𝐭𝐞 - 𝐒𝐞𝐧𝐢𝐨𝐫 𝐕𝐨𝐥 𝐐𝐮𝐚𝐧𝐭 - 𝐁𝐨𝐮𝐭𝐢𝐪𝐮𝐞 𝐅𝐮𝐧𝐝 - 𝐔𝐩 𝐭𝐨 £𝟓𝟎𝟎𝐤𝐓𝐂🚨 One of the top Funds in London (in their space), is looking to hire a Senior Quant who will build out infrastructure in the IR Vol space. This would include modelling pricing and risk for IR Vol Products, ideally focusing on OTC products as well as working directly with the Senior PM implementing tooling and analytics. Comp is up to £500k TC WFH: 3 days in the office For more information, please get in touch: James@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 2, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7355907478854803457/', 'Volatility is thriving — and so is demand for talent that understands it. We''re seeing a sharp increase in demand across buy-side platforms — from hedge funds to asset managers — for Volatility Traders and Quant Researchers in the US, EMEA, and Australasia. Markets remain reactive, dispersion is high, and volatility is no longer just a hedge — it''s a strategy in its own right. As recent headlines put it: 📰 "Volatility trading desks are delivering real alpha as uncertainty surges" (WSJ, June 2025) 📰 "Investors are leaning into vol, RV, and convexity strategies to navigate the new normal" (Reuters) We''re speaking to firms scaling across: ▪️ Equity, rates, FX, and commodity vol ▪️ Systematic and hybrid quant approaches ▪️ Strong emphasis on technical ability, research depth, and signal development Suppose you''re building models, refining surfaces, or monetizing skew. In that case, there''s a meaningful appetite for profiles with hands-on quant and trading experience—especially those combining statistical rigor with real-world trading intuition. 📩 Open to exploring what''s out there? I am happy to have a confidential chat. vick@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 6, 0, 1, 'image', 0, NULL);
