INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7355190263209680897/', '🚨 STOP SCROLLING... If you''re a Pythonista I’m headhunting for Python Engineers to join a seriously sharp trading team, building ultra-fast systems where milliseconds matter. ✅ No pointless meetings ✅ No dull maintenance work ✅ No outdated tech holding you back If you’re fluent in Python and up for a proper challenge, let’s have a chat. 📩 DMs are open or apply below, or tag someone who should see this. daniel@durlstonpartners.com …more', '8mo • 8 months ago • Visible to anyone on or off LinkedIn', 16, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7354854262876635136/', '𝗧𝗲𝗰𝗵𝗻𝗶𝗰𝗮𝗹 𝗟𝗟 𝗢𝗽𝘁𝗶𝗺𝗶𝘀𝗮𝘁𝗶𝗼𝗻 𝗠𝗮𝗻𝗮𝗴𝗲𝗿 - 𝗛𝗙𝗧 - 𝗘𝘂𝗿𝗼𝗽𝗲 𝗼𝗿 𝗗𝘂𝗯𝗮𝗶 I am working with one of the best HFTs in the world, flying a bit more under the radar than most, to bring in a Technical LL Optimisation Manager to work closely with their Head of BD, and oversee cloud and networking solutions. You''ll leverage strong technical understanding of networking and cloud solutions, working closely with internal research and development teams to understand their needs for optimisation and improvements top their existing network and cloud solutions, then working with new and existing vendors to find the best solutions. After this you would work with internal teams to implement these solutions. Looking for: - Hands-on experience in network engineering, cloud infra, LL solutions. - Interest in managing projects, and experience working with vendors and internal stakeholders Comp will be very strong, 3 stage process Feel free to reach out if you need more info: rahn@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7354454119996170240/', 'Why are people really leaving their jobs?.... In the world I work in, whether it''s HFTs, hedge funds, or fintechs, I''ve seen just about every reason for why someone decides to move on. Some are frustrated by lack of growth, others are fed up with chaotic leadership. Sometimes it''s something personal: a toxic manager, burnout, or just not feeling challenged anymore. And sometimes? It’s just about the money. Whatever the reason, one thing''s clear: behind every move is a story. Curious to hear what your top reason is... daniel@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7354425456734916608/', 'How to boost your focus and energy without sacrificing your career? With the demands of a career in finance or tech, finding time and energy for fitness can be tough. I used to finish work drained, convince myself I didn’t have hours for the gym, and overthink my way out of a run. But I’ve found running is one of the most efficient ways to boost focus and clear your head, no gym required. That’s why I’m thinking of starting a Run Club, and I know... another run club! But this one’s for finance and tech professionals in London, a chance to stay active, connect with like minded people, and keep each other accountable 👉 If there’s enough interest, I’d love to host a first meet-up in August. Open to all fitness levels. Comment below if you’d be interested / message me Daniel Frugtniet Hagen - I’ll share details once it’s confirmed. …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 12, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7354072948082679808/', 'Build the brain before chasing the alpha Most roles in quant finance are about research. This one? It''s about building the engine behind it. I''m looking for a Quant Researcher, not the “backtest a signal” type but someone who thrives at the intersection of code and quantitative thinking. Someone who can architect a modelling platform and later help shape the future of research. 🔍 What’s different about this role? – You’ll work shoulder to shoulder with one of the top minds in the team (Head of Quant Research) – Alpha research isn’t the priority yet, engineering excellence is – Your impact will be felt immediately, and learning potential is endless ⚙️ What we’re looking for: – 3–5 YOE (2 for truly exceptional people) – Mastery of Python and cloud (AWS) – Side projects? Even better (crypto counts) – Buyside > sellside (but brilliance beats background) – Someone who can hit the ground running without being micromanaged 📍 Location: NYC preferred (London possible for standout candidates) 💰 Compensation: $400K–$450K total compensation If you’re a engineer who happens to be a quant or a quant with serious engineering depth, this is a rare opportunity to build something impactful, directly alongside leadership, with room to grow into deeper research later. Drop me a message if you''re curious or tag someone who should see this. daniel@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 7, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7353706715575422976/', '🧠 + 💰 = The Next Frontier for Multi-Strats AI isn’t just catching up to finance—it’s rewriting how top hedge funds build edge. Over the last 12 months, the conversations have shifted. It’s no longer “Should we hire AI talent?” It’s: “How do we integrate top-tier researchers into our investment engine—before our competitors do?” We’re seeing multi-strats move fast: 🔹 Building in-house AI labs 🔹 Hiring from top research groups (think DM, OAI, Meta AI) 🔹 Embedding ML talent alongside PMs and quants—not in a silo At Durlston, we’re partnering with funds leading this charge—those backing their AI ambitions with serious capital and long-term vision. If you’re an AI researcher looking to go beyond theory, or a fund rethinking how to future-proof your platform, let’s talk. This space is moving quickly—and the window to build something differentiated is now. vick@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 9, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7353363183794802688/', '“Can you just send me the job details?” Totally fair question. But, and hear me out, sometimes, skipping straight to the job spec can do more harm than good. When the focus is just on the role, not the reason behind your move, you can end up chasing what looks good on paper... but doesn’t feel right when you''re actually in it. ✅ Great salary ✅ Impressive title ❌ Zero alignment with what you value ❌ Not the growth path you’re actually looking for The reality? A job spec can influence your motivations before you’ve even had a chance to reflect on what you truly want. And that’s where mismatches happen, sometimes not until you''re a few months in and wondering why the spark isn’t there. So no, I’m not just going to fire over a JD and hope it sticks. I want to understand what’s important to you first. Autonomy? Mentorship? Technical stretch? A healthier work/life setup?.. What motivates you. Once we have that, we can filter everything else through that lens, not the other way around. The best moves are tailored, not templated. Let’s talk about where you’re heading and if I can help get you there. daniel@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7352951720341037056/', 'A pretty cool position in Abu Dhabi for a Research Quant Developer currently working at a systematic shop with a modern stack and ML tooling. Think; mixing strong components of research and development to work across everything a Quant Portfolio Manager does. This means you’ll need to bring experience in rapid prototyping and visualisation and a skillset of deep familiarity with Python and one other more performant language such as C++ or Java + AWS or Azure Photo: Abu Dhabi rush hour traffic at 17:41 on a Wednesday 💲 USD up to $175k base + strong bonus + relocation perks 📍 Abu Dhabi 📲 Joshwa Shah 📩 josh@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 12, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7352649729576509440/', '𝐀𝐜𝐭𝐢𝐯𝐞 𝐋𝐢𝐯𝐞 𝐓𝐞𝐜𝐡 𝐑𝐨𝐥𝐞𝐬 - UAE, UK, US, Remote If it starts with ‘United’, I’m probably recruiting there. Below is a list of exciting opportunities I’m actively sourcing across the UAE, US and UK. Plus, for those in my network who prefer to skip the commute, I’ve included a remote section too If any of these are of interest or if you know someone who is a good fit, reach out to jared@durlstonpartners.com 𝐔𝐀𝐄: 🌍Crypto - Head of Front Office Technology (HFT/Crypto) – up to $400k TC (UK location as well) 🌍Quant Fund – Trading Systems Developer – up to $400k TC 🌍Quant Fund – Senior Data Engineer – up to $400k TC 🌍Crypto - Product Lead (SWE background) – up to $140k base + bonus + equity 𝐔𝐒: 🌎Quant HFT – Head of AI Research (Deep Learning) – up to $2-4m TC 🌎Quant Fund/HFT - Lead C++ Strategy Developer – up to $700k–$800k TC 🌎AI Start up – Software Engineer (Python) - up to $260k base + equity 🌎AI Start up – Data Engineer (Python) - up to $300k base + equity 𝐔𝐊: 🌍Crypto FinTech - C++ Developer – up to £150k base + equity 🌍Crypto Market Maker - C++ Quant Dev - up to £150k base + up to 100% bonus 🌍Hedge fund – Java Developer (Equities/Credit) – up to £130k base + disc bonus 🌍Crypto Market Maker – Core Python Developer - up to £150k base + up to 100% bonus 𝐑𝐞𝐦𝐨𝐭𝐞: 📍DeFi - Senior Rust Engineer – up to £200k base + equity 📍Crypto HFT – C++ Engineer – up to £175k base + bonus 📍HFT – Infrastructure SRE – up to £200k base + bonus 📍Crypto – Software Engineer (Java) – up to $130k TC …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 22, 3, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7352340190931087360/', '🚨We’ve teamed up with a high-performing, long-established crypto investment firm - a tech-first, well-capitalised group managing significant assets in the digital asset space. 🚨 They’re on the lookout for a 𝐇𝐞𝐚𝐝 𝐨𝐟 𝐅𝐫𝐨𝐧𝐭 𝐎𝐟𝐟𝐢𝐜𝐞 𝐓𝐞𝐜𝐡𝐧𝐨𝐥𝐨𝐠𝐲 to drive the next phase of their trading tech evolution across HFT and crypto markets. This is a unique leadership role with end-to-end ownership of cutting-edge systems in a live trading environment. 🎯 𝐖𝐡𝐚𝐭 𝐭𝐡𝐞𝐲''𝐫𝐞 𝐚𝐟𝐭𝐞𝐫: >A senior engineering leader with experience at a top-tier HFT or quant trading firm >Deep expertise in trading architecture and ultra-low-latency infrastructure >Crypto experience is welcome, but not required >Candidates must be based in or open to relocating to London or Abu Dhabi 💸 𝐂𝐨𝐦𝐩𝐞𝐧𝐬𝐚𝐭𝐢𝐨𝐧: £𝟐𝟓𝟎–𝟑𝟎𝟎𝐤 𝐭𝐨𝐭𝐚𝐥 𝐩𝐚𝐜𝐤𝐚𝐠𝐞 💸 You’ll be joining a nimble, high-impact team where speed and ownership matter. They’re ideally seeking someone coming off gardening leave or able to start soon. If you’re interested (or know someone strong in this space), feel free to reach out - all conversations held in confidence. louis@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 9, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7351883442013282304/', '🚨 Quantitative Researcher | UAE We''re working exclusively with a Quant Fund in the UAE looking to add a Quantitative Researcher to their Research & Investment team. 🔍 The role covers the full research cycle from idea generation, collaborating with the tech teams to meet data requirements (alt/market/fundamental) to backtesting and implementation. This is a strong opportunity to also work on both portfolio construction and systematic manager selection. You’ll join a tight-knit team of high-calibre individuals in a role that offers real ownership and room to grow. They’re looking for curious, driven people who enjoy solving problems and aren’t afraid to get stuck in. The platform is exceptional, as is the compensation, and relocation can be arranged quickly for the right person. If this interests you, and you''re looking to move to the UAE, please don''t hesitate to reach out here or on email teagan@durlstonpartners.com 📧 …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7351555018560282626/', 'What am I seeing in the market?... I’ve been speaking with a lot of clients and candidates over the past few weeks and there’s a clear theme, C++ hiring is booming. Why? Because as more firms chase lower latency, better throughput, and smarter infrastructure, C++ is still the go-to for building performance-critical systems. Whether it’s a hedge fund optimising execution, a crypto exchange scaling up, or an HFT shaving microseconds off their stack, they all need engineers who understand how things work under the hood. We’re seeing this across the board: 🧠 C++ engineers with strong systems knowledge are in serious demand 🌍 Roles across Europe – London, NY, Amsterdam, UAE and remote/hybrid flexibility 💥 Working on real-time trading engines, market data, connectivity, and performance bottlenecks If you’ve got experience with low-level systems, multithreading, networking, etc, and want to work on problems that actually matter, it’s a great time to explore what’s out there. Drop me a message if you''re curious daniel@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 13, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7351151108653809664/', '2 pretty cool hashtag#Remote Rust Engineering positions for a DeFi Trading client of ours. #1 : You''ll be building core infrastructure for a real-time streaming indexer. Think; ingest, transform and serve super high-volume DeFi data. They''ll need you to know how to ensure the data layer is not only accurate but scalable (and low-latency to boot). #2 : You''ll be taking charge of low latency APIs and the infrastructure that surround them. If you like sitting at the very core of what''s being built, you''ll be included in product design, system architecture and backend work. Want to own your own suite of APIs? Lmk! 💲 USD 200k-275k base 📍 Remote 3️⃣ Stage interview process (Founder chat, tech test, test debrief w/ team) 📲 @cryptowarwick 📩 warwick@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7350822707241910273/', '🚀 We’ve just partnered with one of the longest-running and best-performing Crypto Funds — a capital-rich, tech-driven team managing sizeable AUM. 🚀 They’re now looking for a Head of Front Office Technology to lead and scale their trading systems across HFT and digital markets. This is a rare opportunity to take full ownership of the tech powering a live, high-performance trading business. 💼 What they’re looking for💼: ✔️A senior technologist from a tier-1 HFT or systematic trading firm ✔️Strong understanding of trading infrastructure and low-latency systems ✔️Experience in crypto markets is a bonus but not essential ✔️Must be based in (or open to relocating to) London or Abu Dhabi 💰 Total comp: £250–300k💰 The team is agile, fast-moving, and keen to hire someone who can hit the ground running. Ideal candidates will be post-gardening leave or on a short notice. If this sounds like you (or someone you rate), I’d love to hear from you. Discretion assured. james@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7350430128973201408/', 'If you’re an engineer who wants to build tech that directly impacts trading decisions (not just dashboards that get ignored), this is for you. A top-performing hedge fund (global presence, low turnover, serious tech culture) is expanding its front office tech teams in London and NYC. They’ve built one of the cleanest, most scalable infrastructures previous applicants have seen, and they’re growing. A look at their current openings: 1. Python Rapid App Developer (Commodities - London) - Work side-by-side with PMs, starting in agricultural trading (coffee, corn). Fast, business-critical builds, not maintenance work. - 5+ yrs experience (2+ in RAD ideal). Python, SQL, Excel, web scraping. 2. Full Stack Java Developer (Credit - London) - Work directly with PMs, collaborating across fixed income, risk, and equities tech. Tight-knit front office team with real influence. - 3+ yrs experience. Primarily Java (90/10 Java/React). 3. Full Stack Java Developer (Equities - London + NYC) - Front-end is a priority. PM-facing, high-impact, and part of a growing global team. - 3+ yrs experience. Java + React (ideally 50/50 but flexible). Expect: office-based with flexibility where it matters, modern tools, collaborative culture, and a genuinely impressive environment. Oh, and also a rooftop terrace, a bar on tap, and an open-plan office where technology sits at the heart of the business. If you’re interested or just want to chat about what these roles could look like for you, drop me a message. karolis@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7350128116540874753/', 'Quantitative Researcher | New York We’re working with a hedge fund that’s looking to hire a Quantitative Researcher to join their growing team and work directly with the Head of Quantitative Strategy. This is an excellent opportunity for someone early in their career who’s eager to take on responsibility across research implementation and model development. Ask yourself 💭 - Are you a highly capable coder? - Do you thrive in fast-paced, self-directed environments? - Are you looking to work more closely on modelling and implementing research ideas? - Do you take on side projects to push your technical skills? If you have 3 to 5 years of experience in a quantitative role and those questions resonate with you, I’d be happy to share more about the fund, team, and role, as well as walk you through other opportunities (both collaborative and pod-based) that might align with what you''re looking for. 📧 teagan@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7349735530030399488/', '𝐇𝐢𝐫𝐢𝐧𝐠 𝐟𝐨𝐫 𝐅𝐫𝐨𝐧𝐭 𝐎𝐟𝐟𝐢𝐜𝐞 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫𝐢𝐧𝐠 𝐑𝐨𝐥𝐞𝐬 𝐚𝐭 𝐚 𝐋𝐞𝐚𝐝𝐢𝐧𝐠 𝐌𝐮𝐥𝐭𝐢-𝐒𝐭𝐫𝐚𝐭 𝐅𝐮𝐧𝐝 I''m partnering with a top-tier multi-strategy hedge fund that''s expanding its front office engineering teams across multiple asset classes. These are high-impact roles working side-by-side with PMs and quant teams globally, delivering tools and platforms that directly influence trading outcomes. They’re hiring across three exciting verticals: 🔧 𝐑𝐚𝐩𝐢𝐝 𝐀𝐩𝐩𝐥𝐢𝐜𝐚𝐭𝐢𝐨𝐧 𝐏𝐲𝐭𝐡𝐨𝐧 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 - 𝐂𝐨𝐦𝐦𝐨𝐝𝐢𝐭𝐢𝐞𝐬 🌍 Global front office exposure ✅ 5+ years experience 🛠️ Strong in Python, SQL, Excel, web scraping 💻𝐅𝐮𝐥𝐥 𝐒𝐭𝐚𝐜𝐤 𝐉𝐚𝐯𝐚 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 - 𝐂𝐫𝐞𝐝𝐢𝐭 🌍 Collaborate directly with PMs ✅ 3+ years experience 🛠️ Core Java + some React on the frontend 📈𝐅𝐮𝐥𝐥 𝐒𝐭𝐚𝐜𝐤 𝐉𝐚𝐯𝐚 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 - 𝐄𝐪𝐮𝐢𝐭𝐢𝐞𝐬 🌍 High-touch front office role ✅ 3+ years experience 🛠️ Java & React (ideally 50/50 split) These are rare opportunities to work in lean, high-caliber teams where your work will be seen and used by decision-makers daily. 💬 Interested or know someone great? Drop me a message - happy to share more details. louis@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 4, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7349376949477117952/', '🚨 Confidential Build-Out Alert 🚨 💻 Quant Researcher (but really… Engineer/Builder/Doer) 📍 NYC preferred | 💰 $400–450K TC | ⏳ Start before year-end We’re partnering exclusively with a high-performing fund on a stealth build. This is not your typical quant researcher seat. Think: 🔧 Builder over theorist 🔥 Python + AWS wizardry ⚡ Side projects welcome (bonus points for crypto) 👥 Work directly with a senior partner—he’s hands-on, technical, and wants someone better at coding than him 📈 RATES/FX experience = nice to have, but not required 🧠 Market knowledge = teachable 💥 Attitude + execution = must-have You’ll be helping shape the foundations—implementing research ideas, owning projects, and moving fast. Super visible seat. Huge upside. If you’re 2–5 years into your career and ready to level up in a real way, let’s talk. Discretion assured. 📩 DM me for details. vick@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 10, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7349003230648889344/', '🔥 Summer is in full swing at Durlston Partners — and so is hiring across our core markets. Thanks to strong client relationships, we’re seeing sustained demand globally — with high activity across the US, Europe, Asia, and the UAE. Our teams in London, Dubai, and New York are driving searches across investment, technology, and digital assets. We’re actively hiring for: 🟢 EM Rates and/or FX PMs ⚡ European Power PMs/Traders 📉 Senior Macro PMs across linear products 📊 Junior Equity Vol Traders 🏙️ ECM Analysts (New York-based) 🤝 Teams exploring SMA platform deals 📈 Quant PMs running US Cash Equities strategies — open to high payout structures 🎯 Senior Options Traders & Quants with strong track records 🔍 Senior Quant Researchers with deep Bond RV experience — ideally former risk takers 🚀 We’re also hiring across Software Engineering, Development, and Tech, and working on unique mandates in Deep Learning Research, AI, and ML — across both the buy side and leading research labs. 📈 Our Digital Assets team is having a record year, partnering with a broad range of clients across trading, infrastructure, and Web3. If you''re open to a conversation or just want to hear more about what’s happening in the market, feel free to reach out. vick@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 6, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7348659713951121408/', '“I’m not really looking... but what’s out there?” 👀 That’s the most common message I get from C++ engineers, especially those in HFT or market making. And honestly? That’s the best time to talk. 💬 Why? 🤔 Because the top roles never hit job boards. These firms move quietly, fast, and only for the right people. A few things I’m seeing right now: ➡️ C++ engineers with Linux internals knowledge are being snapped up fast ➡️ Crypto-native trading firms are paying very competitively for HFT talent ➡️ If you''ve worked on exchange connectivity, order books, or tick-to-trade paths, your inbox should be on fire🔥 Even if you’re not looking - if you’d be open to hearing what better could look like, DM me. 📩 Adam Baard ab@durlstonpartners.com hashtag#Cpp hashtag#HFT hashtag#TradingJobs hashtag#QuantCareers hashtag#DigitalAssets hashtag#Cplusplus hashtag#proptrading hashtag#highfrequencytrading …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 9, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7348308627729920000/', 'These roles don’t get advertised.... until now 👀 Thinking about a move? Now’s the time I’m working on LIVE roles with some of the most innovative hedge funds, HFTs, and trading firms globally, from digital asset pioneers to world-class quant shops that don''t get advertised. Whether you’re building in Python, C++, Java, or Rust, the demand for top-tier talent is as strong as ever 👇 Python 🐍 Crypto Trading Firm – Core Python Developer – London 🐍 Trading Systems Firm – Trading Systems Engineer – Abu Dhabi C++ 🧠 Crypto Market Maker – C++ Developer – London 🧠 Trading Firm – C++ Developer – Fully Remote (EU) 🧠 HFT Firm – C++ Developer – Fully Remote 🧠 HFT Firm – C++ Developer – Amsterdam 🧠 Hedge Fund – C++ Developer – New York / Chicago 🧠 Prop Shop – C++ Developer – New York / Chicago Java ☕ Hedge Fund – Senior Java Developer – London ☕ Hedge Fund – Full Stack Engineer (90% Java / 10% React) – London ☕ Digital Asset Exchange – Senior Software Engineer – Fully Remote Rust 🦀 Trading Firm – Rust Developer – London 🦀 Crypto Trading Firm – Rust Developer – London 🦀 Crypto Trading Firm – Backend Engineer (Rust) – Fully Remote Frontend / Full Stack 💻 Quant Fund – Treasury Full Stack Engineer – London Data 📊 Investment Firm – Senior Data Engineer – Abu Dhabi 📊 Investment Firm – Data Scientist – Abu Dhabi Other 🚀 Hedge Fund – Crypto Quant Trader – London 🚀 HFT Firm – TradingOps Engineer – Amsterdam 🚀 Investment Firm – ML Quant – Abu Dhabi 🚀 Crypto Trading Firm – Crypto Quant Trader – Fully Remote (US) 🚀 HFT Firm – Quant Researcher – Chicago Open to a confidential chat? Let’s connect and chat! 📧 daniel@durlstonpartners.com Daniel Frugtniet Hagen hashtag#hiring hashtag#rust hashtag#cpp hashtag#python hashtag#java hashtag#crypto hashtag#hedgefunds hashtag#hft hashtag#quant …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 8, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7347919861605408768/', 'Seeking to reduce its dependence on oil revenues, the UAE is rapidly establishing itself as a leading global financial hub, with both the hashtag#ADGM and the hashtag#DIFC attracting top-tier hedge funds and investment managers. 📍Abu Dhabi • Hudson Bay Capital opened its second UAE office this month, expanding into ADGM following its Dubai launch in 2023. • Arini, Hamza Lemssouguer''s credit fund, is set to launch their Abu Dhabi presence later this year. • Brevan Howard has steadily scaled in Abu Dhabi since 2023, now with over 80 professionals in the region and establishing a strong regional leadership team. 📍Dubai • Tudor Capital is among 75+ hedge funds now active in the DIFC, with registrations up 50% year-over-year. • Walleye Capital has entered the region, hiring energy traders and relocating PMs as part of its global expansion. • Millennium, with a Dubai presence since 2020, now employs ~30 staff and plays a central role in the Emirate’s hedge fund ecosystem. • Schonfeld is scaling its team locally, contributing to a hedge fund workforce of 1,000+ professionals across DIFC. Why the UAE ❔ • A tax-friendly environment that supports business growth • Direct access to sovereign wealth and major institutional investors • Ideal time-zone for coverage of global markets • Strong infrastructure and clear, supportive regulation As more firms incorporate the region into their long-term growth strategies, the demand for high-calibre talent continues to accelerate. We’re proud to support several of the funds driving this growth. If you’re exploring opportunities in the UAE or would like a confidential market overview, please reach out on LinkedIn or email me: teagan@durlstonpartners.com 📧 Teagan Hill hashtag#ADGM hashtag#DIFC hashtag#UAE hashtag#GlobalMarkets hashtag#HedgeFunds hashtag#Quant hashtag#Macro hashtag#MultiStrat hashtag#AbuDhabi hashtag#Dubai hashtag#MarketUpdate …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 10, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7347583849092046848/', 'The hedge fund and HFT market in 2025 is buzzing with activity There''s an explosive surge in activity, and the future has never looked more dynamic. Why the buzz? Institutional investors are ramping up allocations to hedge funds off the back of strong performance and a positive start to the year, with systematic, quant, and multi-strategy funds seeing the greatest interest. With market dispersion on the rise, interest rates finding their groove, and volatility keeping things exciting, it''s a playground for active management and serious alpha generation, making these environments particularly attractive for those with technical and analytical expertise. Here’s the plot twist, it’s not just about portfolio managers and quants anymore, but also software engineers. Hedge funds and trading firms are scaling their technology stacks and investing heavily in infrastructure, data, and automation. And guess what? software developers, machine learning engineers, and data scientists are increasingly ditching "Big Tech" for finance. Why? Because the work is intellectually stimulating, the innovation is off the charts, and let''s be real... the compensation often blows the tech giants out of the water! Your move awaits! Competition for top performers is intense, with leading firms prepared to pay a premium to attract and retain the best minds. The appetite for expertise in AI, alternative data, and high-performance systems is only growing, and opportunities are popping up in every major financial hub worldwide. So, if you’re a portfolio manager, quant, or software engineer eyeing your next big career move, now is an exceptional time to dive into the hedge fund and HFT space. The industry is hungry for talent that can deliver results, drive innovation, and thrive in a fast-paced, high-impact environment. Ready to make a move? Let’s connect if you’d like to discuss a rewarding and impactful career move in this thriving sector. Daniel Frugtniet Hagen hashtag#hiring hashtag#hedgefunds hashtag#hft hashtag#careers hashtag#markettrends …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 12, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7347217695127339009/', '🛠️𝘈𝘊𝘛𝘐𝘝𝘌 𝘋𝘌𝘝𝘌𝘓𝘖𝘗𝘌𝘙 𝘙𝘖𝘓𝘌𝘚 📍London, New York, Chicago, UAE, fully remote 𝐂++ 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫𝐬 ➕ Senior C++ Developer - Crypto Trading Firm - London ➕ C++ Developer - Crypto Algo Trading Firm - Fully Remote ➕ C++ Developer - Quant Trading Firm - Fully Remote ➕ Backend Developer - Trading Protocol Firm - Fully Remote ➕ C++ Developer - Quant Trading Firm - New york/chicago 𝐏𝐲𝐭𝐡𝐨𝐧 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫𝐬 🐍 Quant Developer - Hedge Fund - London 🐍 Core Developer - Crypto Trading Firm - London 🐍 Software Engineer - Crypto Trading Firm - Fully Remote 🐍 Quant Developer - Hedge Fund - Abu Dhabi 𝐑𝐮𝐬𝐭 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫𝐬 🦀 Rust Developer - Crypto Trading Firm - London 🦀 Junior Developer - Crypto Trading Firm - London 🦀 Senior Backend Developer - Crypto Trading Firm - Fully Remote 🦀 Trading Systems Developer - Wealth Fund - Abu Dhabi 𝐃𝐚𝐭𝐚 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫𝐬 🔢 Data Engineer - ESG Firm - London 🔢 Senior Data Engineer - Wealth Fund - Abu Dhabi 🔢 Data Engineer - AI Start-Up - New york 𝐃𝐞𝐯𝐎𝐩𝐬 𝐄𝐧𝐠𝐢𝐧𝐞𝐞𝐫 🌉 Site Reliability Engineer - Crypto Trading Firm - Fully Remote 🌉 Head of Market Infra - Quant Trading Firm - Fully Remote 🌉 TradingOps Engineer - Prop Trading Firm - Amsterdam 🌉 Site Reliability Engineer - Quant Trading Firm - New york If any of these roles look interesting, feel free to get in touch ab@durlstonpartners.com Adam Baard …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7346855372042764288/', 'Fancy a Challenge? They''ve doubled in size in the last 12 months, hired engineers from Jane Street and Jump Trading, to name a few, and are building some of the most advanced systems in the industry, all powered by cutting-edge tech and a world-class engineering culture. If that sounds like your kind of environment... here''s your warm-up: import base64 def decode(): msg = "UHl0aG9uIGVuZ2luZWVycyBtYWtlIGdyZWF0IHRyYWRpbmcgc3lzdGVtcyE=" print("Decoded message:", base64.b64decode(msg).decode()) decode() If you know what this says, you''re the kind of engineer I want to talk to. Comment the answer below and I''ll reach out! hashtag#python hashtag#hft hashtag#tradingtech hashtag#hiring hashtag#cpp …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 5, 2, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7346853359984816128/', '🎆 𝐇𝐚𝐩𝐩𝐲 𝟒𝐭𝐡 𝐨𝐟 𝐉𝐮𝐥𝐲! Wishing a happy Independence Day to our team, clients, candidates, and friends across the pond!', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 5, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7346481590300012545/', 'Not every career move starts with a CV. Sometimes it starts with a coffee. Or a pint. ☕🍺 If you''re in the core tech, quant, low-latency engineering or fintech space, and you''re even mildly curious about what else is out there... let''s talk No pressure, no suits, no awkward "where do you see yourself in 5 years?" stuff. Just two humans actually interacting about: – Why some engineers are quietly increasing their comp – What’s happening in the space that’s actually worth paying attention to – Or just what kind of role might make you actually excited to open your laptop on a Monday 📍London-based (but open to virtual coffees if you’re elsewhere) DM me if you’re up for it, coffee’s on me. Pint too, if you''re persuasive. Daniel Frugtniet Hagen hashtag#hiring hashtag#hedgefunds hashtag#hft hashtag#crypto hashtag#london hashtag#coffee hashtag#pint …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 13, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7346130523141906432/', 'What separates good C++ engineers from great ones in HFT? 💰 Honestly, it’s not just about writing fast code, it’s about knowing why it''s fast. The strongest engineers all have this in common: ✅ They think in terms of cache lines, not just code. ✅ They’re benchmarking obsessively, right down to nanoseconds. ✅ They understand how their code behaves on real hardware, not just in theory. If you''re diving into lock-free data structures, playing with custom memory allocators, or tuning for latency under 1µs, you''re exactly who these firms are hunting for. Let’s connect. I’d love to share what I’m seeing in the market. Adam Baard ab@durlstonpartners.com hashtag#Cplusplus hashtag#HFT hashtag#LowLatency hashtag#TradingEngineering …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 15, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7345826187325173761/', '🎉 𝐇𝐚𝐩𝐩𝐲 𝟏𝟓𝐭𝐡 𝐁𝐢𝐫𝐭𝐡𝐝𝐚𝐲, 𝐃𝐮𝐫𝐥𝐬𝐭𝐨𝐧 𝐏𝐚𝐫𝐭𝐧𝐞𝐫𝐬! 🎉 Fifteen years of building long-term partnerships, working with some of the most exciting names in the industry, and making memories with an incredible team. Huge thank you to all the clients and candidates we’ve worked with over the years, including those who’ve been with us since the very beginning. If you’re thinking about your next move and want to work with a seasoned team that knows what they’re doing, or if your company is hiring and could use our help, drop us a message. 📧 hello@durlstonpartners.com hashtag#DP15 hashtag#HappyBirthdayDP hashtag#DurlstonPartners …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 10, 1, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7345768191542894593/', 'Are you a Java engineer who understands how money moves? You know what I mean. One of the UK’s most successful quant funds is hiring into their Core Tech team, the role will be supporting Ops, Treasury, Risk, and more. Sounds basic, but it’s more business-facing, hands-on, and high-impact than you think. They’re after someone who writes clean Java (with some Python), thinks about systems holistically, and isn’t afraid of responsibility. Bonus if you’ve used AI tools to boost dev speed, they’re exploring that too. This is 5 days onsite. No kangaroo CVs. No rigid mindsets. Let me know if you think you’re a good fit, or know someone who is. karolis@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7345368000687992833/', 'At Durlston Partners, we’ve spent over a decade building high-performing teams for the world’s most sophisticated Hedge Funds, HFTs, AI/ML firms, Digital Asset firms, and FinTechs. With offices in London, New York, and Dubai, we specialise in placing elite talent, quant researchers, traders, software engineers, data scientists, and AI specialists, who rarely engage with job boards or LinkedIn. We’ve partnered with everything from multi-billion-dollar hedge funds to high-growth startups, supporting critical hiring phases with both world-class talent and strategic insights, from compensation benchmarking to organisational structuring around capital raises, launches, and M&As. Our expertise spans: 🔹 Hedge Funds & Quant Trading - Systematic and discretionary search across front-office and core tech 🔹 High-Frequency & Algo Trading - Ultra-low-latency engineers, researchers, and PMs 🔹 AI & Machine Learning - AI research teams and infrastructure buildouts 🔹 Crypto & Digital Assets - Building the core teams at institutional crypto players since 2016 🔹 FinTech & Private Equity - Engineering, quant dev, and data science for next-gen financial tech We’ve successfully placed talent across London, New York, Zurich, Hong Kong, Singapore, UAE, and Qatar, earning a reputation for long-term partnerships and unmatched delivery. If you''re scaling or want market insight on comp trends, hiring strategy or org structure, I’d love to connect. 📧 shannon@durlstonpartners.com hashtag#Talent hashtag#Hiring hashtag#HedgeFunds hashtag#AI hashtag#Trading hashtag#Crypto hashtag#FinTech hashtag#ExecutiveSearch hashtag#QuantRecruitment hashtag#DurlstonPartners …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 8, 0, 1, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7344677198764646400/', '🚨 We’re working with a well-backed hedge fund in the UAE looking to add a Quantitative Researcher focused on intra-day strategies. 📍 Location: UAE 🧠 Experience: 3–5 years at a top hedge fund or prop shop 🎓 Education: MS or PhD in a quantitative field 📈 Focus: Research and build alpha-driven intraday signals across liquid markets This is a hands-on role in a lean team with real capital behind it. You’ll own strategy development end-to-end, from research to deployment. If you have a strong track record in alpha research, market microstructure, or ML-based signal design—and are open to relocating or already in the region—get in touch. DM me or reach out directly at vick@durlstonpartners.com …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 6, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7344307261613256705/', '𝐀𝐫𝐞 𝐲𝐨𝐮 𝐚 𝐋𝐋 𝐂++ 𝐃𝐞𝐯𝐞𝐥𝐨𝐩𝐞𝐫 𝐢𝐧 𝐇𝐅𝐓 𝐰𝐡𝐨 𝐢𝐬 𝐭𝐢𝐫𝐞𝐝 𝐨𝐟 𝐜𝐨𝐦𝐦𝐮𝐭𝐢𝐧𝐠 𝐭𝐨 𝐭𝐡𝐞 𝐨𝐟𝐟𝐢𝐜𝐞? I''m working with one of the leading high frequency trading firms globally, looking to bring on C++ engineers (all levels) to architect hyper high performant systems. And guess what, they are fully hashtag hashtag#remote !! This role will focus on extremely low latency optimisation (think hashtag hashtag#picoseconds, etc). 💰Very open on compensation and the position is fully remote globally🌍 Reach out to me for a confidential conversation - Referrals well Rewarded ✉ Louis@durlstonpartners.com Louis Esquerré-Gow hashtag#cpp hashtag#hedgefunds hashtag#crypto hashtag#tradingsystem hashtag#hft hashtag#highfrequencytrading …more', '9mo • 9 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7343952423251525644/', 'What’s the one thing all top developers are looking for? Impact? Compensation? Challenge? Autonomy? If you''re a C++, Java, Rust or Python engineer working in Hedge Funds, HFT, or Crypto, and looking for that one thing, I want to speak with you. I’m hiring for a range of ultra-low latency and core backend roles across: 🌍 London 🌍 Europe 🌍 UAE These are high-performance environments where nanoseconds matter, compensation reflects excellence, and the engineering bar is seriously high. Whether you''re actively looking or just curious, send me a message. Discretion guaranteed and opportunities worth hearing about. daniel@durlstonpartners.com hashtag#hft hashtag#hedgefunds hashtag#crypto hashtag#cpp hashtag#cplusplus hashtag#rust hashtag#java hashtag#python hashtag#hiring …more', '10mo • 10 months ago • Visible to anyone on or off LinkedIn', 8, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7343559840662732801/', '𝗔𝗹𝗽𝗵𝗮 𝗚𝗲𝗻𝗲𝗿𝗮𝘁𝗶𝗼𝗻, 𝗧𝗮𝘅 𝗢𝗽𝘁𝗶𝗺𝗶𝘀𝗮𝘁𝗶𝗼𝗻 - 𝗖𝗼𝗺𝗲 𝘁𝗼 𝘁𝗵𝗲 𝗠𝗶𝗱𝗱𝗹𝗲 𝗘𝗮𝘀𝘁🌴 I work with some of the most exciting players in the region - hedge funds, HFTs, sovereign funds, and quietly powerful family offices - all hungry for world-class Quant talent. If you''re a Quantitative Researcher, Trader or Developer, with strong experience in building alpha, productionising strategies, constructing portfolios etc, then I can help you make the jump. We’ve got a strong handle on the ecosystem here including the rapidly evolving market landscape, quick visa process, comp benchmarks, team structures, and (most importantly) 𝘄𝗵𝗮𝘁’𝘀 𝗿𝗲𝗮𝗹 𝘃𝘀 𝗻𝗼𝗶𝘀𝗲. Relocating isn’t just about a new job, it’s a very important life move. I''ve done it myself, and have helped plenty of others, so I am more than happy to help you to navigate the entire journey. If you’re even considering Dubai (or Abu Dhabi), now or down the line, let’s talk so I can give you a lay of the land. 📩 DM me or drop me a message for a discreet chat - rahn@durlstonpartners.com …more', '10mo • 10 months ago • Visible to anyone on or off LinkedIn', 10, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7343220101195726848/', '💡 Digital Assets Are Building HFT-Grade Infrastructure The crypto-native firms are maturing fast. The line between traditional HFT and digital asset trading infrastructure is blurring. 📈 What does that mean for C++ engineers? ➡️ Trading firms are hiring for the exact same profiles: C++17/20, ultra-low latency systems, real-time data ingestion, exchange connectivity. ➡️ Some of the best comp packages and greenfield engineering challenges are now coming from digital asset firms. Plus: These firms tend to move faster, less bureaucracy, adopt newer tech, and offer greater ownership. If you’re a C++ engineer with HFT experience, don’t ignore what’s happening in the digital asset world. The opportunity frontier is shifting. Adam Baard ab@durlstonpartners.com hashtag#Crypto hashtag#Trading hashtag#DigitalAssets hashtag#CryptoTrading hashtag#Cplusplus hashtag#HFT hashtag#TradingEngineering hashtag#FintechJobs …more', '10mo • 10 months ago • Visible to anyone on or off LinkedIn', 7, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7342860355477405697/', 'Back from 3 Weeks in Dubai - Regional Market Pulse A quick update after spending the last few weeks on the ground in the UAE and speaking with clients across all regions. US: Senior mandates remain active. We’re in deep conversations with PMs and researchers across macro, volatility, and systematic equities. Seeing more crossover between stat arb and applied AI - especially on intraday alpha and signal infra. UAE: Big moves here. The GCC-wide Schengen-style tourist visa was just approved - a strong signal of regional coordination and growth. Add to that BlueCrest relocating key operations to the UAE, and you get a clear picture: this place is not just a hub, it’s the hub. And while the conflict a bit north has raised concerns across the broader region, the UAE has stayed neutral, resilient, and focused — continuing to position itself as a safe, forward-looking financial center. Markets are active, capital is flowing, and the momentum isn’t slowing. Asia: Hong Kong and Singapore are holding steady. An uptick in options trading mandates - delta-one, vol-focused, and everything in between. Firms are investing in execution upgrades and full-stack trading solutions. Also, live mandates across quant dev and mid-freq research. Europe: London and Paris remain busy. Demand is shifting toward multi-asset thinkers and systematic credit. Index rebalancing, ML overlays, and hybrid research+execution roles are coming up more frequently. Vikram Tandon vick@durlstonpartners.com …more', '10mo • 10 months ago • Visible to anyone on or off LinkedIn', 5, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7342853976440160257/', 'Systematic Trading Opportunities - Global Expansion We’re working with a leading systematic trading firm undergoing global expansion. With a track record of strong returns and industry-leading infrastructure, they’re now looking to add exceptional talent across portfolio management, quant research, and AI leadership. They are open to candidates across the UK, US, Singapore, India, and remote (within Europe). 🔹 1. Portfolio Managers - Fully Automated Strategies ➡️ Asset Classes: Options, Futures, Equities ➡️ Strategy Type: Fully automated (HFT or MFT) ➡️ Requirements: Strong live track record with high Sharpe and significant PnL ➡️ Ideal Backgrounds: Tier-1 options trading firms and top systematic platforms 🔹 2. Quant Researchers - End-to-End Systematic Research ➡️Asset Classes: Options, Futures, Equities ➡️Strategy Type: Fully automated (HFT or MFT) ➡️Requirements: Must run strategies end-to-end with strong Sharpe and live PnL ➡️Ideal Backgrounds: Top electronic trading firms with a strong research-to-deployment workflow 🔹 3. Head of AI - Define Strategic AI Direction ➡️Mandate: Own and lead the AI agenda across the trading business ➡️Ideal Profile: Background in HFT and/or experience in top AI research environments ➡️Ideal Backgrounds: Candidates with experience in both high-performance computing and applied machine learning at scale 💡 Why Join? ➡️ Remote Flexibility: Location-agnostic and open to remote setups in Europe ➡️ Elite Infrastructure: A market-leading internal compute cluster supporting ultra-low-latency trading ➡️ Strong Capital Base: Enabling rapid scale-up of successful strategies ➡️ Collaborative Culture: High autonomy, deep technical focus, and performance-driven growth If you''re interested, I’d be keen to discuss the fund, team, and role details, as well as other potential opportunities (tier 1 collaborative or pod-based). DM me or email me: teagan@dursltonpartners.com 📩 hashtag#SystematicTrading hashtag#QuantFinance hashtag#PortfolioManager hashtag#QuantResearch hashtag#MachineLearning …more', '10mo • 10 months ago • Visible to anyone on or off LinkedIn', 11, 0, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7342487769488785409/', 'Have you participated and (ideally) won a competitive programming or ML (Kaggle) competition in the last few years? Are you a grad and finance isn''t quite your bag? An AI startup, which has raised over $20 M and is preparing to raise again, is building software infrastructure that enables everyday users to train AI models by combining the computational power of their devices. The engineering team are all young, and all come from a top 5 global HFT background. Sponsorship is available. Comp: Up to $240k base + high equity WFH: Remote or in-office, your choice Process: 4 stages, including a paid onsite Reach out if this sounds like you or one of your siblings! Karolis Kundrotas karolis@durlstonpartners.com …more', '10mo • 10 months ago • Visible to anyone on or off LinkedIn', 16, 1, 0, 'image', 0, NULL);
INSERT OR IGNORE INTO posts (company_key, author_kind, author_name, author_url, post_url, post_text, posted_date, reactions_count, comments_count, reposts_count, media_type, is_repost, original_author) VALUES ('durlston-partners', 'company', NULL, 'https://www.linkedin.com/company/durlston-partners/posts', 'https://www.linkedin.com/feed/update/urn:li:activity:7342151809211285504/', 'Let’s talk compensation 💰💰 Software Engineers in Hedge Funds, HFTs & Crypto There’s a lot of noise (and sometimes hype) around salaries in this space, so let’s break it down. Yes, the tier 1 firms "you know who I''m talking about" that pay very well but it’s important to understand that those packages aren’t the market norm. 📊 Here’s a more grounded look at current ranges in London, from what I see: Junior Engineers (0–2 YOE): - Base: £60k – £110k - Bonus: up to 100%+ depending on performance and firm type Mid-Level (2–5 YOE): - Base: £110k – £130k - Bonus: up to 150% depending on performance and firm type Senior/Lead (5+ YOE): - Base: £130k+ - Bonus: up to 200%+ (some discretionary, some performance-based)) 🔍 HFTs tend to have the most aggressive comp structures (higher bonuses, flatter orgs). 🏦 Hedge Funds are more varied, some are engineering-led, others less so. 🌐 Crypto firms can swing wildly, some offer equity/token upside, but packages can be riskier or more volatile. It’s also worth noting: first-year comp can be on the lower end, especially when joining a new firm or ramping up technically, but progression is often fast, and year-on-year increases tend to be meaningful. 📌 P.S. These are just indicative ranges, compensation varies significantly by firm, team, skillset, performance, and structure. Happy to share more detailed ranges or benchmarks if helpful, feel free to reach out. Daniel Frugtniet Hagen daniel@durlstonpartners.com hashtag#salaries hashtag#hft hashtag#hedgefunds hashtag#crypto hashtag#hiring …more', '10mo • 10 months ago • Visible to anyone on or off LinkedIn', 13, 1, 1, 'image', 0, NULL);
